import { Injectable, Logger } from '@nestjs/common';
import sharp from 'sharp';

import { IMAGE_SIZES, ImageSizeConfig, ImageSizeName, DEFAULT_SIZES } from '../utils/image-sizes';

export interface GeneratedImage {
  size: ImageSizeName;
  buffer: Buffer;
  width: number;
  height: number;
  format: string;
  contentType: string;
}

export interface ImageMetadata {
  width: number;
  height: number;
  size: number;
  format: string;
  contentType: string;
  density?: number;
  hasAlpha: boolean;
}

export interface OptimizeOptions {
  quality?: number;
  format?: 'webp' | 'jpeg' | 'png';
  width?: number;
  height?: number;
  fit?: 'cover' | 'inside' | 'outside';
}

@Injectable()
export class ImageProcessingService {
  private readonly logger = new Logger(ImageProcessingService.name);

  async generateSizes(buffer: Buffer, sizes: ImageSizeName[] = DEFAULT_SIZES): Promise<GeneratedImage[]> {
    const metadata = await sharp(buffer).metadata();
    const results: GeneratedImage[] = [];

    for (const sizeName of sizes) {
      const config = IMAGE_SIZES[sizeName];
      try {
        const generated = await this.generateSize(buffer, config, metadata);
        results.push(generated);
      } catch (error) {
        this.logger.error(`Failed to generate size '${sizeName}': ${error instanceof Error ? error.message : String(error)}`);
        throw error;
      }
    }

    return results;
  }

  private async generateSize(buffer: Buffer, config: ImageSizeConfig, metadata: sharp.Metadata): Promise<GeneratedImage> {
    let pipeline = sharp(buffer);

    if (config.name === 'original') {
      // original: keep original dimensions, just re-encode
    } else {
      pipeline = pipeline.resize(config.width, config.height, {
        fit: config.fit,
        withoutEnlargement: true,
        ...(config.fit === 'cover' ? { position: sharp.strategy.attention } : {}),
      });
    }

    const webpBuffer = await pipeline
      .webp({ quality: config.quality, effort: 4 })
      .toBuffer();

    const outputMetadata = await sharp(webpBuffer).metadata();

    return {
      size: config.name,
      buffer: webpBuffer,
      width: outputMetadata.width ?? (config.name === 'original' ? metadata.width ?? 0 : config.width),
      height: outputMetadata.height ?? (config.name === 'original' ? metadata.height ?? 0 : config.height),
      format: 'webp',
      contentType: 'image/webp',
    };
  }

  async optimize(buffer: Buffer, options: OptimizeOptions = {}): Promise<Buffer> {
    const { quality = 80, format = 'webp', width, height, fit = 'inside' } = options;

    let pipeline = sharp(buffer);

    if (width || height) {
      pipeline = pipeline.resize(width, height, { fit, withoutEnlargement: true });
    }

    switch (format) {
      case 'webp':
        return pipeline.webp({ quality, effort: 4 }).toBuffer();
      case 'jpeg':
        return pipeline.jpeg({ quality }).toBuffer();
      case 'png':
        return pipeline.png({ quality }).toBuffer();
      default:
        return pipeline.webp({ quality, effort: 4 }).toBuffer();
    }
  }

  async getMetadata(buffer: Buffer): Promise<ImageMetadata> {
    const metadata = await sharp(buffer).metadata();

    const formatMap: Record<string, string> = {
      jpeg: 'image/jpeg',
      jpg: 'image/jpeg',
      png: 'image/png',
      webp: 'image/webp',
      gif: 'image/gif',
      avif: 'image/avif',
      tiff: 'image/tiff',
    };

    return {
      width: metadata.width ?? 0,
      height: metadata.height ?? 0,
      size: metadata.size ?? buffer.length,
      format: metadata.format ?? 'unknown',
      contentType: formatMap[metadata.format ?? ''] ?? 'application/octet-stream',
      density: metadata.density,
      hasAlpha: metadata.hasAlpha ?? false,
    };
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import * as Minio from "minio";
import sharp from "sharp";
import { v4 as uuidv4 } from "uuid";

import { sanitizeImage } from "../security/image-sanitizer";
import { UserKeyService } from "../security/user-key.service";

/**
 * Multer 文件类型定义
 * 用于处理上传的文件
 */
interface MulterFile {
  fieldname: string;
  originalname: string;
  encoding: string;
  mimetype: string;
  buffer: Buffer;
  size: number;
  destination?: string;
  filename?: string;
  path?: string;
  stream?: NodeJS.ReadableStream;
}

@Injectable()
export class StorageService {
  private readonly logger = new Logger(StorageService.name);
  private readonly minioClient: Minio.Client;
  private readonly bucket: string;

  constructor(
    private configService: ConfigService,
    private userKeyService: UserKeyService,
  ) {
    const accessKey = this.configService.get<string>("MINIO_ACCESS_KEY");
    const secretKey = this.configService.get<string>("MINIO_SECRET_KEY");
    
    if (!accessKey || !secretKey) {
      throw new Error(
        "MINIO_ACCESS_KEY and MINIO_SECRET_KEY environment variables are required. " +
        "Please configure these in your .env file. " +
        "See .env.example for reference."
      );
    }
    
    const port = this.configService.get<string>("MINIO_PORT", "9000");
    const endpoint = this.configService.get<string>("MINIO_ENDPOINT");
    if (!endpoint) {
      throw new Error("MINIO_ENDPOINT environment variable is required");
    }
    
    this.minioClient = new Minio.Client({
      endPoint: endpoint,
      port: parseInt(port, 10) || 9000,
      useSSL:
        this.configService.get<string>("MINIO_USE_SSL", "false") === "true",
      accessKey,
      secretKey,
    });
    this.bucket = this.configService.get<string>("MINIO_BUCKET", "xuno");
    this.logger.log(`StorageService initialized with endpoint: ${endpoint}, bucket: ${this.bucket}`);
    this.ensureBucket();
  }

  private async ensureBucket() {
    try {
      const exists = await this.minioClient.bucketExists(this.bucket);
      if (!exists) {
        await this.minioClient.makeBucket(this.bucket);
        this.logger.log(`Created bucket: ${this.bucket}`);
      }
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to ensure bucket: ${errorMessage}`);
    }
  }

  async uploadImage(
    file: MulterFile,
    folder: string = "uploads",
  ): Promise<{ url: string; thumbnailUrl?: string }> {
    const ext = file.originalname.split(".").pop() || "jpg";
    const filename = `${folder}/${uuidv4()}.${ext}`;

    await this.minioClient.putObject(
      this.bucket,
      filename,
      file.buffer,
      file.size,
      { "Content-Type": file.mimetype },
    );

    const url = await this.getFileUrl(filename);

    let thumbnailUrl: string | undefined;
    if (folder === "photos") {
      thumbnailUrl = await this.createThumbnail(file, filename);
    }

    return { url, thumbnailUrl };
  }

  async uploadBuffer(
    filename: string,
    buffer: Buffer,
    contentType: string = 'application/octet-stream',
  ): Promise<void> {
    await this.minioClient.putObject(
      this.bucket,
      filename,
      buffer,
      buffer.length,
      { 'Content-Type': contentType },
    );
  }

  private async createThumbnail(
    file: MulterFile,
    originalFilename: string,
  ): Promise<string | undefined> {
    try {
      const thumbnail = await sanitizeImage(sharp(file.buffer))
        .resize(300, 300, { fit: "cover" })
        .toBuffer();

      const thumbnailFilename = originalFilename.replace(
        /(\.\w+)$/,
        "-thumbnail$1",
      );

      await this.minioClient.putObject(
        this.bucket,
        thumbnailFilename,
        thumbnail,
        thumbnail.length,
        { "Content-Type": file.mimetype },
      );

      return await this.getFileUrl(thumbnailFilename);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to create thumbnail: ${errorMessage}`);
      return undefined;
    }
  }

  /**
   * 上传临时文件（用于数据导出等场景）
   * @param filename 文件名（包含路径）
   * @param content 文件内容
   * @param expiresIn 过期时间（秒）
   * @returns 预签名下载 URL
   */
  async uploadTemporary(
    filename: string,
    content: Buffer,
    expiresIn: number = 7 * 24 * 60 * 60, // 默认 7 天
  ): Promise<string> {
    await this.minioClient.putObject(
      this.bucket,
      filename,
      content,
      content.length,
      { "Content-Type": "application/json" },
    );

    return this.getFileUrl(filename, expiresIn);
  }

  /**
   * 删除文件
   * @param filenameOrUrl 文件名或完整 URL
   */
  async delete(filenameOrUrl: string): Promise<void> {
    // 如果是完整 URL，提取文件名
    let filename = filenameOrUrl;
    try {
      const url = new URL(filenameOrUrl);
      // 从 URL 路径中提取文件名（移除开头的 /）
      filename = url.pathname.substring(1);
      // 如果有 bucket 名称在路径中，移除它
      if (filename.startsWith(`${this.bucket}/`)) {
        filename = filename.substring(this.bucket.length + 1);
      }
    } catch (error) {
      // 不是有效的 URL，记录并直接使用原始值作为文件名
      this.logger.debug(
        `Input '${filenameOrUrl.substring(0, 50)}...' is not a valid URL, treating as filename. Error: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    await this.minioClient.removeObject(this.bucket, filename);
  }

  /**
   * 获取文件预签名 URL
   * @param filename 文件名
   * @param expiresIn 过期时间（秒）
   */
  async fileExists(filename: string): Promise<boolean> {
    try {
      await this.minioClient.statObject(this.bucket, filename);
      return true;
    } catch {
      return false;
    }
  }

  async getFileUrl(
    filename: string,
    expiresIn: number = 86400,
  ): Promise<string> {
    return await this.minioClient.presignedUrl(
      "GET",
      this.bucket,
      filename,
      expiresIn,
    );
  }

  /**
   * 删除文件（旧方法，保持向后兼容）
   * @deprecated 使用 delete() 方法代替
   */
  async deleteFile(filename: string): Promise<void> {
    await this.delete(filename);
  }

  async fetchRemoteAsset(
    url: string,
  ): Promise<{
    body: Buffer;
    contentType: string;
    cacheControl: string;
  }> {
    const response = await fetch(url);

    if (!response.ok) {
      throw new Error(`Failed to fetch asset: ${response.status}`);
    }

    return {
      body: Buffer.from(await response.arrayBuffer()),
      contentType:
        response.headers.get("content-type") ?? "application/octet-stream",
      cacheControl:
        response.headers.get("cache-control") ?? "private, max-age=300",
    };
  }

  async fetchRemoteAssetDataUri(url: string): Promise<string> {
    const asset = await this.fetchRemoteAsset(url);
    return `data:${asset.contentType};base64,${asset.body.toString("base64")}`;
  }

  async generateWatermarkedImage(
    imageUrl: string,
    watermarkText: string = "寻裳 AI 试衣",
  ): Promise<string> {
    const asset = await this.fetchRemoteAsset(imageUrl);
    const imageBuffer = asset.body;

    const svgWatermark = `
      <svg width="300" height="40">
        <text x="0" y="28" font-family="sans-serif" font-size="24" fill="white" opacity="0.6">
          ${watermarkText}
        </text>
      </svg>`;

    const watermarkedBuffer = await sharp(imageBuffer)
      .composite([
        {
          input: Buffer.from(svgWatermark),
          gravity: "southeast",
        },
      ])
      .png()
      .toBuffer();

    const filename = `tryon-results/watermarked/${uuidv4()}.png`;
    await this.minioClient.putObject(
      this.bucket,
      filename,
      watermarkedBuffer,
      watermarkedBuffer.length,
      { "Content-Type": "image/png" },
    );

    return this.getFileUrl(filename);
  }

  async getCDNUrl(path: string): Promise<string> {
    const cdnBaseUrl = this.configService.get<string>("CDN_BASE_URL");
    if (cdnBaseUrl) {
      return `${cdnBaseUrl}/${path}`;
    }
    return this.getFileUrl(path);
  }

  async uploadEncrypted(
    userId: string,
    file: MulterFile,
    folder: string = "uploads",
  ): Promise<{ url: string; thumbnailUrl?: string }> {
    const encryptedBuffer = await this.userKeyService.encryptBufferForUser(
      userId,
      file.buffer,
    );

    const ext = file.originalname.split(".").pop() || "jpg";
    const filename = `${folder}/${uuidv4()}.${ext}.enc`;

    await this.minioClient.putObject(
      this.bucket,
      filename,
      encryptedBuffer,
      encryptedBuffer.length,
      {
        "Content-Type": "application/octet-stream",
        "X-Encrypted": "true",
        "X-Original-Content-Type": file.mimetype,
      },
    );

    const url = await this.getFileUrl(filename);

    let thumbnailUrl: string | undefined;
    if (folder === "photos") {
      thumbnailUrl = await this.createThumbnail(file, filename);
    }

    return { url, thumbnailUrl };
  }

  async downloadEncrypted(
    userId: string,
    filenameOrUrl: string,
  ): Promise<Buffer> {
    const filename = this.extractFilename(filenameOrUrl);
    const dataStream = await this.minioClient.getObject(this.bucket, filename);
    const chunks: Buffer[] = [];

    for await (const chunk of dataStream) {
      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    }

    const encryptedBuffer = Buffer.concat(chunks);
    return this.userKeyService.decryptBufferForUser(userId, encryptedBuffer);
  }

  private extractFilename(filenameOrUrl: string): string {
    try {
      const url = new URL(filenameOrUrl);
      let filename = url.pathname.substring(1);
      if (filename.startsWith(`${this.bucket}/`)) {
        filename = filename.substring(this.bucket.length + 1);
      }
      return filename;
    } catch {
      return filenameOrUrl;
    }
  }
}

import { ValidationPipe, VersioningType } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { NestFactory } from "@nestjs/core";
import { SwaggerModule } from "@nestjs/swagger";
import compression from "compression";
import { Request, Response, NextFunction } from "express";
import helmet from "helmet";

import { AppModule } from "./app.module";
import { AllExceptionsFilter } from "./common/filters";
import { ErrorHandlerMiddleware } from "./common/middleware/error-handler.middleware";
import { MetricsMiddleware } from "./common/middleware/metrics.middleware";
import { XssSanitizationPipe } from "./common/pipes/xss-sanitization.pipe";
import { createSwaggerConfig } from "./config/swagger.config";
import { MetricsService } from "./modules/metrics/metrics.service";

async function bootstrap() {
  const app = await NestFactory.create(AppModule);

  // 获取 MetricsService 实例
  const metricsService = app.get(MetricsService);
  const metricsMiddleware = new MetricsMiddleware(metricsService);

  // 应用全局错误处理中间件（必须在最前面）
  const errorHandlerMiddleware = new ErrorHandlerMiddleware();
  app.use((req: Request, res: Response, next: NextFunction) => {
    errorHandlerMiddleware.use(req, res, next);
  });

  // 应用指标中间件（排除 /metrics 端点）
  app.use((req: Request, res: Response, next: NextFunction) => {
    if (!req.path.includes('/metrics')) {
      metricsMiddleware.use(req, res, next);
    } else {
      next();
    }
  });

  // 安全中间件
  app.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          scriptSrc: ["'self'"],
          styleSrc: ["'self'", "'unsafe-inline'"],
          imgSrc: ["'self'", "data:", "blob:"],
          connectSrc: ["'self'", "ws://localhost:8081"],
          fontSrc: ["'self'"],
          objectSrc: ["'none'"],
          upgradeInsecureRequests: [],
        },
      },
      crossOriginResourcePolicy: { policy: "same-site" },
      crossOriginOpenerPolicy: { policy: "same-origin" },
      crossOriginEmbedderPolicy: { policy: "require-corp" },
      referrerPolicy: { policy: "strict-origin-when-cross-origin" },
    }),
  );

  // 响应压缩
  app.use(
    compression({
      threshold: 1024, // 超过 1KB 的响应才压缩
      level: 6, // 压缩级别 1-9
    }),
  );

  // CORS 配置
  const corsOrigins = process.env.CORS_ORIGINS?.split(",").filter(Boolean) || [];
  app.enableCors({
    origin: corsOrigins.length > 0
      ? corsOrigins
      : (process.env.NODE_ENV === "production"
        ? []
        : ["http://localhost:3000", "http://localhost:3001"]),
    credentials: true,
    methods: ["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"],
    allowedHeaders: ["Content-Type", "Authorization", "X-Requested-With", "X-CSRF-Token"],
    exposedHeaders: ["X-Total-Count", "X-CSRF-Token"],
    maxAge: 86400,
  });

  // API 版本控制
  app.setGlobalPrefix("api");
  app.enableVersioning({
    type: VersioningType.URI,
    defaultVersion: "1",
  });

  // 全局验证管道 (XSS防护 + 输入验证)
  app.useGlobalPipes(
    new XssSanitizationPipe(),
    new ValidationPipe({
      whitelist: true,
      forbidNonWhitelisted: true,
      transform: true,
      transformOptions: {
        enableImplicitConversion: true,
      },
    }),
  );

  // 全局异常过滤器
  app.useGlobalFilters(new AllExceptionsFilter());

  // Swagger API 文档配置 - 仅在非生产环境启用
  if (process.env.NODE_ENV !== "production") {
    const config = createSwaggerConfig();

    const document = SwaggerModule.createDocument(app, config);
    SwaggerModule.setup("api/docs", app, document, {
      swaggerOptions: {
        persistAuthorization: true,
        displayRequestDuration: true,
        docExpansion: "list",
      },
    });
  }

  const configService = app.get(ConfigService);
  const port = configService.get<number>("PORT", 3001);

  await app.listen(port);

  if (process.env.NODE_ENV !== "production") {
    console.log(`🚀 寻裳 API running on: http://localhost:${port}/api`);
    console.log(`📚 API Documentation: http://localhost:${port}/api/docs`);
  } else {
    console.log(`🚀 寻裳 API running in production mode on port ${port}`);
  }
}

bootstrap();

/**
 * AI Safety Service
 *
 * Main service for LLM output validation and hallucination detection.
 * Integrates with Python ML service for advanced detection capabilities.
 *
 * 2026 AI Safety Best Practices Implementation
 */

import { HttpService } from '@nestjs/axios';
import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { AxiosResponse as _AxiosResponse } from 'axios';
import { Counter, Histogram, Gauge } from 'prom-client';
import { firstValueFrom } from 'rxjs';

import { resolveServiceUrl } from '../../common/config/runtime-flags';

// Types
export interface ValidationResult {
  isValid: boolean;
  confidenceScore: number;
  issues: DetectedIssue[];
  processingTimeMs: number;
  validatedAt: string;
}

export interface DetectedIssue {
  type: string;
  severity: 'error' | 'warning' | 'info';
  description: string;
  confidence: number;
  location?: string;
  suggestion?: string;
  details?: Record<string, any>;
}

export interface ValidationContext {
  occasion?: string;
  season?: string;
  bodyType?: string;
  colorSeason?: string;
  temperature?: number;
  userId?: string;
  sessionId?: string;
  knowledgeContext?: string[];
  userPreferences?: Record<string, any>;
}

export interface HallucinationLog {
  id: string;
  response: string;
  detection: { isHallucination?: boolean; confidenceScore: number; issues: DetectedIssue[] };
  context: ValidationContext;
  timestamp: Date;
  resolved: boolean;
  resolution?: string;
}

@Injectable()
export class AISafetyService {
  private readonly logger = new Logger(AISafetyService.name);
  private readonly mlServiceUrl: string;

  constructor(
    private readonly configService: ConfigService,
    private readonly httpService: HttpService,
    @InjectMetric('hallucination_detection_total')
    private readonly detectionCounter: Counter<string>,
    @InjectMetric('hallucination_rate')
    private readonly hallucinationRate: Gauge<string>,
    @InjectMetric('validation_latency_seconds')
    private readonly validationLatency: Histogram<string>,
  ) {
    this.mlServiceUrl = resolveServiceUrl(this.configService, 'ML_SERVICE_URL', 'http://localhost:8001');
  }

  /**
   * Validate LLM response for hallucinations
   *
   * @param response - LLM generated response text
   * @param context - Validation context (occasion, season, body_type, etc.)
   * @returns ValidationResult with confidence score and detected issues
   */
  async validateResponse(
    response: string,
    context: ValidationContext = {},
  ): Promise<ValidationResult> {
    const startTime = Date.now();

    try {
      // Call Python ML service for detection
      const detectionResult = await this.callMLService(response, context);

      // Record metrics
      this.recordMetrics(detectionResult, context);

      // Log if hallucination detected
      if (detectionResult.isHallucination || detectionResult.confidenceScore < 0.7) {
        await this.logHallucination(response, detectionResult, context);
      }

      const processingTime = Date.now() - startTime;

      // Record latency
      this.validationLatency.observe(processingTime / 1000);

      return {
        isValid: !detectionResult.isHallucination && detectionResult.confidenceScore >= 0.5,
        confidenceScore: detectionResult.confidenceScore,
        issues: detectionResult.issues,
        processingTimeMs: processingTime,
        validatedAt: new Date().toISOString(),
      };
    } catch (error) {
      this.logger.error(
        `Validation failed: ${this.getErrorMessage(error)}`,
        error instanceof Error ? error.stack : undefined,
      );

      // Return a conservative result on error
      return {
        isValid: false,
        confidenceScore: 0,
        issues: [
          {
            type: 'validation_error',
            severity: 'error',
            description: 'Failed to validate response',
            confidence: 1.0,
            details: { error: this.getErrorMessage(error) },
          },
        ],
        processingTimeMs: Date.now() - startTime,
        validatedAt: new Date().toISOString(),
      };
    }
  }

  /**
   * Validate and correct response if possible
   *
   * @param response - Original response
   * @param context - Validation context
   * @returns Corrected response and validation result
   */
  async validateAndCorrect(
    response: string,
    context: ValidationContext = {},
  ): Promise<{ correctedResponse: string; validation: ValidationResult }> {
    const validation = await this.validateResponse(response, context);

    let correctedResponse = response;

    // If hallucination detected, add disclaimer
    if (!validation.isValid) {
      const criticalIssues = validation.issues.filter(
        (i) => i.severity === 'error'
      );

      if (criticalIssues.length > 0) {
        // Add warning prefix for critical issues
        correctedResponse = this.addWarningPrefix(response, criticalIssues);
      }
    }

    return {
      correctedResponse,
      validation,
    };
  }

  /**
   * Log hallucination detection for analysis
   *
   * @param response - The response with hallucination
   * @param detection - Detection result (partial ValidationResult)
   */
  logHallucination(
    response: string,
    detection: { isHallucination?: boolean; confidenceScore: number; issues: DetectedIssue[] },
    context: ValidationContext = {},
  ): Promise<void> {
    const logEntry: HallucinationLog = {
      id: this.generateLogId(),
      response: response.substring(0, 500), // Truncate for storage
      detection,
      context,
      timestamp: new Date(),
      resolved: false,
    };

    // Log to console for now (could be extended to database)
    this.logger.warn({
      message: 'Hallucination detected',
      logId: logEntry.id,
      confidenceScore: detection.confidenceScore,
      issueCount: detection.issues.length,
      criticalIssues: detection.issues.filter((i) => i.severity === 'error').length,
      context: {
        occasion: context.occasion,
        season: context.season,
        bodyType: context.bodyType,
      },
    });

    // In production, this would be stored in a database for analysis
    // await this.hallucinationLogRepository.save(logEntry);
  }

  /**
   * Get hallucination statistics
   */
  getStatistics(
    _startDate?: Date,
    _endDate?: Date,
  ): Promise<{
    totalDetections: number;
    hallucinationRate: number;
    averageConfidence: number;
    issuesByType: Record<string, number>;
    issuesBySeverity: Record<string, number>;
  }> {
    // In production, this would query the database
    // For now, return placeholder data
    return {
      totalDetections: 0,
      hallucinationRate: 0,
      averageConfidence: 1.0,
      issuesByType: {},
      issuesBySeverity: {},
    };
  }

  /**
   * Quick validation check (lightweight, for real-time use)
   */
  quickCheck(response: string): Promise<boolean> {
    try {
      // Simple checks without full ML service call
      const suspiciousPatterns = [
        /绝对|一定|必须|always|never|must/gi,
        /\d{4}年|year \d{4}/g, // Future dates
        /\$\d{6,}/g, // Unusually high prices
      ];

      for (const pattern of suspiciousPatterns) {
        if (pattern.test(response)) {
          return false;
        }
      }

      return true;
    } catch (error) {
      // Log unexpected error but default to true to avoid blocking responses
      this.logger.warn(
        `quickCheck encountered unexpected error: ${this.getErrorMessage(error)}. Defaulting to true.`,
      );
      return true;
    }
  }

  /**
   * Call Python ML service for hallucination detection
   */
  private async callMLService(
    textToValidate: string,
    context: ValidationContext,
  ): Promise<{
    isHallucination: boolean;
    confidenceScore: number;
    issues: DetectedIssue[];
  }> {
    try {
      const response = await firstValueFrom(
        this.httpService.post<{
          is_hallucination?: boolean;
          confidence_score?: number;
          issues?: Array<{ type: string; severity: string; description: string }>;
        }>(
          `${this.mlServiceUrl}/api/v1/hallucination/detect`,
          {
            text: textToValidate,
            context: {
              occasion: context.occasion,
              season: context.season,
              body_type: context.bodyType,
              color_season: context.colorSeason,
              temperature: context.temperature,
            },
          },
          {
            headers: {
              'Content-Type': 'application/json',
            },
            timeout: 5000,
          },
        ),
      );

      const data = response.data;

      return {
        isHallucination: data.is_hallucination ?? false,
        confidenceScore: data.confidence_score ?? 1.0,
        issues: (data.issues ?? []).map((issue: { type: string; severity: string; description: string; confidence?: number; location?: string; suggestion?: string; details?: Record<string, unknown> }) => ({
          type: issue.type,
          severity: issue.severity as 'error' | 'warning' | 'info',
          description: issue.description,
          confidence: issue.confidence ?? 0.5,
          location: issue.location,
          suggestion: issue.suggestion,
          details: issue.details,
        })),
      };
    } catch (error) {
      // If ML service is unavailable, use fallback validation
      this.logger.warn(
        `ML service unavailable, using fallback: ${this.getErrorMessage(error)}`,
      );
      return this.fallbackValidation(textToValidate, context);
    }
  }

  /**
   * Fallback validation when ML service is unavailable
   */
  private fallbackValidation(
    response: string,
    context: ValidationContext,
  ): {
    isHallucination: boolean;
    confidenceScore: number;
    issues: DetectedIssue[];
  } {
    const issues: DetectedIssue[] = [];

    // Temperature consistency check
    if (context.temperature !== undefined) {
      const tempMatch = response.match(/(-?\d+)\s*[°度]C?/i);
      const mentionedTempText = tempMatch?.[1];
      if (mentionedTempText) {
        const mentionedTemp = parseInt(mentionedTempText, 10);
        if (Math.abs(mentionedTemp - context.temperature) > 15) {
          issues.push({
            type: 'numerical_error',
            severity: 'warning',
            description: `Temperature ${mentionedTemp}C differs significantly from actual ${context.temperature}C`,
            confidence: 0.8,
          });
        }
      }
    }

    // Occasion appropriateness check
    if (context.occasion) {
      const forbiddenPatterns: Record<string, RegExp[]> = {
        business: [/短裤|sandals|flip.?flops/i],
        formal: [/jeans|sneakers|t-?shirt/i],
        interview: [/casual|jeans|sneakers/i],
      };

      const patterns = forbiddenPatterns[context.occasion.toLowerCase()];
      if (patterns) {
        for (const pattern of patterns) {
          if (pattern.test(response)) {
            issues.push({
              type: 'fashion_rule',
              severity: 'warning',
              description: `Item may not be appropriate for ${context.occasion} occasion`,
              confidence: 0.7,
            });
          }
        }
      }
    }

    const confidenceScore = issues.length > 0
      ? Math.max(0.3, 1 - issues.length * 0.2)
      : 0.8; // Lower confidence for fallback

    return {
      isHallucination: confidenceScore < 0.5,
      confidenceScore,
      issues,
    };
  }

  /**
   * Record metrics for monitoring
   */
  private recordMetrics(
    result: { isHallucination: boolean; confidenceScore: number; issues: DetectedIssue[] },
    context: ValidationContext,
  ): void {
    // Increment detection counter
    this.detectionCounter.inc({
      status: result.isHallucination ? 'hallucination' : 'valid',
      occasion: context.occasion || 'unknown',
    });

    // Update hallucination rate gauge
    this.hallucinationRate.set(
      { occasion: context.occasion || 'all' },
      result.isHallucination ? 1 : 0,
    );
  }

  /**
   * Add warning prefix to response with critical issues
   */
  private addWarningPrefix(
    response: string,
    _issues: DetectedIssue[],
  ): string {
    const warningPrefix = '[提示：该建议可能包含不准确信息，请谨慎参考]\n\n';
    return warningPrefix + response;
  }

  /**
   * Generate unique log ID
   */
  private generateLogId(): string {
    return `hallucination_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Unknown error';
  }
}

