// Body type to style recommendations
const BODY_TYPE_STYLE_MAP: Record<string, string[]> = {
  hourglass: ["french", "minimalist", "smart_casual"],
  rectangle: ["korean", "japanese", "streetwear"],
  triangle: ["french", "minimalist", "smart_casual"],
