// ==================== Service Implementation ====================

@Injectable()
export class DecisionEngineService {
  private readonly logger = new Logger(DecisionEngineService.name);
  private readonly apiKey: string;
  private readonly apiEndpoint: string;
  private readonly model: string;
  private readonly treeTtlMs = 30 * 60 * 1000; // 30 minutes
  private readonly treeConfigPrefix = "decision_tree:";
  private readonly useRedis: boolean;

  // In-memory cache for active decision trees
  private readonly treeCache = new Map<string, DecisionTree>();

  constructor(
    private configService: ConfigService,
    private prisma: PrismaService,
    private redisService: RedisService,
  ) {
    this.apiKey =
      this.configService.get<string>("AI_STYLIST_API_KEY", "") ||
      this.configService.get<string>("GLM_API_KEY", "") ||
      this.configService.get<string>("OPENAI_API_KEY", "");
    this.apiEndpoint =
      this.configService.get<string>("AI_STYLIST_API_ENDPOINT", "") ||
      this.configService.get<string>("GLM_API_ENDPOINT", "") ||
      this.configService.get<string>(
        "OPENAI_API_ENDPOINT",
        "https://open.bigmodel.cn/api/paas/v4",
      );
    this.model =
      this.configService.get<string>("AI_STYLIST_MODEL", "") ||
      this.configService.get<string>("GLM_MODEL", "") ||
      this.configService.get<string>("OPENAI_MODEL", "glm-5");
    this.useRedis = this.configService.get<string>("REDIS_URL") ? true : false;
  }

  // ==================== Decision Tree Construction ====================

  /**
   * Create a new decision tree based on user profile and context
   */
  async createDecisionTree(
    input: CreateDecisionTreeInput,
  ): Promise<DecisionTreeResult> {
    const { userId, sessionId, context, userProfile } = input;

    this.logger.log(`Creating decision tree for user ${userId}, session ${sessionId}`);

    // Build root node based on context and profile
    const rootNode = await this.buildRootNode(context, userProfile);

    // Create decision tree structure
    const tree: DecisionTree = {
      treeId: randomUUID(),
      sessionId,
      userId,
      rootNodeId: rootNode.nodeId,
      currentNodeId: rootNode.nodeId,
      nodes: new Map([[rootNode.nodeId, rootNode]]),
      decisions: [],
      status: "active",
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    // Persist tree
    await this.persistTree(tree);

    return {
      success: true,
      tree,
      currentNode: rootNode,
      isComplete: false,
      message: "决策树创建成功",
    };
  }

  /**
   * Build the root decision node based on user context and profile
   */
  private async buildRootNode(
    context: DecisionContext,
    userProfile: UserProfile,
  ): Promise<DecisionNode> {
    // Determine the best starting node type
    const nodeType = this.determineRootNodeType(context, userProfile);

    // Generate options based on node type and user profile
    const options = await this.generateNodeOptions(nodeType, context, userProfile);

    // Generate LLM reasoning
    const llmReasoning = await this.generateNodeReasoning(nodeType, context, userProfile, options);

    const node: DecisionNode = {
      nodeId: randomUUID(),
      nodeType,
      question: NODE_TYPE_QUESTIONS[nodeType],
      options,
      llmReasoning,
      depth: 0,
    };

    return node;
  }

  /**
   * Determine the most appropriate root node type based on user state
   */
  private determineRootNodeType(
    context: DecisionContext,
    userProfile: UserProfile,
  ): DecisionNodeType {
    // If user already has style preferences, start with fit or color
    if (context.preferredStyles.length > 0 || userProfile.stylePreferences.length > 0) {
      // If fit goals are specified, start with fit
      if (context.fitGoals.length > 0) {
        return "top"; // Start with clothing selection
      }
      // Otherwise start with color
      return "color";
    }

    // Default: start with style selection
    return "style";
  }

  /**
   * Generate options for a decision node
   */
  private async generateNodeOptions(
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
  ): Promise<DecisionOption[]> {
    let baseOptions: Array<{ id: string; label: string; description?: string; fitTypes?: string[] }>;

    switch (nodeType) {
      case "style":
        baseOptions = this.filterStyleOptions(userProfile);
        break;
      case "top":
        baseOptions = this.filterTopOptions(userProfile);
        break;
      case "bottom":
        baseOptions = this.filterBottomOptions(userProfile);
        break;
      case "color":
        baseOptions = this.generateColorOptions(userProfile);
        break;
      case "fit":
        baseOptions = this.filterFitGoalOptions(userProfile);
        break;
      default:
        baseOptions = STYLE_OPTIONS;
    }

    // Score each option
    const scoredOptions = baseOptions.map((opt) => {
      const scores = this.calculateOptionScores(opt, nodeType, context, userProfile);
      return {
        optionId: opt.id,
        content: this.buildOptionContent(opt, nodeType),
        displayName: opt.label,
        description: opt.description,
        fitScore: scores.fitScore,
        styleScore: scores.styleScore,
        preferenceScore: scores.preferenceScore,
        compositeScore: this.calculateCompositeScore(scores),
      };
    });

    // Sort by composite score and return top options
    return scoredOptions
      .sort((a, b) => b.compositeScore - a.compositeScore)
      .slice(0, 4);
  }

  /**
   * Filter style options based on user's body type and preferences
   */
  private filterStyleOptions(userProfile: UserProfile): typeof STYLE_OPTIONS {
    const bodyType = userProfile.bodyType?.toLowerCase() || "rectangle";
    const recommendedStyles = BODY_TYPE_STYLE_MAP[bodyType] || [];

    // Prioritize recommended styles
    const prioritized = [...STYLE_OPTIONS].sort((a, b) => {
      const aRecommended = recommendedStyles.includes(a.id);
      const bRecommended = recommendedStyles.includes(b.id);
      if (aRecommended && !bRecommended) {return -1;}
      if (!aRecommended && bRecommended) {return 1;}
      return 0;
    });

    return prioritized;
  }

  /**
   * Filter top options based on body type
   */
  private filterTopOptions(userProfile: UserProfile): typeof TOP_OPTIONS {
    const bodyType = userProfile.bodyType?.toLowerCase() || "rectangle";

    return TOP_OPTIONS.filter((opt) => {
      if (!opt.fitTypes) {return true;}
      return opt.fitTypes.includes(bodyType);
    });
  }

  /**
   * Filter bottom options based on body type
   */
  private filterBottomOptions(userProfile: UserProfile): typeof BOTTOM_OPTIONS {
    const bodyType = userProfile.bodyType?.toLowerCase() || "rectangle";

    return BOTTOM_OPTIONS.filter((opt) => {
      if (!opt.fitTypes) {return true;}
      return opt.fitTypes.includes(bodyType);
    });
  }

  /**
   * Generate color options based on user's color season
   */
  private generateColorOptions(userProfile: UserProfile): Array<{ id: string; label: string; description?: string }> {
    const colorSeason = userProfile.colorSeason?.toLowerCase() || "autumn";
    const recommendedColors =
      COLOR_SEASON_MAP[colorSeason] ?? COLOR_SEASON_MAP.autumn ?? [];

    // Add some neutral options
    const neutrals = ["黑色", "白色", "灰色", "藏青"];
    const allColors = [...new Set([...recommendedColors.slice(0, 3), ...neutrals.slice(0, 2)])];

    return allColors.map((color, index) => ({
      id: `color_${index}`,
      label: color,
      description: index < 3 ? "推荐色" : "百搭色",
    }));
  }

  /**
   * Filter fit goal options based on body type
   */
  private filterFitGoalOptions(userProfile: UserProfile): typeof FIT_GOAL_OPTIONS {
    const bodyType = userProfile.bodyType?.toLowerCase() || "rectangle";

    return FIT_GOAL_OPTIONS.filter((opt) => {
      if (opt.bodyTypes.length === 0) {return true;} // Universal options
      return opt.bodyTypes.includes(bodyType);
    });
  }

  /**
   * Build option content based on node type
   */
  private buildOptionContent(
    opt: { id: string; label: string; fitTypes?: string[] },
    nodeType: DecisionNodeType,
  ): DecisionOptionContent {
    const content: DecisionOptionContent = {};

    switch (nodeType) {
      case "style":
        content.styleTags = [opt.label];
        break;
      case "top":
        content.category = ClothingCategory.tops;
        content.fitAttributes = [opt.id];
        break;
      case "bottom":
        content.category = ClothingCategory.bottoms;
        content.fitAttributes = [opt.id];
        break;
      case "color":
        content.colorTags = [opt.label];
        break;
      case "fit":
        content.fitAttributes = [opt.id];
        break;
    }

    return content;
  }

  // ==================== Option Scoring Algorithm ====================

  /**
   * Calculate all scores for an option
   */
  private calculateOptionScores(
    opt: { id: string; label: string; fitTypes?: string[] },
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
  ): { fitScore: number; styleScore: number; preferenceScore: number } {
    return {
      fitScore: this.calculateFitScore(opt, nodeType, userProfile),
      styleScore: this.calculateStyleScore(opt, nodeType, context, userProfile),
      preferenceScore: this.calculatePreferenceScore(opt, nodeType, userProfile),
    };
  }

  /**
   * Calculate fit score based on body type compatibility
   */
  private calculateFitScore(
    opt: { id: string; label: string; fitTypes?: string[] },
    nodeType: DecisionNodeType,
    userProfile: UserProfile,
  ): number {
    const bodyType = userProfile.bodyType?.toLowerCase();

    if (!bodyType) {return 50;} // Default score when no body type info

    // Check if option has fit type recommendations
    if (opt.fitTypes && opt.fitTypes.length > 0) {
      return opt.fitTypes.includes(bodyType) ? 85 : 40;
    }

    // Body type specific scoring
    const bodyTypeScores: Record<string, Record<string, number>> = {
      hourglass: {
        fitted: 90, regular: 75, loose: 60, oversized: 50,
        slim: 85, straight: 70, wide: 65, "skirt_a": 90,
      },
      rectangle: {
        fitted: 70, regular: 80, loose: 75, oversized: 85,
        slim: 75, straight: 80, wide: 70, "skirt_a": 70,
      },
      triangle: {
        fitted: 60, regular: 75, loose: 80, oversized: 70,
        slim: 55, straight: 85, wide: 90, "skirt_a": 90,
      },
      inverted_triangle: {
        fitted: 60, regular: 70, loose: 85, oversized: 90,
        slim: 80, straight: 75, wide: 70, "skirt_a": 60,
      },
      oval: {
        fitted: 45, regular: 70, loose: 85, oversized: 80,
        slim: 50, straight: 75, wide: 90, "skirt_a": 75,
      },
    };

    const typeScores = bodyTypeScores[bodyType];
    const optionScore = typeScores?.[opt.id];
    if (optionScore !== undefined) {
      return optionScore;
    }

    return 60;
  }

  /**
   * Calculate style score based on context and preferences
   */
  private calculateStyleScore(
    opt: { id: string; label: string },
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
  ): number {
    let score = 50; // Base score

    // Check against preferred styles from context
    if (context.preferredStyles.length > 0) {
      const isPreferred = context.preferredStyles.some(
        (style) => style.toLowerCase().includes(opt.label.toLowerCase()) ||
                   opt.label.toLowerCase().includes(style.toLowerCase()),
      );
      if (isPreferred) {score += 30;}
    }

    // Check against style avoidances
    if (context.styleAvoidances.length > 0) {
      const isAvoided = context.styleAvoidances.some(
        (avoid) => avoid.toLowerCase().includes(opt.label.toLowerCase()) ||
                   opt.label.toLowerCase().includes(avoid.toLowerCase()),
      );
      if (isAvoided) {score -= 40;}
    }

    // Check against user's historical preferences
    if (userProfile.stylePreferences.length > 0) {
      const matchesPreference = userProfile.stylePreferences.some(
        (pref) => pref.toLowerCase().includes(opt.label.toLowerCase()) ||
                  opt.label.toLowerCase().includes(pref.toLowerCase()),
      );
      if (matchesPreference) {score += 20;}
    }

    // Check occasion fit
    if (context.occasion) {
      const occasionStyleBonus = this.getOccasionStyleBonus(opt.id, context.occasion);
      score += occasionStyleBonus;
    }

    return Math.max(0, Math.min(100, score));
  }

  /**
   * Get bonus score for style-occasion match
   */
  private getOccasionStyleBonus(styleId: string, occasion: string): number {
    const occasionStyles: Record<string, string[]> = {
      interview: ["smart_casual", "minimalist"],
      work: ["smart_casual", "minimalist", "french"],
      date: ["french", "korean", "japanese"],
      travel: ["korean", "sporty", "streetwear"],
      party: ["streetwear", "vintage", "french"],
      daily: ["japanese", "korean", "minimalist"],
      campus: ["korean", "japanese", "sporty"],
    };

    const recommendedStyles = occasionStyles[occasion] || [];
    return recommendedStyles.includes(styleId) ? 15 : 0;
  }

  /**
   * Calculate preference score based on user behavior history
   */
  private calculatePreferenceScore(
    opt: { id: string; label: string },
    nodeType: DecisionNodeType,
    userProfile: UserProfile,
  ): number {
    let score = 50; // Base score

    // Analyze behavior history
    const relevantBehaviors = userProfile.behaviorHistory.filter((b) => {
      if (!b.category) {return false;}
      return b.category.toLowerCase() === nodeType.toLowerCase() ||
             b.value?.toLowerCase().includes(opt.label.toLowerCase());
    });

    // Weight behaviors by recency and type
    const now = Date.now();
    let totalWeight = 0;

    for (const behavior of relevantBehaviors) {
      const age = now - behavior.timestamp.getTime();
      const recencyFactor = Math.max(0.1, 1 - age / (30 * 24 * 60 * 60 * 1000)); // Decay over 30 days

      // Positive behaviors boost score
      if (["view", "like", "favorite", "purchase", "try_on_complete"].includes(behavior.type)) {
        totalWeight += behavior.weight * recencyFactor;
      }
      // Negative behaviors reduce score
      else if (["unfavorite", "dislike"].includes(behavior.type)) {
        totalWeight -= behavior.weight * recencyFactor;
      }
    }

    score += Math.min(30, totalWeight * 10); // Cap bonus at 30

    // Check color preferences for color node type
    if (nodeType === "color" && userProfile.colorPreferences.length > 0) {
      const colorMatch = userProfile.colorPreferences.some(
        (color) => color.toLowerCase().includes(opt.label.toLowerCase()) ||
                   opt.label.toLowerCase().includes(color.toLowerCase()),
      );
      if (colorMatch) {score += 25;}
    }

    return Math.max(0, Math.min(100, score));
  }

  /**
   * Calculate composite score from individual scores
   * Formula: fit * 0.3 + style * 0.3 + preference * 0.4
   */
  private calculateCompositeScore(scores: {
    fitScore: number;
    styleScore: number;
    preferenceScore: number;
  }): number {
    return (
      scores.fitScore * 0.3 +
      scores.styleScore * 0.3 +
      scores.preferenceScore * 0.4
    );
  }

  // ==================== LLM Reasoning ====================

  /**
   * Generate LLM reasoning for a decision node
   */
  private async generateNodeReasoning(
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
    options: DecisionOption[],
  ): Promise<string> {
    // Fallback reasoning if LLM is not available
    const fallbackReasoning = this.buildFallbackReasoning(nodeType, context, userProfile, options);

    if (!this.apiKey || !this.apiEndpoint || !this.model) {
      return fallbackReasoning;
    }

    try {
      const prompt = this.buildReasoningPrompt(nodeType, context, userProfile, options);
      const response = await this.callLLM([
        {
          role: "system",
          content: "你是一个专业的穿搭顾问。请用简洁的中文解释为什么推荐这些选项，控制在100字以内。",
        },
        {
          role: "user",
          content: prompt,
        },
      ]);

      const content = response.choices[0]?.message?.content?.trim();
      return content || fallbackReasoning;
    } catch (error) {
      this.logger.warn(`Failed to generate LLM reasoning: ${error}`);
      return fallbackReasoning;
    }
  }

  /**
   * Build fallback reasoning without LLM
   */
  private buildFallbackReasoning(
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
    options: DecisionOption[],
  ): string {
    const topOption = options[0];
    if (!topOption) {
      return "已根据你的信息生成当前推荐。";
    }
    const reasons: string[] = [];

    if (nodeType === "style") {
      if (userProfile.bodyType) {
        reasons.push(`根据你的${this.getBodyTypeDisplayName(userProfile.bodyType)}体型`);
      }
      if (context.occasion) {
        reasons.push(`适合${this.getOccasionDisplayName(context.occasion)}场景`);
      }
      reasons.push(`推荐${topOption.displayName}风格`);
    } else if (nodeType === "color") {
      if (userProfile.colorSeason) {
        reasons.push(`基于你的${this.getColorSeasonDisplayName(userProfile.colorSeason)}型色彩`);
      }
      reasons.push(`${topOption.displayName}会很好看`);
    } else if (nodeType === "fit") {
      reasons.push(`${topOption.displayName}效果最适合你的需求`);
    } else {
      reasons.push(`根据你的体型和偏好，${topOption.displayName}是不错的选择`);
    }

    return reasons.join("，") + "。";
  }

  /**
   * Build prompt for LLM reasoning
   */
  private buildReasoningPrompt(
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
    options: DecisionOption[],
  ): string {
    const topOptions = options.slice(0, 3).map((o) => o.displayName).join("、");

    return JSON.stringify({
      nodeType,
      occasion: context.occasion,
      bodyType: userProfile.bodyType,
      colorSeason: userProfile.colorSeason,
      preferredStyle: [...context.preferredStyles, ...userProfile.stylePreferences][0],
      topOptions,
      task: "请简要解释为什么推荐这些选项",
    }, null, 2);
  }

  // ==================== User Decision Recording ====================

  /**
   * Record a user's decision and advance the decision tree
   */
  async recordDecision(input: RecordDecisionInput): Promise<DecisionTreeResult> {
    const { sessionId, nodeId, chosenOptionId, rejectedOptionIds = [], decisionTime = 0 } = input;

    this.logger.log(`Recording decision for session ${sessionId}, node ${nodeId}`);

    // Get current tree
    const tree = await this.getTree(sessionId);
    if (!tree) {
      return {
        success: false,
        isComplete: false,
        message: "决策树不存在或已过期",
      };
    }

    // Get current node
    const currentNode = tree.nodes.get(nodeId);
    if (!currentNode) {
      return {
        success: false,
        isComplete: false,
        message: "决策节点不存在",
      };
    }

    // Record the decision
    const decision: UserDecision = {
      id: randomUUID(),
      sessionId,
      nodeId,
      nodeType: currentNode.nodeType,
      chosenOptionId,
      rejectedOptionIds,
      decisionTime,
      timestamp: new Date(),
    };

    tree.decisions.push(decision);
    tree.updatedAt = new Date();

    // Persist decision to database
    await this.persistDecision(decision, tree.userId);

    // Update user preferences based on decision
    await this.updatePreferencesFromDecision(tree.userId, decision, currentNode);

    // Determine next node type
    const nextNodeType = this.getNextNodeType(currentNode.nodeType, tree);

    // Check if tree is complete
    if (!nextNodeType) {
      tree.status = "completed";
      await this.persistTree(tree);

      return {
        success: true,
        tree,
        isComplete: true,
        message: "决策流程已完成",
      };
    }

    // Build next node
    const context = await this.buildContextFromDecisions(tree);
    const userProfile = await this.getUserProfile(tree.userId);

    const nextNode = await this.buildNextNode(nextNodeType, context, userProfile, currentNode);
    nextNode.parentNodeId = currentNode.nodeId;

    tree.nodes.set(nextNode.nodeId, nextNode);
    tree.currentNodeId = nextNode.nodeId;
    tree.updatedAt = new Date();

    await this.persistTree(tree);

    return {
      success: true,
      tree,
      currentNode,
      nextNode,
      isComplete: false,
      message: "决策已记录",
    };
  }

  /**
   * Determine the next node type based on current node and decision history
   */
  private getNextNodeType(
    currentNodeType: DecisionNodeType,
    tree: DecisionTree,
  ): DecisionNodeType | null {
    const decisionTypes = tree.decisions.map((d) => d.nodeType);
    const currentIndex = DECISION_NODE_TYPES.indexOf(currentNodeType);

    // Check if all node types have been covered
    if (decisionTypes.length >= 4) {
      return null; // Tree complete
    }

    // Determine next unvisited node type
    for (let i = currentIndex + 1; i < DECISION_NODE_TYPES.length; i++) {
      const nodeType = DECISION_NODE_TYPES[i];
      if (nodeType && !decisionTypes.includes(nodeType)) {
        return nodeType;
      }
    }

    // Wrap around to beginning
    for (let i = 0; i < currentIndex; i++) {
      const nodeType = DECISION_NODE_TYPES[i];
      if (nodeType && !decisionTypes.includes(nodeType)) {
        return nodeType;
      }
    }

    return null;
  }

  /**
   * Build context from recorded decisions
   */
  private async buildContextFromDecisions(tree: DecisionTree): Promise<DecisionContext> {
    const context: DecisionContext = {
      preferredStyles: [],
      styleAvoidances: [],
      fitGoals: [],
      preferredColors: [],
    };

    for (const decision of tree.decisions) {
      const node = tree.nodes.get(decision.nodeId);
      if (!node) {continue;}

      const chosenOption = node.options.find((o) => o.optionId === decision.chosenOptionId);
      if (!chosenOption) {continue;}

      switch (node.nodeType) {
        case "style":
          if (chosenOption.content.styleTags) {
            context.preferredStyles.push(...chosenOption.content.styleTags);
          }
          break;
        case "color":
          if (chosenOption.content.colorTags) {
            context.preferredColors.push(...chosenOption.content.colorTags);
          }
          break;
        case "fit":
          if (chosenOption.content.fitAttributes) {
            context.fitGoals.push(...chosenOption.content.fitAttributes);
          }
          break;
      }

      // Record rejected styles as avoidances
      for (const rejectedId of decision.rejectedOptionIds) {
        const rejectedOption = node.options.find((o) => o.optionId === rejectedId);
        if (rejectedOption?.content.styleTags && node.nodeType === "style") {
          context.styleAvoidances.push(...rejectedOption.content.styleTags);
        }
      }
    }

    return context;
  }

  /**
   * Build next decision node
   */
  private async buildNextNode(
    nodeType: DecisionNodeType,
    context: DecisionContext,
    userProfile: UserProfile,
    parentNode: DecisionNode,
  ): Promise<DecisionNode> {
    const options = await this.generateNodeOptions(nodeType, context, userProfile);
    const llmReasoning = await this.generateNodeReasoning(nodeType, context, userProfile, options);

    return {
      nodeId: randomUUID(),
      nodeType,
      question: NODE_TYPE_QUESTIONS[nodeType],
      options,
      llmReasoning,
      parentNodeId: parentNode.nodeId,
      depth: parentNode.depth + 1,
    };
  }

  // ==================== Decision History & Persistence ====================

  /**
   * Persist decision to database
   */
  private async persistDecision(
    decision: UserDecision,
    userId: string,
  ): Promise<void> {
    try {
      await this.prisma.userDecision.create({
        data: {
          id: decision.id,
          userId,
          sessionId: decision.sessionId,
          nodeId: decision.nodeId,
          nodeType: decision.nodeType,
          chosenOptionId: decision.chosenOptionId,
          rejectedOptionIds: decision.rejectedOptionIds,
          decisionTime: decision.decisionTime,
          timestamp: decision.timestamp,
        },
      });
    } catch (error) {
      this.logger.error(`Failed to persist decision: ${error}`);
      // Continue even if persistence fails
    }
  }

  /**
   * Update user preferences based on decision
   */
  private async updatePreferencesFromDecision(
    userId: string,
    decision: UserDecision,
    node: DecisionNode,
  ): Promise<void> {
    const chosenOption = node.options.find((o) => o.optionId === decision.chosenOptionId);
    if (!chosenOption) {return;}

    try {
      // Update preference weights
      const category = `decision_${node.nodeType}`;

      // Increase weight for chosen option
      await this.prisma.userPreferenceWeight.upsert({
        where: {
          userId_category_key: {
            userId,
            category,
            key: chosenOption.displayName,
          },
        },
        create: {
          userId,
          category,
          key: chosenOption.displayName,
          weight: 1.0,
          source: "decision_tree",
        },
        update: {
          weight: { increment: 0.5 },
        },
      });

      // Decrease weight for rejected options
      for (const rejectedId of decision.rejectedOptionIds) {
        const rejectedOption = node.options.find((o) => o.optionId === rejectedId);
        if (rejectedOption) {
          await this.prisma.userPreferenceWeight.upsert({
            where: {
              userId_category_key: {
                userId,
                category,
                key: rejectedOption.displayName,
              },
            },
            create: {
              userId,
              category,
              key: rejectedOption.displayName,
              weight: -0.3,
              source: "decision_tree",
            },
            update: {
              weight: { decrement: 0.3 },
            },
          });
        }
      }

      // Record behavior event
      await this.prisma.userBehaviorEvent.create({
        data: {
          sessionId: decision.sessionId,
          userId,
          eventType: "recommendation_click",
          category: "decision_tree",
          action: decision.nodeType,
          targetType: "decision_option",
          targetId: decision.chosenOptionId,
          metadata: {
            nodeId: decision.nodeId,
            chosenOption: chosenOption.displayName,
            rejectedCount: decision.rejectedOptionIds.length,
            decisionTime: decision.decisionTime,
          },
        },
      });
    } catch (error) {
      this.logger.error(`Failed to update preferences: ${error}`);
    }
  }

  /**
   * Persist decision tree to cache
   */
  private async persistTree(tree: DecisionTree): Promise<void> {
    // Serialize tree for storage
    const serializedTree = this.serializeTree(tree);

    // Store in memory cache
    this.treeCache.set(tree.sessionId, tree);

    // Store in Redis if available
    if (this.useRedis) {
      try {
        // Convert ms to seconds for setex
        const ttlSeconds = Math.ceil(this.treeTtlMs / 1000);
        await this.redisService.setex(
          `${this.treeConfigPrefix}${tree.sessionId}`,
          ttlSeconds,
          serializedTree,
        );
      } catch (error) {
        this.logger.warn(`Failed to persist tree to Redis: ${error}`);
      }
    }
  }

  /**
   * Get decision tree from cache
   */
  private async getTree(sessionId: string): Promise<DecisionTree | null> {
    // Check memory cache first
    const cachedTree = this.treeCache.get(sessionId);
    if (cachedTree) {
      return cachedTree;
    }

    // Check Redis if available
    if (this.useRedis) {
      try {
        const serializedTree = await this.redisService.get(
          `${this.treeConfigPrefix}${sessionId}`,
        );
        if (serializedTree) {
          const tree = this.deserializeTree(serializedTree);
          this.treeCache.set(sessionId, tree);
          return tree;
        }
      } catch (error) {
        this.logger.warn(`Failed to get tree from Redis: ${error}`);
      }
    }

    return null;
  }

  /**
   * Serialize decision tree for storage
   */
  private serializeTree(tree: DecisionTree): string {
    return JSON.stringify({
      treeId: tree.treeId,
      sessionId: tree.sessionId,
      userId: tree.userId,
      rootNodeId: tree.rootNodeId,
      currentNodeId: tree.currentNodeId,
      nodes: Array.from(tree.nodes.entries()),
      decisions: tree.decisions,
      status: tree.status,
      createdAt: tree.createdAt,
      updatedAt: tree.updatedAt,
    });
  }

  /**
   * Deserialize decision tree from storage
   */
  private deserializeTree(data: string): DecisionTree {
    const parsed = JSON.parse(data) as Omit<DecisionTree, 'nodes' | 'decisions' | 'createdAt' | 'updatedAt'> & {
      nodes: [string, DecisionNode][];
      decisions: SerializedDecision[];
      createdAt: string;
      updatedAt: string;
    };
    return {
      ...parsed,
      nodes: new Map(parsed.nodes),
      createdAt: new Date(parsed.createdAt),
      updatedAt: new Date(parsed.updatedAt),
      decisions: parsed.decisions.map((d): UserDecision => ({
        ...d,
        timestamp: new Date(d.timestamp),
      })),
    };
  }

  // ==================== User Profile & Context ====================

  /**
   * Get user profile with behavior history
   */
  async getUserProfile(userId: string): Promise<UserProfile> {
    const [profile, behaviors, preferenceWeights] = await Promise.all([
      this.prisma.userProfile.findUnique({
        where: { userId },
        include: {
          user: {
            select: {
              styleProfiles: {
                where: { isActive: true },
                select: { name: true, keywords: true },
              },
            },
          },
        },
      }),
      this.prisma.userBehaviorEvent.findMany({
        where: { userId },
        orderBy: { createdAt: "desc" },
        take: 100,
      }),
      this.prisma.userPreferenceWeight.findMany({
        where: { userId },
      }),
    ]);

    // Extract style preferences
    const stylePreferences: string[] = [];
    if (profile?.stylePreferences) {
      const prefs = extractStringArray(profile.stylePreferences);
      stylePreferences.push(...prefs);
    }

    // Add from style profiles
    if (profile?.user?.styleProfiles) {
      for (const sp of profile.user.styleProfiles) {
        stylePreferences.push(sp.name, ...sp.keywords);
      }
    }

    // Add from preference weights
    const styleWeights = preferenceWeights.filter((w) => w.category === "decision_style");
    stylePreferences.push(
      ...styleWeights.sort((a, b) => Number(b.weight) - Number(a.weight)).map((w) => w.key),
    );

    // Extract color preferences
    const colorPreferences: string[] = [];
    if (profile?.colorPreferences) {
      const prefs = extractStringArray(profile.colorPreferences);
      colorPreferences.push(...prefs);
    }

    // Build behavior history
    const behaviorHistory: BehaviorRecord[] = behaviors.map((b) => ({
      type: b.action,
      category: b.category,
      value: b.targetId || undefined,
      weight: this.getBehaviorWeight(b.eventType),
      timestamp: b.createdAt,
    }));

    return {
      userId,
      bodyType: profile?.bodyType || undefined,
      skinTone: profile?.skinTone || undefined,
      colorSeason: profile?.colorSeason || undefined,
      height: profile?.height || undefined,
      weight: profile?.weight || undefined,
      stylePreferences: [...new Set(stylePreferences)],
      colorPreferences: [...new Set(colorPreferences)],
      fitGoals: [],
      behaviorHistory,
    };
  }

  /**
   * Get behavior weight based on event type
   */
  private getBehaviorWeight(eventType: string): number {
    const weights: Record<string, number> = {
      recommendation_click: 1.0,
      try_on_complete: 1.5,
      favorite: 1.2,
      purchase: 2.0,
      unfavorite: -0.5,
    };
    return weights[eventType] || 0.5;
  }

  // ==================== Query Interfaces ====================

  /**
   * Get decision history for a session
   */
  async getSessionDecisions(sessionId: string): Promise<UserDecision[]> {
    const decisions = await this.prisma.userDecision.findMany({
      where: { sessionId },
      orderBy: { timestamp: "asc" },
    });

    return decisions.map((d) => ({
      id: d.id,
      sessionId: d.sessionId,
      nodeId: d.nodeId,
      nodeType: d.nodeType as DecisionNodeType,
      chosenOptionId: d.chosenOptionId,
      rejectedOptionIds: d.rejectedOptionIds,
      decisionTime: d.decisionTime,
      timestamp: d.timestamp,
    }));
  }

  /**
   * Get decision statistics for a user
   */
  async getUserDecisionStats(userId: string): Promise<{
    totalDecisions: number;
    decisionsByType: Record<string, number>;
    topChoices: Array<{ choice: string; count: number }>;
    averageDecisionTime: number;
  }> {
    const decisions = await this.prisma.userDecision.findMany({
      where: { userId },
    });

    const decisionsByType: Record<string, number> = {};
    const choiceCounts: Record<string, number> = {};
    let totalTime = 0;
    let validTimeCount = 0;

    for (const decision of decisions) {
      // Count by type
      decisionsByType[decision.nodeType] = (decisionsByType[decision.nodeType] || 0) + 1;

      // Count choices (would need to join with option data for display names)
      choiceCounts[decision.chosenOptionId] = (choiceCounts[decision.chosenOptionId] || 0) + 1;

      // Sum decision times
      if (decision.decisionTime > 0) {
        totalTime += decision.decisionTime;
        validTimeCount++;
      }
    }

    const topChoices = Object.entries(choiceCounts)
      .map(([choice, count]) => ({ choice, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    return {
      totalDecisions: decisions.length,
      decisionsByType,
      topChoices,
      averageDecisionTime: validTimeCount > 0 ? totalTime / validTimeCount : 0,
    };
  }

  /**
   * Get current decision node for a session
   */
  async getCurrentNode(sessionId: string): Promise<DecisionNode | null> {
    const tree = await this.getTree(sessionId);
    if (!tree) {return null;}

    return tree.nodes.get(tree.currentNodeId) || null;
  }

  /**
   * Skip a decision node
   */
  async skipNode(sessionId: string, nodeId: string): Promise<DecisionTreeResult> {
    const tree = await this.getTree(sessionId);
    if (!tree) {
      return {
        success: false,
        isComplete: false,
        message: "决策树不存在",
      };
    }

    const currentNode = tree.nodes.get(nodeId);
    if (!currentNode) {
      return {
        success: false,
        isComplete: false,
        message: "节点不存在",
      };
    }

    // Record skip as a decision with no choice
    const decision: UserDecision = {
      id: randomUUID(),
      sessionId,
      nodeId,
      nodeType: currentNode.nodeType,
      chosenOptionId: "skipped",
      rejectedOptionIds: [],
      decisionTime: 0,
      timestamp: new Date(),
    };

    tree.decisions.push(decision);

    // Move to next node
    const nextNodeType = this.getNextNodeType(currentNode.nodeType, tree);

    if (!nextNodeType) {
      tree.status = "completed";
      await this.persistTree(tree);
      return {
        success: true,
        tree,
        isComplete: true,
        message: "决策流程已完成",
      };
    }

    const context = await this.buildContextFromDecisions(tree);
    const userProfile = await this.getUserProfile(tree.userId);

    const nextNode = await this.buildNextNode(nextNodeType, context, userProfile, currentNode);
    nextNode.parentNodeId = currentNode.nodeId;

    tree.nodes.set(nextNode.nodeId, nextNode);
    tree.currentNodeId = nextNode.nodeId;
    tree.updatedAt = new Date();

    await this.persistTree(tree);

    return {
      success: true,
      tree,
      currentNode,
      nextNode,
      isComplete: false,
      message: "已跳过当前节点",
    };
  }

  // ==================== Helper Methods ====================

  /**
   * Call LLM API
   */
  private async callLLM(
    messages: Array<{ role: string; content: string }>,
  ): Promise<LlmChatCompletionResponse> {
    const response = await fetch(`${this.apiEndpoint}/chat/completions`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${this.apiKey}`,
      },
      body: JSON.stringify({
        model: this.model,
        messages,
        max_tokens: 200,
        temperature: 0.7,
      }),
    });

    if (!response.ok) {
      throw new Error(`LLM API error: ${response.status}`);
    }

    return response.json() as Promise<LlmChatCompletionResponse>;
  }

  /**
   * Get display name for body type
   */
  private getBodyTypeDisplayName(bodyType: string): string {
    const names: Record<string, string> = {
      hourglass: "X型",
      rectangle: "H型",
      triangle: "A型",
      inverted_triangle: "Y型",
      oval: "O型",
    };
    return names[bodyType.toLowerCase()] || bodyType;
  }

  /**
   * Get display name for occasion
   */
  private getOccasionDisplayName(occasion: string): string {
    const names: Record<string, string> = {
      interview: "面试",
      work: "通勤",
      date: "约会",
      travel: "出游",
      party: "聚会",
      daily: "日常",
      campus: "校园",
    };
    return names[occasion.toLowerCase()] || occasion;
  }

  /**
   * Get display name for color season
   */
  private getColorSeasonDisplayName(season: string): string {
    const names: Record<string, string> = {
      spring: "春季",
      summer: "夏季",
      autumn: "秋季",
      winter: "冬季",
    };
    return names[season.toLowerCase()] || season;
  }
}

/**
 * @fileoverview NL Slot Extractor Service - LLM-powered slot extraction.
 *
 * Uses the LLM provider to extract structured styling preferences from
 * natural language Chinese messages. Falls back to keyword-based extraction
 * when the LLM is unavailable.
 *
 * @module NlSlotExtractorService
 */

import { Injectable, Logger } from "@nestjs/common";

import { LlmProviderService } from "./llm-provider.service";
import { SLOT_EXTRACTION_PROMPT } from "./prompts/system-prompt";

// Import shared types
import {
  type ExtractedSlots,
  type ExtractionResult,
} from "./types";

/**
 * Valid values for slot fields.
 */
const VALID_OCCASIONS = [
  "interview",
  "work",
  "date",
  "travel",
  "party",
  "daily",
  "campus",
] as const;

const VALID_STYLES = [
  "极简",
  "韩系",
  "法式",
  "日系",
  "轻正式",
  "街头",
  "运动",
  "复古",
] as const;

const VALID_FIT_GOALS = [
  "显高",
  "显瘦",
  "修饰胯部",
  "平衡肩线",
  "利落专业",
  "减龄",
  "提气色",
] as const;

const VALID_COLORS = [
  "白色",
  "黑色",
  "灰色",
  "蓝色",
  "米色",
  "卡其",
  "粉色",
  "绿色",
  "酒红",
  "驼色",
  "焦糖",
  "藏青",
  "米白",
  "奶白",
];

/**
 * NL Slot Extractor Service
 *
 * Provides two extraction strategies:
 * 1. LLM-powered extraction (primary) - Uses the configured LLM to understand
 *    Chinese natural language and extract structured data
 * 2. Keyword-based extraction (fallback) - Uses regex patterns and keyword
 *    matching when LLM is unavailable
 *
 * @example
 * ```typescript
 * const result = await nlExtractor.extractFromMessage(
 *   "我要一套面试穿搭，极简风格，预算1000以内，想显高一点"
 * );
 * // result.slots = {
 * //   occasion: "interview",
 * //   preferredStyles: ["极简"],
 * //   fitGoals: ["显高"],
 * //   budgetMax: 1000,
 * // }
 * ```
 */
@Injectable()
export class NlSlotExtractorService {
  private readonly logger = new Logger(NlSlotExtractorService.name);

  constructor(private readonly llmProvider: LlmProviderService) {}

  /**
   * Extract structured slots from a user message using LLM.
   *
   * Falls back to keyword-based extraction if LLM is unavailable.
   */
  async extractFromMessage(
    message: string,
    existingSlots?: Partial<ExtractedSlots>,
  ): Promise<ExtractionResult> {
    if (!message?.trim()) {
      return {
        slots: {},
        rawResponse: null,
        usedLlm: false,
        confidence: 0,
      };
    }

    // Try LLM extraction first
    if (this.llmProvider.isConfigured) {
      try {
        const result = await this.extractWithLlm(message, existingSlots);
        if (result.confidence > 0.3) {
          return result;
        }

        this.logger.debug(
          `LLM extraction confidence too low (${result.confidence}), trying keyword fallback`,
        );
      } catch (error) {
        this.logger.warn(
          `LLM slot extraction failed, falling back to keywords: ${error instanceof Error ? error.message : String(error)}`,
        );
      }
    }

    // Keyword fallback
    return this.extractWithKeywords(message);
  }

  /**
   * Extract slots using LLM.
   */
  private async extractWithLlm(
    message: string,
    existingSlots?: Partial<ExtractedSlots>,
  ): Promise<ExtractionResult> {
    const contextParts: string[] = [];
    if (existingSlots) {
      const nonEmpty = Object.entries(existingSlots)
        .filter(([, value]) => {
          if (Array.isArray(value)) {
            return value.length > 0;
          }
          return value !== null && value !== undefined;
        })
        .map(([key, value]) => `${key}: ${JSON.stringify(value)}`);

      if (nonEmpty.length > 0) {
        contextParts.push(`之前已收集的信息：\n${nonEmpty.join("\n")}`);
      }
    }

    const userMessage = contextParts.length > 0
      ? `${contextParts.join("\n\n")}\n\n用户最新消息：${message}`
      : `用户消息：${message}`;

    const response = await this.llmProvider.chatStructured<ExtractedSlots>({
      messages: [
        { role: "system", content: SLOT_EXTRACTION_PROMPT },
        { role: "user", content: userMessage },
      ],
      maxTokens: 500,
      temperature: 0.1,
      requestId: `slot-extract-${Date.now()}`,
    });

    if (!response.parsed) {
      return {
        slots: {},
        rawResponse: response.raw.content,
        usedLlm: true,
        confidence: 0,
      };
    }

    const slots = this.validateAndNormalizeSlots(response.parsed as unknown as Record<string, unknown>);

    return {
      slots,
      rawResponse: response.raw.content,
      usedLlm: true,
      confidence: this.calculateConfidence(slots, message),
    };
  }

  /**
   * Extract slots using keyword matching (fallback).
   */
  private extractWithKeywords(message: string): ExtractionResult {
    const slots: Partial<ExtractedSlots> = {};

    const occasion = this.extractOccasion(message);
    if (occasion) {
      slots.occasion = occasion;
    }

    const styles = this.extractStyles(message);
    if (styles.length > 0) {
      slots.preferredStyles = styles;
    }

    const goals = this.extractFitGoals(message);
    if (goals.length > 0) {
      slots.fitGoals = goals;
    }

    const colors = this.extractColors(message);
    if (colors.length > 0) {
      slots.preferredColors = colors;
    }

    const budget = this.extractBudget(message);
    if (budget.max !== undefined) {
      slots.budgetMax = budget.max;
    }
    if (budget.min !== undefined) {
      slots.budgetMin = budget.min;
    }

    const avoidances = this.extractStyleAvoidances(message);
    if (avoidances.length > 0) {
      slots.styleAvoidances = avoidances;
    }

    slots.photoSkip = this.isPhotoSkipMessage(message);

    return {
      slots,
      rawResponse: null,
      usedLlm: false,
      confidence: this.calculateConfidence(slots, message),
    };
  }

  /**
   * Validate and normalize extracted slots against allowed values.
   */
  private validateAndNormalizeSlots(raw: Record<string, unknown>): Partial<ExtractedSlots> {
    const slots: Partial<ExtractedSlots> = {};

    // Validate occasion
    if (typeof raw.occasion === "string") {
      const normalizedOccasion = raw.occasion.toLowerCase().trim();
      if ((VALID_OCCASIONS as readonly string[]).includes(normalizedOccasion)) {
        slots.occasion = normalizedOccasion;
      }
    }

    // Validate preferred styles
    if (Array.isArray(raw.preferredStyles)) {
      slots.preferredStyles = raw.preferredStyles
        .filter((s: unknown) => typeof s === "string")
        .filter((s: string) => (VALID_STYLES as readonly string[]).includes(s));
    }

    // Validate fit goals
    if (Array.isArray(raw.fitGoals)) {
      slots.fitGoals = raw.fitGoals
        .filter((g: unknown) => typeof g === "string")
        .filter((g: string) => (VALID_FIT_GOALS as readonly string[]).includes(g));
    }

    // Validate colors (more lenient - accept any string)
    if (Array.isArray(raw.preferredColors)) {
      slots.preferredColors = raw.preferredColors
        .filter((c: unknown) => typeof c === "string" && c.trim().length > 0);
    }

    // Validate style avoidances
    if (Array.isArray(raw.styleAvoidances)) {
      slots.styleAvoidances = raw.styleAvoidances
        .filter((s: unknown) => typeof s === "string" && s.trim().length > 0);
    }

    // Validate budget
    if (typeof raw.budgetMax === "number" && raw.budgetMax > 0) {
      slots.budgetMax = raw.budgetMax;
    }
    if (typeof raw.budgetMin === "number" && raw.budgetMin > 0) {
      slots.budgetMin = raw.budgetMin;
    }

    // Validate weather
    if (typeof raw.weather === "string" && raw.weather.trim().length > 0) {
      slots.weather = raw.weather.trim();
    }

    // Validate photo skip
    if (typeof raw.photoSkip === "boolean") {
      slots.photoSkip = raw.photoSkip;
    }

    return slots;
  }

  /**
   * Calculate confidence score for extracted slots.
   */
  private calculateConfidence(
    slots: Partial<ExtractedSlots>,
    originalMessage: string,
  ): number {
    if (!originalMessage?.trim()) {
      return 0;
    }

    let score = 0;
    let maxScore = 0;

    // Message length factor (longer messages are more likely to contain useful info)
    const lengthFactor = Math.min(originalMessage.length / 20, 1);
    maxScore += 0.1;
    score += 0.1 * lengthFactor;

    // Occasion extraction
    maxScore += 0.25;
    if (slots.occasion) {
      score += 0.25;
    }

    // Style extraction
    maxScore += 0.2;
    if (slots.preferredStyles && slots.preferredStyles.length > 0) {
      score += 0.2;
    }

    // Fit goals extraction
    maxScore += 0.15;
    if (slots.fitGoals && slots.fitGoals.length > 0) {
      score += 0.15;
    }

    // Budget extraction
    maxScore += 0.15;
    if (slots.budgetMax !== undefined && slots.budgetMax !== null) {
      score += 0.15;
    }

    // Color extraction
    maxScore += 0.15;
    if (slots.preferredColors && slots.preferredColors.length > 0) {
      score += 0.15;
    }

    return maxScore > 0 ? score / maxScore : 0;
  }

  // ==================== Keyword-based extraction methods ====================

  private extractOccasion(message: string): string | null {
    const source = message.toLowerCase();
    const occasionMap: Array<[string, string]> = [
      ["面试", "interview"],
      ["求职", "interview"],
      ["职场", "work"],
      ["上班", "work"],
      ["通勤", "work"],
      ["约会", "date"],
      ["相亲", "date"],
      ["旅行", "travel"],
      ["出游", "travel"],
      ["旅游", "travel"],
      ["聚会", "party"],
      ["派对", "party"],
      ["逛街", "daily"],
      ["日常", "daily"],
      ["校园", "campus"],
      ["上学", "campus"],
    ];

    for (const [keyword, occasion] of occasionMap) {
      if (source.includes(keyword)) {
        return occasion;
      }
    }
    return null;
  }

  private extractStyles(message: string): string[] {
    const styleMap: Array<[string, string]> = [
      ["极简", "极简"],
      ["minimal", "极简"],
      ["韩系", "韩系"],
      ["法式", "法式"],
      ["日系", "日系"],
      ["轻正式", "轻正式"],
      ["通勤", "轻正式"],
      ["街头", "街头"],
      ["运动", "运动"],
      ["复古", "复古"],
    ];

    const normalized = message.toLowerCase();
    return [...new Set(
      styleMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    )];
  }

  private extractFitGoals(message: string): string[] {
    const goalMap: Array<[string, string]> = [
      ["显高", "显高"],
      ["拉长比例", "显高"],
      ["显瘦", "显瘦"],
      ["遮肉", "显瘦"],
      ["遮胯", "修饰胯部"],
      ["修肩", "平衡肩线"],
      ["利落", "利落专业"],
      ["正式", "利落专业"],
      ["减龄", "减龄"],
      ["提气色", "提气色"],
    ];

    const normalized = message.toLowerCase();
    return [...new Set(
      goalMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    )];
  }

  private extractColors(message: string): string[] {
    return VALID_COLORS.filter((color) => message.includes(color));
  }

  private extractBudget(message: string): { min?: number; max?: number } {
    const rangeMatch = message.match(/(\d{2,5})\s*(?:-|~|到|至)\s*(\d{2,5})/);
    if (rangeMatch) {
      const min = Number(rangeMatch[1]);
      const max = Number(rangeMatch[2]);
      return {
        min: Math.min(min, max),
        max: Math.max(min, max),
      };
    }

    const underMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:以内|以下)/i,
    );
    if (underMatch) {
      return { max: Number(underMatch[1]) };
    }

    const aroundMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:左右|上下)/i,
    );
    if (aroundMatch) {
      const center = Number(aroundMatch[1]);
      return {
        min: Math.max(center - 200, 0),
        max: center + 200,
      };
    }

    return {};
  }

  private extractStyleAvoidances(message: string): string[] {
    const avoidances: string[] = [];

    if (message.includes("不要太甜") || message.includes("别太甜")) {
      avoidances.push("甜美");
    }
    if (message.includes("不要太正式") || message.includes("别太正式")) {
      avoidances.push("正式");
    }
    if (message.includes("不要太成熟") || message.includes("别太成熟")) {
      avoidances.push("成熟");
    }

    return avoidances;
  }

  private isPhotoSkipMessage(message: string): boolean {
    return (
      message.includes("跳过") ||
      message.includes("先不要拍") ||
      message.includes("直接推荐") ||
      message.includes("不用了") ||
      message.includes("不需要照片")
    );
  }
}

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";

import { RedisService } from "../../../common/redis/redis.service";

/**
 * ProfileEventSubscriberService subscribes to Redis Pub/Sub channels
 * for profile and quiz events, updating AI stylist context caches.
 * Uses fire-and-forget pattern -- never blocks the event publisher.
 */
@Injectable()
export class ProfileEventSubscriberService implements OnModuleInit {
  private readonly logger = new Logger(ProfileEventSubscriberService.name);

  constructor(private readonly redisService: RedisService) {}

  onModuleInit(): void {
    this.subscribeToProfileUpdates();
    this.subscribeToQuizCompleted();
  }

  private subscribeToProfileUpdates(): void {
    this.redisService.subscribe("profile:updated", (message: string) => {
      this.handleProfileUpdated(message).catch(() => {
        // Fire-and-forget: subscription handler must not block publisher
      });
    }).catch((error: unknown) => {
      this.logger.warn(`Failed to subscribe to profile:updated: ${error instanceof Error ? error.message : String(error)}`);
    });

    this.logger.log("Subscribed to profile:updated Redis channel");
  }

  private subscribeToQuizCompleted(): void {
    this.redisService.subscribe("quiz:completed", (message: string) => {
      this.handleQuizCompleted(message).catch(() => {
        // Fire-and-forget
      });
    }).catch((error: unknown) => {
      this.logger.warn(`Failed to subscribe to quiz:completed: ${error instanceof Error ? error.message : String(error)}`);
    });

    this.logger.log("Subscribed to quiz:completed Redis channel");
  }

  private async handleProfileUpdated(message: string): Promise<void> {
    try {
      const data = JSON.parse(message) as { userId: string; changedFields: string[] };
      this.logger.debug(`AI Stylist: received profile:updated for user ${data.userId}, fields: ${data.changedFields.join(",")}`);

      // Update AI stylist's user context cache
      // The actual cache update is handled by AiStylistContextService
      // This subscriber serves as the event trigger point
    } catch {
      // Malformed message, ignore
    }
  }

  private async handleQuizCompleted(message: string): Promise<void> {
    try {
      const data = JSON.parse(message) as { userId: string; quizId: string };
      this.logger.debug(`AI Stylist: received quiz:completed for user ${data.userId}, quiz: ${data.quizId}`);

      // Refresh style recommendation context
      // The actual context refresh is handled by AiStylistContextService
    } catch {
      // Malformed message, ignore
    }
  }
}

import {
  Injectable,
  Logger,
  OnModuleInit,
  OnModuleDestroy,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import { RedisService } from "../../../common/redis/redis.service";

export interface CloudTask {
  taskId: string;
  type: "tryon" | "segmentation" | "recommendation" | "compatibility";
  payload: Record<string, unknown>;
  priority: "low" | "normal" | "high" | "urgent";
  status: "pending" | "processing" | "completed" | "failed";
  createdAt: Date;
  startedAt?: Date;
  completedAt?: Date;
  retryCount: number;
  maxRetries: number;
  result?: unknown;
  error?: string;
}

export interface TaskProgress {
  taskId: string;
  progress: number;
  stage: string;
  estimatedTimeRemaining?: number;
}

export interface CloudConnection {
  connected: boolean;
  latency: number;
  lastHeartbeat: Date;
  serverLoad: number;
}

export interface SyncMessage {
  type:
    | "sync_request"
    | "sync_response"
    | "delta_update"
    | "conflict_resolution";
  timestamp: Date;
  deviceId: string;
  data: Record<string, unknown>;
  checksum?: string;
}

export interface CommunicationProtocol {
  version: string;
  encoding: "json" | "protobuf" | "msgpack";
  compression: boolean;
  encryption: boolean;
  timeout: number;
  retryPolicy: {
    maxRetries: number;
    backoffMultiplier: number;
    initialDelay: number;
    maxDelay: number;
  };
}

@Injectable()
export class CloudCommunicationService
  implements OnModuleInit, OnModuleDestroy
{
  private readonly logger = new Logger(CloudCommunicationService.name);

  private readonly PROTOCOL: CommunicationProtocol = {
    version: "1.0.0",
    encoding: "json",
    compression: true,
    encryption: true,
    timeout: 30000,
    retryPolicy: {
      maxRetries: 3,
      backoffMultiplier: 2,
      initialDelay: 1000,
      maxDelay: 10000,
    },
  };

  private connectionStatus: CloudConnection = {
    connected: false,
    latency: 0,
    lastHeartbeat: new Date(),
    serverLoad: 0,
  };

  private taskQueue: Map<string, CloudTask> = new Map();
  private pendingCallbacks: Map<
    string,
    {
      resolve: (result: unknown) => void;
      reject: (error: Error) => void;
      timeout: NodeJS.Timeout;
    }
  > = new Map();

  private heartbeatInterval?: NodeJS.Timeout;
  private taskProcessorInterval?: NodeJS.Timeout;
  private readonly DEVICE_ID = `device_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  constructor(
    private configService: ConfigService,
    private redisService: RedisService,
  ) {}

  async onModuleInit() {
    this.logger.log("Initializing Cloud Communication Service");
    await this.initializeConnection();
    this.startHeartbeat();
    this.startTaskProcessor();
  }

  async onModuleDestroy() {
    this.logger.log("Destroying Cloud Communication Service");
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
    if (this.taskProcessorInterval) {
      clearInterval(this.taskProcessorInterval);
    }
    await this.flushPendingTasks();
  }

  private async initializeConnection(): Promise<void> {
    this.logger.log("Establishing cloud connection...");

    try {
      const start = Date.now();
      await this.pingCloud();
      this.connectionStatus.latency = Date.now() - start;
      this.connectionStatus.connected = true;
      this.connectionStatus.lastHeartbeat = new Date();
      this.logger.log(
        `Cloud connection established. Latency: ${this.connectionStatus.latency}ms`,
      );
    } catch (error) {
      this.logger.error("Failed to establish cloud connection:", error);
      this.connectionStatus.connected = false;
    }
  }

  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(async () => {
      try {
        const start = Date.now();
        await this.pingCloud();
        this.connectionStatus.latency = Date.now() - start;
        this.connectionStatus.lastHeartbeat = new Date();
        this.connectionStatus.connected = true;
      } catch (error) {
        this.logger.warn("Heartbeat failed:", error);
        this.connectionStatus.connected = false;
      }
    }, 30000);
  }

  private startTaskProcessor(): void {
    this.taskProcessorInterval = setInterval(async () => {
      await this.processPendingTasks();
    }, 5000);
  }

  private async pingCloud(): Promise<void> {
    const client = this.redisService.getClient();
    const pingKey = `cloud:ping:${this.DEVICE_ID}`;
    await client.set(pingKey, Date.now().toString(), "EX", 60);
  }

  async submitTask(
    type: CloudTask["type"],
    payload: Record<string, unknown>,
    priority: CloudTask["priority"] = "normal",
  ): Promise<string> {
    const taskId = `task_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    const task: CloudTask = {
      taskId,
      type,
      payload,
      priority,
      status: "pending",
      createdAt: new Date(),
      retryCount: 0,
      maxRetries: this.PROTOCOL.retryPolicy.maxRetries,
    };

    this.taskQueue.set(taskId, task);
    await this.persistTask(task);

    this.logger.log(
      `Task ${taskId} submitted: ${type} with priority ${priority}`,
    );
    return taskId;
  }

  async getTaskResult(taskId: string, timeout: number = 30000): Promise<unknown> {
    return new Promise((resolve, reject) => {
      const timeoutHandle = setTimeout(() => {
        this.pendingCallbacks.delete(taskId);
        reject(new Error(`Task ${taskId} timed out after ${timeout}ms`));
      }, timeout);

      this.pendingCallbacks.set(taskId, {
        resolve: (result) => {
          clearTimeout(timeoutHandle);
          this.pendingCallbacks.delete(taskId);
          resolve(result);
        },
        reject: (error) => {
          clearTimeout(timeoutHandle);
          this.pendingCallbacks.delete(taskId);
          reject(error);
        },
        timeout: timeoutHandle,
      });

      this.checkTaskCompletion(taskId);
    });
  }

  private async checkTaskCompletion(taskId: string): Promise<void> {
    const task = this.taskQueue.get(taskId);
    if (!task) {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error(`Task ${taskId} not found`));
      }
      return;
    }

    if (task.status === "completed") {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.resolve(task.result);
      }
    } else if (task.status === "failed") {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error(task.error || "Task failed"));
      }
    }
  }

  private async processPendingTasks(): Promise<void> {
    if (!this.connectionStatus.connected) {
      this.logger.debug("Cloud not connected, skipping task processing");
      return;
    }

    const pendingTasks = Array.from(this.taskQueue.values())
      .filter((t) => t.status === "pending")
      .sort(
        (a, b) =>
          this.getPriorityWeight(b.priority) -
          this.getPriorityWeight(a.priority),
      );

    for (const task of pendingTasks.slice(0, 5)) {
      await this.processTask(task);
    }
  }

  private getPriorityWeight(priority: CloudTask["priority"]): number {
    const weights = { urgent: 4, high: 3, normal: 2, low: 1 };
    return weights[priority];
  }

  private async processTask(task: CloudTask): Promise<void> {
    this.logger.log(`Processing task ${task.taskId}`);
    task.status = "processing";
    task.startedAt = new Date();
    await this.persistTask(task);

    try {
      const result = await this.executeOnCloud(task);
      task.status = "completed";
      task.completedAt = new Date();
      task.result = result;

      const callback = this.pendingCallbacks.get(task.taskId);
      if (callback) {
        callback.resolve(result);
      }
    } catch (error) {
      this.logger.error(`Task ${task.taskId} failed:`, error);
      task.retryCount++;

      if (task.retryCount >= task.maxRetries) {
        task.status = "failed";
        task.error = error instanceof Error ? error.message : String(error);

        const callback = this.pendingCallbacks.get(task.taskId);
        if (callback) {
          callback.reject(new Error(task.error));
        }
      } else {
        task.status = "pending";
        const delay = this.calculateBackoffDelay(task.retryCount);
        await this.delay(delay);
      }
    }

    await this.persistTask(task);
  }

  private calculateBackoffDelay(retryCount: number): number {
    const { initialDelay, backoffMultiplier, maxDelay } =
      this.PROTOCOL.retryPolicy;
    const delay = initialDelay * Math.pow(backoffMultiplier, retryCount - 1);
    return Math.min(delay, maxDelay);
  }

  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private async executeOnCloud(task: CloudTask): Promise<unknown> {
    const client = this.redisService.getClient();
    const taskKey = `cloud:task:${task.taskId}`;
    const resultKey = `cloud:result:${task.taskId}`;

    await client.hset(taskKey, {
      type: task.type,
      payload: JSON.stringify(task.payload),
      priority: task.priority,
      deviceId: this.DEVICE_ID,
      createdAt: task.createdAt.toISOString(),
    });
    await client.expire(taskKey, 3600);

    await client.lpush("cloud:task:queue", task.taskId);

    const startTime = Date.now();
    const timeout = this.PROTOCOL.timeout;

    while (Date.now() - startTime < timeout) {
      const resultData = await client.get(resultKey);
      if (resultData) {
        await client.del(resultKey);
        return JSON.parse(resultData);
      }
      await this.delay(500);
    }

    throw new Error("Cloud task execution timed out");
  }

  private async persistTask(task: CloudTask): Promise<void> {
    const client = this.redisService.getClient();
    const key = `local:task:${task.taskId}`;
    await client.hset(key, {
      taskId: task.taskId,
      type: task.type,
      payload: JSON.stringify(task.payload),
      priority: task.priority,
      status: task.status,
      createdAt: task.createdAt.toISOString(),
      startedAt: task.startedAt?.toISOString() || "",
      completedAt: task.completedAt?.toISOString() || "",
      retryCount: task.retryCount.toString(),
      maxRetries: task.maxRetries.toString(),
      result: task.result ? JSON.stringify(task.result) : "",
      error: task.error || "",
    });
    await client.expire(key, 86400);
  }

  getTaskProgress(taskId: string): Promise<TaskProgress | null> {
    const task = this.taskQueue.get(taskId);
    if (!task) {return null;}

    let progress = 0;
    let stage = "pending";

    if (task.status === "processing") {
      const elapsed = Date.now() - (task.startedAt?.getTime() || Date.now());
      const estimatedTotal = 5000;
      progress = Math.min(90, (elapsed / estimatedTotal) * 100);
      stage = this.getProcessingStage(task.type, progress);
    } else if (task.status === "completed") {
      progress = 100;
      stage = "completed";
    } else if (task.status === "failed") {
      stage = "failed";
    }

    return {
      taskId,
      progress,
      stage,
      estimatedTimeRemaining:
        task.status === "processing" ? 5000 * (1 - progress / 100) : undefined,
    };
  }

  private getProcessingStage(
    type: CloudTask["type"],
    progress: number,
  ): string {
    const stages: Record<CloudTask["type"], string[]> = {
      tryon: [
        "preprocessing",
        "pose_estimation",
        "garment_warping",
        "image_synthesis",
        "postprocessing",
      ],
      segmentation: [
        "image_loading",
        "feature_extraction",
        "mask_generation",
        "refinement",
      ],
      recommendation: [
        "user_profiling",
        "item_retrieval",
        "ranking",
        "diversification",
      ],
      compatibility: [
        "feature_extraction",
        "graph_construction",
        "gnn_propagation",
        "scoring",
      ],
    };

    const typeStages = stages[type] ?? ["queued"];
    const stageIndex = Math.floor((progress / 100) * typeStages.length);
    return typeStages[Math.min(stageIndex, typeStages.length - 1)] ?? "queued";
  }

  async cancelTask(taskId: string): Promise<boolean> {
    const task = this.taskQueue.get(taskId);
    if (!task) {return false;}

    if (task.status === "pending" || task.status === "processing") {
      task.status = "failed";
      task.error = "Cancelled by user";
      await this.persistTask(task);

      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error("Task cancelled"));
      }

      return true;
    }
    return false;
  }

  async syncData(message: SyncMessage): Promise<SyncMessage> {
    const client = this.redisService.getClient();
    const syncKey = `sync:${message.deviceId}:${Date.now()}`;

    await client.set(syncKey, JSON.stringify(message), "EX", 300);

    const response: SyncMessage = {
      type: "sync_response",
      timestamp: new Date(),
      deviceId: this.DEVICE_ID,
      data: { status: "acknowledged", originalMessageId: syncKey },
    };

    return response;
  }

  async requestDeltaSync(lastSyncTime: Date, dataType: string): Promise<unknown[]> {
    this.logger.log(
      `Requesting delta sync for ${dataType} since ${lastSyncTime.toISOString()}`,
    );

    const client = this.redisService.getClient();
    const deltaKey = `delta:${dataType}:${this.DEVICE_ID}`;

    const deltas = await client.lrange(deltaKey, 0, -1);
    return deltas.map((d) => JSON.parse(d));
  }

  getConnectionStatus(): CloudConnection {
    return { ...this.connectionStatus };
  }

  getProtocolInfo(): CommunicationProtocol {
    return { ...this.PROTOCOL };
  }

  getQueueStats(): {
    total: number;
    pending: number;
    processing: number;
    completed: number;
    failed: number;
  } {
    const tasks = Array.from(this.taskQueue.values());
    return {
      total: tasks.length,
      pending: tasks.filter((t) => t.status === "pending").length,
      processing: tasks.filter((t) => t.status === "processing").length,
      completed: tasks.filter((t) => t.status === "completed").length,
      failed: tasks.filter((t) => t.status === "failed").length,
    };
  }

  private async flushPendingTasks(): Promise<void> {
    this.logger.log("Flushing pending tasks...");

    for (const [_taskId, callback] of this.pendingCallbacks) {
      callback.reject(new Error("Service shutting down"));
    }
    this.pendingCallbacks.clear();

    for (const task of this.taskQueue.values()) {
      if (task.status === "processing") {
        task.status = "pending";
        await this.persistTask(task);
      }
    }
  }

  async prefetchUserData(userId: string): Promise<void> {
    this.logger.log(`Prefetching data for user: ${userId}`);

    const client = this.redisService.getClient();
    const prefetchKey = `prefetch:user:${userId}`;

    await client.set(
      prefetchKey,
      JSON.stringify({
        userId,
        timestamp: new Date().toISOString(),
        deviceId: this.DEVICE_ID,
      }),
      "EX",
      300,
    );
  }

  async batchSubmitTasks(
    tasks: Array<{
      type: CloudTask["type"];
      payload: Record<string, unknown>;
      priority?: CloudTask["priority"];
    }>,
  ): Promise<string[]> {
    const taskIds: string[] = [];

    for (const task of tasks) {
      const taskId = await this.submitTask(
        task.type,
        task.payload,
        task.priority,
      );
      taskIds.push(taskId);
    }

    return taskIds;
  }

  async getBatchResults(
    taskIds: string[],
    timeout: number = 60000,
  ): Promise<Map<string, unknown>> {
    const results = new Map<string, unknown>();
    const startTime = Date.now();

    while (Date.now() - startTime < timeout) {
      for (const taskId of taskIds) {
        if (!results.has(taskId)) {
          const task = this.taskQueue.get(taskId);
          if (task?.status === "completed") {
            results.set(taskId, task.result);
          } else if (task?.status === "failed") {
            results.set(taskId, { error: task.error });
          }
        }
      }

      if (results.size === taskIds.length) {
        break;
      }

      await this.delay(500);
    }

    return results;
  }
}

import {
  Injectable,
  Logger,
  ServiceUnavailableException,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { allowUnverifiedAiFallbacks, resolveServiceUrl } from "../../../common/config/runtime-flags";

export interface HybridProcessingRequest {
  requestId?: string;
  userId?: string;
  personImage: Buffer;
  garmentImage?: Buffer;
  type?: "tryon" | "recommendation" | "segmentation";
  context?: Record<string, unknown>;
  poseKeypoints?: PoseKeypoint[];
  options?: {
    useCloud?: boolean;
    priority?: "speed" | "quality" | "balanced";
    timeout?: number;
  };
}

export interface HybridProcessingResult {
  requestId: string;
  result: TryOnResult | RecommendationResult | SegmentationResult;
  processingPath: "local" | "cloud" | "hybrid";
  latency: number;
  confidence: number;
  metadata: {
    localLatency?: number;
    cloudLatency?: number;
    cacheHit?: boolean;
    modelVersion: string;
  };
}

export interface PoseKeypoint {
  id: number;
  x: number;
  y: number;
  z: number;
  visibility: number;
}

export interface TryOnResult {
  type: "tryon";
  image: string | Buffer;
  score: number;
}

export interface RecommendationResult {
  type: "recommendation";
  items: Array<{
    itemId: string;
    score: number;
    reasons: string[];
  }>;
}

export interface SegmentationResult {
  type: "segmentation";
  mask: number[][];
  attributes: Record<string, unknown>;
}

/**
 * API 返回的推荐商品项结构
 */
interface ApiRecommendationItem {
  id: string;
  score: number;
  reasons?: string[];
}

export interface NetworkQuality {
  bandwidth: number;
  latency: number;
  stability: number;
  score: number;
}

export interface ProcessingDecision {
  useCloud: boolean;
  reason: string;
  estimatedLatency: number;
  estimatedCost: number;
}

@Injectable()
export class HybridProcessingService {
  private readonly logger = new Logger(HybridProcessingService.name);
  private aiClient: AxiosInstance;
  private aiServiceAvailable = false;
  private readonly allowFallbacks: boolean;
  private readonly aiServiceUrl: string;

  private readonly thresholds = {
    complexity: 0.7,
    networkQuality: 0.5,
    cacheHit: 0.8,
    userPreference: 0.6,
    maxLocalLatency: 100,
    maxCloudLatency: 5000,
  };

  private readonly weights = {
    gnn: 0.35,
    hypergraph: 0.35,
    crossAttention: 0.3,
  };

  private cacheHits = 0;
  private totalRequests = 0;
  private networkLatencyHistory: number[] = [];

  constructor(private configService: ConfigService) {
    this.allowFallbacks = allowUnverifiedAiFallbacks(this.configService);

    this.aiServiceUrl = resolveServiceUrl(this.configService, "AI_SERVICE_URL", "http://localhost:8001");

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 30000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkAiServiceHealth();
  }

  private async checkAiServiceHealth(): Promise<void> {
    try {
      const start = Date.now();
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      const latency = Date.now() - start;

      if (response.data?.status === "healthy") {
        this.aiServiceAvailable = true;
        this.networkLatencyHistory.push(latency);
        this.logger.log(`AI Service connected (latency: ${latency}ms)`);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `AI Service not available for hybrid processing (${this.aiServiceUrl}): ${errorMessage}`,
      );
      this.aiServiceAvailable = false;
    }
  }

  async process(
    request: HybridProcessingRequest,
  ): Promise<HybridProcessingResult> {
    const startTime = Date.now();
    const requestId = request.requestId || `hybrid_${Date.now()}`;
    this.totalRequests++;

    this.logger.log(`Processing request ${requestId}`);

    const networkQuality = await this.assessNetworkQuality();
    const imageComplexity = this.assessImageComplexity(
      request.personImage,
      request.garmentImage,
    );

    const decision = this.makeProcessingDecision(
      imageComplexity,
      networkQuality,
      request.options,
    );

    this.logger.log(
      `Decision for ${requestId}: ${decision.useCloud ? "cloud" : "local"} - ${decision.reason}`,
    );

    let result: TryOnResult | RecommendationResult | SegmentationResult;
    let localLatency: number | undefined;
    let cloudLatency: number | undefined;
    const cacheHit = false;

    if (decision.useCloud) {
      const cloudStart = Date.now();
      result = await this.processOnCloud(request);
      cloudLatency = Date.now() - cloudStart;
    } else {
      const localStart = Date.now();
      result = await this.processLocally(request);
      localLatency = Date.now() - localStart;
    }

    const totalLatency = Date.now() - startTime;

    return {
      requestId,
      result,
      processingPath: decision.useCloud ? "cloud" : "local",
      latency: totalLatency,
      confidence: this.calculateConfidence(result),
      metadata: {
        localLatency,
        cloudLatency,
        cacheHit,
        modelVersion: "1.0.0",
      },
    };
  }

  private async assessNetworkQuality(): Promise<NetworkQuality> {
    if (this.aiServiceAvailable && this.networkLatencyHistory.length > 0) {
      const recentLatencies = this.networkLatencyHistory.slice(-5);
      const avgLatency =
        recentLatencies.reduce((a, b) => a + b, 0) / recentLatencies.length;
      const latencyVariance =
        recentLatencies.reduce(
          (sum, l) => sum + Math.pow(l - avgLatency, 2),
          0,
        ) / recentLatencies.length;
      const stability = Math.max(
        0,
        1 - Math.sqrt(latencyVariance) / avgLatency,
      );

      const bandwidth = Math.max(1, 1000 / avgLatency);

      const score =
        (bandwidth / 100) * 0.4 +
        (1 - avgLatency / 500) * 0.3 +
        stability * 0.3;

      return { bandwidth, latency: avgLatency, stability, score };
    }

    return {
      bandwidth: 10,
      latency: 500,
      stability: 0.5,
      score: 0.3,
    };
  }

  private assessImageComplexity(
    personImage: Buffer,
    garmentImage?: Buffer,
  ): number {
    const personComplexity = this.calculateImageComplexity(personImage);
    const garmentComplexity = this.calculateImageComplexity(
      garmentImage ?? personImage,
    );

    return (personComplexity + garmentComplexity) / 2;
  }

  private calculateImageComplexity(image: Buffer): number {
    if (!image || image.length === 0) {
      return 0.5;
    }

    const size = image.length;
    const sizeScore = Math.min(size / (1024 * 1024), 1);

    let entropy = 0;
    const byteFreq = new Map<number, number>();
    const sampleSize = Math.min(image.length, 10000);
    const step = Math.max(1, Math.floor(image.length / sampleSize));

    for (let i = 0; i < image.length; i += step) {
      const byte = image[i];
      if (byte === undefined) {
        continue;
      }
      byteFreq.set(byte, (byteFreq.get(byte) || 0) + 1);
    }

    const totalSamples = Math.ceil(image.length / step);
    byteFreq.forEach((count) => {
      const p = count / totalSamples;
      entropy -= p * Math.log2(p);
    });

    const normalizedEntropy = entropy / 8;

    return 0.3 * sizeScore + 0.7 * normalizedEntropy;
  }

  private makeProcessingDecision(
    imageComplexity: number,
    networkQuality: NetworkQuality,
    options: HybridProcessingRequest["options"],
  ): ProcessingDecision {
    if (options?.useCloud !== undefined) {
      return {
        useCloud: options.useCloud,
        reason: "User specified processing path",
        estimatedLatency: options.useCloud ? 2000 : 80,
        estimatedCost: options.useCloud ? 0.01 : 0,
      };
    }

    const conditions = [
      imageComplexity > this.thresholds.complexity,
      networkQuality.score > this.thresholds.networkQuality,
    ];

    const useCloud = conditions.filter(Boolean).length >= 1;

    const reason = useCloud
      ? `Complexity: ${(imageComplexity * 100).toFixed(1)}%, Network: ${(networkQuality.score * 100).toFixed(1)}%`
      : "Local processing sufficient";

    return {
      useCloud,
      reason,
      estimatedLatency: useCloud ? 2000 : 80,
      estimatedCost: useCloud ? 0.01 : 0,
    };
  }

  private async processLocally(
    request: HybridProcessingRequest,
  ): Promise<TryOnResult | RecommendationResult | SegmentationResult> {
    this.logger.log("Processing locally with Python ML service");

    try {
      if (request.type === "tryon") {
        const response = await this.aiClient.post("/api/tryon", {
          person_image: request.personImage.toString("base64"),
          garment_image: request.garmentImage?.toString("base64"),
          mode: "local",
        });

        if (response.data?.success) {
          return {
            type: "tryon",
            image: response.data.data.result_image,
            score: response.data.data.confidence || 0.85,
          };
        }
      }

      if (request.type === "recommendation") {
        const response = await this.aiClient.post("/api/recommendations", {
          user_id: request.userId,
          context: request.context,
          count: 10,
        });

        if (response.data?.success) {
          return {
            type: "recommendation",
            items: response.data.data.items.map((item: ApiRecommendationItem) => ({
              itemId: item.id,
              score: item.score,
              reasons: item.reasons || [],
            })),
          };
        }
      }
    } catch (error: unknown) {
      this.logger.error(
        `Local hybrid processing failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (this.allowFallbacks) {
        return this.getFallbackResult(request);
      }
      throw new ServiceUnavailableException("Local hybrid processing failed");
    }

    if (this.allowFallbacks) {
      return this.getFallbackResult(request);
    }

    throw new ServiceUnavailableException(
      "Local hybrid processing did not produce a valid result",
    );
  }

  private async processOnCloud(
    request: HybridProcessingRequest,
  ): Promise<TryOnResult | RecommendationResult | SegmentationResult> {
    this.logger.log("Processing on cloud with enhanced AI models");

    try {
      if (request.type === "tryon") {
        const response = await this.aiClient.post("/api/tryon", {
          person_image: request.personImage.toString("base64"),
          garment_image: request.garmentImage?.toString("base64"),
          mode: "cloud",
          enhance: true,
        });

        if (response.data?.success) {
          return {
            type: "tryon",
            image: response.data.data.result_image,
            score: response.data.data.confidence || 0.92,
          };
        }
      }

      if (request.type === "recommendation") {
        const response = await this.aiClient.post(
          "/api/recommendations/advanced",
          {
            user_id: request.userId,
            context: request.context,
            count: 20,
            use_advanced_models: true,
          },
        );

        if (response.data?.success) {
          return {
            type: "recommendation",
            items: response.data.data.items.map((item: ApiRecommendationItem) => ({
              itemId: item.id,
              score: item.score,
              reasons: item.reasons || [],
            })),
          };
        }
      }
    } catch (error: unknown) {
      this.logger.warn(
        `Cloud processing failed, falling back to local: ${error instanceof Error ? error.message : String(error)}`,
      );
      return this.processLocally(request);
    }

    if (this.allowFallbacks) {
      return this.getFallbackResult(request);
    }

    throw new ServiceUnavailableException(
      "Cloud hybrid processing did not produce a valid result",
    );
  }

  private calculateConfidence(
    result: TryOnResult | RecommendationResult | SegmentationResult,
  ): number {
    if (result.type === "tryon") {
      return result.score;
    }
    if (result.type === "recommendation") {
      const scores = result.items.map((i) => i.score);
      return scores.length > 0
        ? scores.reduce((a, b) => a + b, 0) / scores.length
        : 0;
    }
    return 0.8;
  }

  checkCache(_requestId: string): Promise<boolean> {
    return false;
  }

  invalidateCache(pattern: string): Promise<void> {
    this.logger.log(`Invalidating cache for pattern: ${pattern}`);
  }

  getStatistics(): {
    totalRequests: number;
    cacheHitRate: number;
    averageLatency: number;
    cloudUsageRate: number;
  } {
    return {
      totalRequests: this.totalRequests,
      cacheHitRate:
        this.totalRequests > 0 ? this.cacheHits / this.totalRequests : 0,
      averageLatency: 500,
      cloudUsageRate: 0.6,
    };
  }

  prefetchUserData(userId: string): Promise<void> {
    this.logger.log(`Prefetching data for user: ${userId}`);
  }

  syncUserData(userId: string): Promise<void> {
    this.logger.log(`Syncing data for user: ${userId}`);
  }

  private getFallbackResult(
    request: HybridProcessingRequest,
  ): TryOnResult | RecommendationResult | SegmentationResult {
    if (request.type === "recommendation") {
      return {
        type: "recommendation",
        items: [],
      };
    }

    if (request.type === "segmentation") {
      return {
        type: "segmentation",
        mask: [],
        attributes: {},
      };
    }

    return {
      type: "tryon",
      image: request.personImage.toString("base64"),
      score: 0.5,
    };
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { resolveServiceUrl } from "../../../common/config/runtime-flags";

export interface StyleAnalysisResult {
  style_name: string;
  confidence: number;
  core_elements: string[];
  key_items: string[];
  color_palette: string[];
  patterns: string[];
  materials: string[];
  occasions: string[];
  seasons: string[];
  body_type_suggestions: Record<string, string[]>;
  celebrity_references: string[];
  brand_references: string[];
  price_range: string;
  similar_styles: string[];
}

export interface OutfitSuggestion {
  category: string;
  description: string;
  style_tags: string[];
  color_suggestions: string[];
  item_examples: string[];
  pairing_tips: string;
}

export interface StyleRecommendationResult {
  style_analysis: StyleAnalysisResult;
  outfit_suggestions: OutfitSuggestion[];
  embedding_prompts: string[];
  style_weights: Record<string, number>;
}

export interface RecommendationItem {
  item_id: string;
  score: number;
  category: string;
  style_tags: string[];
  color_tags: string[];
  reasons: string[];
  image_url?: string;
  price?: number;
  brand?: string;
}

export interface FullRecommendationResult {
  style_analysis: StyleAnalysisResult;
  recommendations: RecommendationItem[];
  total: number;
}

@Injectable()
export class StyleUnderstandingService {
  private readonly logger = new Logger(StyleUnderstandingService.name);
  private mlClient!: AxiosInstance;
  private readonly mlServiceUrl: string;

  constructor(private configService: ConfigService) {
    this.mlServiceUrl = resolveServiceUrl(this.configService, "ML_SERVICE_URL", "http://localhost:8001");
  }

  onModuleInit() {
    this.mlClient = axios.create({
      baseURL: this.mlServiceUrl,
      timeout: 60000,
      headers: {
        "Content-Type": "application/json",
      },
    });
  }

  async analyzeStyle(
    userInput: string,
    userProfile?: {
      gender?: string;
      age?: number;
      bodyType?: string;
      stylePreferences?: string[];
    },
  ): Promise<StyleAnalysisResult> {
    try {
      const response = await this.mlClient.post("/api/style/analyze", {
        user_input: userInput,
        user_profile: userProfile,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`风格分析失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackStyleAnalysis(userInput);
    }
  }

  async getStyleSuggestions(
    userInput: string,
    bodyType?: string,
    occasion?: string,
  ): Promise<StyleRecommendationResult> {
    try {
      const response = await this.mlClient.post("/api/style/suggestions", {
        user_input: userInput,
        body_type: bodyType,
        occasion: occasion,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取风格建议失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackSuggestions(userInput);
    }
  }

  async getRecommendations(
    userInput: string,
    options?: {
      userProfile?: Record<string, any>;
      occasion?: string;
      category?: string;
      topK?: number;
    },
  ): Promise<FullRecommendationResult> {
    try {
      const response = await this.mlClient.post("/api/recommendations", {
        user_input: userInput,
        user_profile: options?.userProfile,
        occasion: options?.occasion,
        category: options?.category,
        top_k: options?.topK || 10,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取推荐失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackRecommendations(userInput);
    }
  }

  async getOutfitRecommendation(
    userInput: string,
    options?: {
      userProfile?: Record<string, any>;
      occasion?: string;
    },
  ): Promise<{
    outfit_id: string;
    style_analysis: StyleAnalysisResult;
    items: RecommendationItem[];
    compatibility_score: number;
    total_price?: number;
  }> {
    try {
      const response = await this.mlClient.post("/api/recommendations/outfit", {
        user_input: userInput,
        user_profile: options?.userProfile,
        occasion: options?.occasion,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取搭配推荐失败: ${this.getErrorMessage(error)}`);
      return {
        outfit_id: `outfit_${Date.now()}`,
        style_analysis: this.getFallbackStyleAnalysis(userInput),
        items: [],
        compatibility_score: 0,
      };
    }
  }

  quickMatchStyle(userInput: string): { style: string; confidence: number } {
    const styleKeywords: Record<string, string[]> = {
      小红书同款: ["小红书", "网红", "爆款", "种草"],
      法式慵懒: ["法式", "慵懒", "巴黎", "French"],
      韩系: ["韩系", "韩国", "Korean", "韩风"],
      日系: ["日系", "日本", "Japanese", "文艺"],
      街头潮流: ["街头", "潮流", "嘻哈", "streetwear"],
      极简风: ["极简", "简约", "minimalist"],
      复古风: ["复古", "vintage", "怀旧"],
      运动风: ["运动", "健身", "sporty"],
    };

    for (const [style, keywords] of Object.entries(styleKeywords)) {
      for (const keyword of keywords) {
        if (userInput.includes(keyword)) {
          return { style, confidence: 0.9 };
        }
      }
    }

    return { style: "休闲风", confidence: 0.5 };
  }

  private getFallbackStyleAnalysis(userInput: string): StyleAnalysisResult {
    const quickMatch = this.quickMatchStyle(userInput);

    const styleData: Record<string, Partial<StyleAnalysisResult>> = {
      小红书同款: {
        core_elements: ["显瘦", "日常", "拍照好看"],
        key_items: ["白衬衫", "阔腿裤", "针织开衫"],
        color_palette: ["米白", "浅蓝", "卡其"],
        occasions: ["约会", "逛街", "拍照"],
      },
      法式慵懒: {
        core_elements: ["优雅", "随性", "浪漫"],
        key_items: ["条纹衫", "牛仔裤", "芭蕾舞鞋"],
        color_palette: ["海军蓝", "白色", "红色"],
        occasions: ["约会", "咖啡厅", "旅行"],
      },
      韩系: {
        core_elements: ["温柔", "甜美", "年轻"],
        key_items: ["针织背心", "百褶裙", "小白鞋"],
        color_palette: ["粉色", "米色", "浅蓝"],
        occasions: ["约会", "上学", "逛街"],
      },
    };

    const matchedData = styleData[quickMatch.style] || {};

    return {
      style_name: quickMatch.style,
      confidence: quickMatch.confidence,
      core_elements: matchedData.core_elements || ["日常", "舒适"],
      key_items: matchedData.key_items || ["T恤", "牛仔裤"],
      color_palette: matchedData.color_palette || ["白色", "蓝色"],
      patterns: ["纯色"],
      materials: ["棉", "牛仔"],
      occasions: matchedData.occasions || ["日常"],
      seasons: ["春", "秋"],
      body_type_suggestions: {},
      celebrity_references: [],
      brand_references: ["优衣库", "ZARA"],
      price_range: "100-500元",
      similar_styles: ["简约风", "休闲风"],
    };
  }

  private getFallbackSuggestions(userInput: string): StyleRecommendationResult {
    const analysis = this.getFallbackStyleAnalysis(userInput);

    return {
      style_analysis: analysis,
      outfit_suggestions: [
        {
          category: "tops",
          description: `${analysis.style_name}风格上衣`,
          style_tags: analysis.similar_styles,
          color_suggestions: analysis.color_palette.slice(0, 3),
