import { ConfigService } from '@nestjs/config';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { JwtService } from '@nestjs/jwt';
import { Test, TestingModule } from '@nestjs/testing';
import { Server, Socket } from 'socket.io';

import { PrismaService } from '../../common/prisma/prisma.service';
import { CHAT_EVENTS } from '../ws/events';
import { EventBusService } from '../ws/services/event-bus.service';

import { ChatGateway } from './chat.gateway';
import { ChatService } from './chat.service';
import { SenderTypeDto, MessageTypeDto } from './dto';


function createMockSocket(overrides: Record<string, unknown> = {}): Socket {
  const rooms = new Set<string>();
  return {
    id: `socket-${Math.random().toString(36).slice(2, 9)}`,
    handshake: { auth: {} },
    emit: jest.fn(),
    disconnect: jest.fn(),
    join: jest.fn().mockImplementation((room: string) => {
      rooms.add(room);
      return Promise.resolve();
    }),
    leave: jest.fn().mockImplementation((room: string) => {
      rooms.delete(room);
      return Promise.resolve();
    }),
    ...overrides,
  } as unknown as Socket;
}

describe('ChatGateway', () => {
  let gateway: ChatGateway;
  let chatService: ChatService;
  let eventBus: EventBusService;
  let jwtService: JwtService;
  let prisma: PrismaService;

  const mockRedis = {
    publish: jest.fn().mockResolvedValue(1),
    get: jest.fn(),
    set: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        ChatGateway,
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn((key: string) => {
              if (key === 'JWT_SECRET') {return 'test-jwt-secret';}
              if (key === 'REDIS_URL') {return 'redis://localhost:6379';}
              return null;
            }),
          },
        },
        {
          provide: JwtService,
          useValue: {
            verify: jest.fn(),
          },
        },
        {
          provide: 'REDIS_CLIENT',
          useValue: mockRedis,
        },
        {
          provide: EventBusService,
          useValue: {
            on: jest.fn(),
            off: jest.fn(),
            publish: jest.fn().mockResolvedValue(undefined),
          },
        },
        {
          provide: ChatService,
          useValue: {
            getRoomById: jest.fn(),
            sendMessage: jest.fn(),
            markAsRead: jest.fn(),
            isConsultant: jest.fn(),
          },
        },
        {
          provide: PrismaService,
          useValue: {
            chatRoom: {
              findUnique: jest.fn(),
            },
          },
        },
        EventEmitter2,
      ],
    }).compile();

    gateway = module.get<ChatGateway>(ChatGateway);
    chatService = module.get<ChatService>(ChatService);
    eventBus = module.get<EventBusService>(EventBusService);
    jwtService = module.get<JwtService>(JwtService);
    prisma = module.get<PrismaService>(PrismaService);

    // Mock server
    gateway.server = {
      to: jest.fn().mockReturnValue({
        emit: jest.fn(),
      }),
    } as unknown as Server;
  });

  it('should be defined', () => {
    expect(gateway).toBeDefined();
  });

  describe('handleConnection', () => {
    it('should disconnect client without token', async () => {
      const client = createMockSocket();

      await gateway.handleConnection(client);

      expect(client.emit).toHaveBeenCalledWith('error', { message: 'Authentication required' });
      expect(client.disconnect).toHaveBeenCalled();
    });

    it('should connect client with valid token', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      expect(client.join).toHaveBeenCalledWith(`chat:user:${userId}`);
      expect(client.emit).toHaveBeenCalledWith('connected', expect.objectContaining({
        message: 'Connected to chat events',
        userId,
      }));
      expect(gateway.isUserOnline(userId)).toBe(true);
    });

    it('should disconnect client with invalid token', async () => {
      (jwtService.verify as jest.Mock).mockImplementation(() => {
        throw new Error('Invalid token');
      });

      const client = createMockSocket({
        handshake: { auth: { token: 'invalid-token' } },
      });

      await gateway.handleConnection(client);

      expect(client.disconnect).toHaveBeenCalled();
    });
  });

  describe('handleJoinRoom', () => {
    it('should reject join when user has no access to room', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.getRoomById as jest.Mock).mockRejectedValue(new Error('Forbidden'));

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      // First connect the client
      await gateway.handleConnection(client);

      await gateway.handleJoinRoom(client, { roomId: 'room-no-access' });

      expect(client.emit).toHaveBeenCalledWith('error', { message: '无权访问此聊天室' });
    });

    it('should allow join when user has access to room', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.getRoomById as jest.Mock).mockResolvedValue({ id: 'room-1' });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      await gateway.handleJoinRoom(client, { roomId: 'room-1' });

      expect(client.join).toHaveBeenCalledWith('chat:room:room-1');
      expect(client.emit).toHaveBeenCalledWith('chat:joined', { roomId: 'room-1' });
    });
  });

  describe('handleMessage', () => {
    it('should send message and publish event', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.isConsultant as jest.Mock).mockResolvedValue(false);
      (prisma.chatRoom.findUnique as jest.Mock).mockResolvedValue({
        id: 'room-1',
        consultantId: 'consultant-1',
      });
      (chatService.sendMessage as jest.Mock).mockResolvedValue({ id: 'msg-1' });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      await gateway.handleMessage(client, {
        roomId: 'room-1',
        content: 'Hello',
        messageType: 'text',
      });

      expect(chatService.sendMessage).toHaveBeenCalledWith(userId, expect.objectContaining({
        roomId: 'room-1',
        senderType: SenderTypeDto.USER,
        content: 'Hello',
        messageType: MessageTypeDto.TEXT,
      }));

      expect(eventBus.publish).toHaveBeenCalledWith(
        CHAT_EVENTS.MESSAGE_CREATED,
        userId,
        expect.objectContaining({
          roomId: 'room-1',
          messageId: 'msg-1',
          senderType: SenderTypeDto.USER,
        }),
      );
    });

    it('should emit error when message send fails', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (prisma.chatRoom.findUnique as jest.Mock).mockResolvedValue(null);

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      await gateway.handleMessage(client, {
        roomId: 'room-nonexistent',
        content: 'Hello',
        messageType: 'text',
      });

      expect(client.emit).toHaveBeenCalledWith('error', expect.objectContaining({
        message: expect.stringContaining('消息发送失败'),
      }));
    });
  });

  describe('handleTyping', () => {
    it('should broadcast typing state to room', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.isConsultant as jest.Mock).mockResolvedValue(false);
      (prisma.chatRoom.findUnique as jest.Mock).mockResolvedValue({
        id: 'room-1',
        consultantId: 'consultant-1',
      });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      const mockTo = { emit: jest.fn() };
      (gateway.server.to as jest.Mock).mockReturnValue(mockTo);

      await gateway.handleTyping(client, {
        roomId: 'room-1',
        isTyping: true,
      });

      expect(gateway.server.to).toHaveBeenCalledWith('chat:room:room-1');
      expect(mockTo.emit).toHaveBeenCalledWith('chat:typing', expect.objectContaining({
        roomId: 'room-1',
        senderId: userId,
        senderType: SenderTypeDto.USER,
        isTyping: true,
      }));
    });
  });

  describe('handleRead', () => {
    it('should call markAsRead and publish event', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.markAsRead as jest.Mock).mockResolvedValue({ markedCount: 3 });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      await gateway.handleRead(client, {
        roomId: 'room-1',
        lastMessageId: 'msg-5',
      });

      expect(chatService.markAsRead).toHaveBeenCalledWith(userId, 'room-1', {
        lastMessageId: 'msg-5',
      });

      expect(eventBus.publish).toHaveBeenCalledWith(
        CHAT_EVENTS.MESSAGE_READ,
        userId,
        expect.objectContaining({
          roomId: 'room-1',
          readerId: userId,
          lastMessageId: 'msg-5',
        }),
      );
    });

    it('should silently fail when markAsRead throws', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });
      (chatService.markAsRead as jest.Mock).mockRejectedValue(new Error('DB error'));

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);

      // Should not throw
      await expect(
        gateway.handleRead(client, { roomId: 'room-1' }),
      ).resolves.toBeUndefined();
    });
  });

  describe('handleDisconnect', () => {
    it('should clean up user connection on disconnect', async () => {
      const userId = 'user-123';
      (jwtService.verify as jest.Mock).mockReturnValue({ sub: userId });

      const client = createMockSocket({
        handshake: { auth: { token: 'valid-token' } },
      });

      await gateway.handleConnection(client);
      expect(gateway.isUserOnline(userId)).toBe(true);

      await gateway.handleDisconnect(client);
      expect(gateway.isUserOnline(userId)).toBe(false);
    });
  });
});

import {
  Logger,
  UsePipes,
  ValidationPipe,
  Inject,
  OnModuleInit,
  OnModuleDestroy,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import Redis from 'ioredis';
import { Server, Socket } from 'socket.io';

import { PrismaService } from '../../common/prisma/prisma.service';
import { REDIS_CLIENT } from '../../common/redis/redis.service';
import {
  CHAT_EVENTS,
  ChatMessageCreatedPayload,
  ChatMessageReadPayload,
} from '../ws/events';
import { EventBusService, type EventEnvelope } from '../ws/services/event-bus.service';

import { ChatService } from './chat.service';
import { SenderTypeDto, MessageTypeDto } from './dto/chat.dto';


interface ChatUserConnection {
  socketId: string;
  userId: string;
  activeRoomId?: string;
  connectedAt: Date;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(',').filter(Boolean) || (process.env.NODE_ENV === 'production' ? [] : ['http://localhost:3000']),
    credentials: true,
  },
  namespace: '/ws/chat',
  transports: ['websocket', 'polling'],
})
@UsePipes(new ValidationPipe())
export class ChatGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect, OnModuleInit, OnModuleDestroy
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(ChatGateway.name);

  private userSocketMap = new Map<string, Set<string>>();
  private connections = new Map<string, ChatUserConnection>();
  private eventUnsubscribers: Array<() => void> = [];

  constructor(
    private configService: ConfigService,
    private jwtService: JwtService,
    @Inject(REDIS_CLIENT) private redis: Redis,
    private eventBus: EventBusService,
    private chatService: ChatService,
    private prisma: PrismaService,
  ) {}

  onModuleInit() {
    if (!process.env.CORS_ORIGINS && process.env.NODE_ENV === 'production') {
      this.logger.warn('CORS_ORIGINS not set in production. WebSocket connections may be blocked. Set CORS_ORIGINS env var.');
    }

    const eventMappings = [
      { eventType: CHAT_EVENTS.MESSAGE_CREATED, handler: (envelope: EventEnvelope) => this.handleMessageCreated(envelope as unknown as { payload: ChatMessageCreatedPayload }) },
      { eventType: CHAT_EVENTS.MESSAGE_READ, handler: (envelope: EventEnvelope) => this.handleMessageRead(envelope as unknown as { payload: ChatMessageReadPayload }) },
    ];

    for (const mapping of eventMappings) {
      this.eventBus.on(mapping.eventType, mapping.handler);
      this.eventUnsubscribers.push(() => this.eventBus.off(mapping.eventType, mapping.handler));
    }

    this.logger.log('Chat WebSocket gateway initialized');
  }

  onModuleDestroy() {
    for (const unsubscribe of this.eventUnsubscribers) {
      unsubscribe();
    }
    this.eventUnsubscribers = [];
    this.connections.clear();
    this.userSocketMap.clear();
    this.logger.log('Chat WebSocket gateway destroyed');
  }

  afterInit(_server: Server) {
    this.logger.log('Chat WebSocket server initialized');
  }

  async handleConnection(client: Socket) {
    try {
      const userId = this.extractUserId(client);
      if (!userId) {
        this.logger.warn(`Chat client ${client.id} rejected: no valid token`);
        client.emit('error', { message: 'Authentication required' });
        client.disconnect();
        return;
      }

      const connection: ChatUserConnection = {
        socketId: client.id,
        userId,
        connectedAt: new Date(),
      };

      this.connections.set(client.id, connection);

      if (!this.userSocketMap.has(userId)) {
        this.userSocketMap.set(userId, new Set());
      }
      this.userSocketMap.get(userId)!.add(client.id);

      await client.join(`chat:user:${userId}`);

      this.logger.log(`Chat client ${client.id} connected for user ${userId}`);

      client.emit('connected', {
        message: 'Connected to chat events',
        userId,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Chat connection error: ${message}`);
      client.disconnect();
    }
  }

  handleDisconnect(client: Socket) {
    const connection = this.connections.get(client.id);
    if (connection) {
      const { userId } = connection;
      const userSocketSet = this.userSocketMap.get(userId);
      if (userSocketSet) {
        userSocketSet.delete(client.id);
        if (userSocketSet.size === 0) {
          this.userSocketMap.delete(userId);
        }
      }
      this.connections.delete(client.id);
      this.logger.log(`Chat client ${client.id} disconnected for user ${userId}`);
    }
  }

  @SubscribeMessage('chat:join')
  async handleJoinRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { roomId: string },
  ) {
    const connection = this.connections.get(client.id);
    if (!connection) {return;}

    // 验证用户有权访问此聊天室
    try {
      await this.chatService.getRoomById(connection.userId, data.roomId);
    } catch {
      client.emit('error', { message: '无权访问此聊天室' });
      return;
    }

    await client.join(`chat:room:${data.roomId}`);
    connection.activeRoomId = data.roomId;

    client.emit('chat:joined', { roomId: data.roomId });
    this.logger.debug(`Client ${client.id} joined chat room: ${data.roomId}`);
  }

  @SubscribeMessage('chat:leave')
  async handleLeaveRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { roomId: string },
  ) {
    await client.leave(`chat:room:${data.roomId}`);
    const connection = this.connections.get(client.id);
    if (connection?.activeRoomId === data.roomId) {
      connection.activeRoomId = undefined;
    }
    client.emit('chat:left', { roomId: data.roomId });
  }

  @SubscribeMessage('chat:message')
  async handleMessage(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { roomId: string; content: string; messageType: string; imageUrl?: string; fileUrl?: string },
  ) {
    const connection = this.connections.get(client.id);
    if (!connection) {return;}

    try {
      // 确定发送者类型
      const room = await this.prisma.chatRoom.findUnique({ where: { id: data.roomId } });
      if (!room) {throw new Error('Room not found');}

      const senderType = room.consultantId && (await this.chatService.isConsultant(connection.userId, room.consultantId)) ? SenderTypeDto.CONSULTANT : SenderTypeDto.USER;

      const message = await this.chatService.sendMessage(connection.userId, {
        roomId: data.roomId,
        senderType,
        content: data.content,
        messageType: (data.messageType as MessageTypeDto) || MessageTypeDto.TEXT,
        imageUrl: data.imageUrl,
        fileUrl: data.fileUrl,
      });

      // 通过 EventBus 广播消息创建事件
      await this.eventBus.publish(CHAT_EVENTS.MESSAGE_CREATED, connection.userId, {
        roomId: data.roomId,
        messageId: message.id,
        senderId: connection.userId,
        senderType,
        messageType: data.messageType || 'text',
        content: data.content,
      });
    } catch (error) {
      const msg = error instanceof Error ? error.message : 'Unknown error';
      client.emit('error', { message: `消息发送失败: ${msg}` });
    }
  }

  @SubscribeMessage('chat:typing')
  async handleTyping(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { roomId: string; isTyping: boolean },
  ) {
    try {
      const connection = this.connections.get(client.id);
      if (!connection) {return;}

      const room = await this.prisma.chatRoom.findUnique({ where: { id: data.roomId } });
      if (!room) {return;}

      const senderType = room.consultantId && (await this.chatService.isConsultant(connection.userId, room.consultantId)) ? 'consultant' : 'user';

      this.server.to(`chat:room:${data.roomId}`).emit('chat:typing', {
        roomId: data.roomId,
        senderId: connection.userId,
        senderType,
        isTyping: data.isTyping,
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Error handling typing event: ${message}`);
    }
  }

  @SubscribeMessage('chat:read')
  async handleRead(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { roomId: string; lastMessageId?: string },
  ) {
    const connection = this.connections.get(client.id);
    if (!connection) {return;}

    try {
      await this.chatService.markAsRead(connection.userId, data.roomId, { lastMessageId: data.lastMessageId });

      await this.eventBus.publish(CHAT_EVENTS.MESSAGE_READ, connection.userId, {
        roomId: data.roomId,
        readerId: connection.userId,
        lastMessageId: data.lastMessageId,
      });
    } catch {
      // Silently fail read receipts
    }
  }

  private async handleMessageCreated(envelope: { payload: ChatMessageCreatedPayload }) {
    const { roomId } = envelope.payload;
    this.server.to(`chat:room:${roomId}`).emit('chat:message', envelope.payload);
  }

  private async handleMessageRead(envelope: { payload: ChatMessageReadPayload }) {
    const { roomId } = envelope.payload;
    this.server.to(`chat:room:${roomId}`).emit('chat:read', envelope.payload);
  }

  private extractUserId(client: Socket): string | null {
    const auth = client.handshake.auth;
    const token = auth?.token;
    if (!token) {return null;}
    return this.validateToken(token as string);
  }

  private validateToken(token: string): string | null {
    try {
      const jwtSecret = this.configService.get<string>('JWT_SECRET');
      if (!jwtSecret) {return null;}
      const payload = this.jwtService.verify(token, { secret: jwtSecret });
      return payload.sub || payload.userId || null;
    } catch {
      return null;
    }
  }

  isUserOnline(userId: string): boolean {
    return this.userSocketMap.has(userId);
  }
}

import crypto from 'crypto';

import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import axios, { AxiosInstance } from 'axios';

interface JDImageInfo {
  imageList?: string;
  whiteImage?: string;
}

interface JDCategoryInfo {
  cid1Name?: string;
  cid2Name?: string;
}

interface JDItem {
  skuId?: string | number;
  skuName?: string;
  brandName?: string;
  price?: number | string;
  originalPrice?: number | string;
  imageInfo?: JDImageInfo;
  categoryInfo?: JDCategoryInfo;
  materialUrl?: string;
  goodCommentsShare?: number | string;
  inOrderCount30Days?: number | string;
}

interface ClothingItem {
  id: string;
  name: string;
  brand?: string;
  price: number;
  originalPrice?: number;
  currency: string;
  images: string[];
  mainImage: string;
  category: string;
  subcategory?: string;
  description?: string;
  sizes?: string[];
  colors?: string[];
  material?: string;
  source: string;
  sourceUrl?: string;
  externalId: string;
  rating?: number;
  reviewCount?: number;
  salesCount?: number;
  tags?: string[];
  createdAt: Date;
  updatedAt: Date;
}

interface DataSourceConfig {
  name: string;
  enabled: boolean;
  priority: number;
  apiKey?: string;
  apiSecret?: string;
  appKey?: string;
  endpoint?: string;
}

interface SearchResult {
  items: ClothingItem[];
  total: number;
  page: number;
  pageSize: number;
  source: string;
}

@Injectable()
export class ClothingDataSourceService {
  private readonly logger = new Logger(ClothingDataSourceService.name);
  private readonly axiosInstance: AxiosInstance;
  private readonly sources: Map<string, DataSourceConfig> = new Map();

  constructor(private readonly configService: ConfigService) {
    this.axiosInstance = axios.create({
      timeout: 30000,
      headers: {
        'Content-Type': 'application/json',
        'User-Agent': 'XunO/1.0',
      },
    });

    this.initializeSources();
  }

  private initializeSources(): void {
    const sources = [
      {
        name: 'taobao',
        enabled: !!this.configService.get('TAOBAO_APP_KEY'),
        priority: 1,
        apiKey: this.configService.get('TAOBAO_APP_KEY'),
        apiSecret: this.configService.get('TAOBAO_APP_SECRET'),
        endpoint: 'https://eco.taobao.com/router/rest',
      },
      {
        name: 'jd',
        enabled: !!this.configService.get('JD_APP_KEY'),
        priority: 2,
        apiKey: this.configService.get('JD_APP_KEY'),
        apiSecret: this.configService.get('JD_APP_SECRET'),
        endpoint: 'https://api.jd.com/routerjson',
      },
      {
        name: 'dewu',
        enabled: !!this.configService.get('DEWU_APP_KEY'),
        priority: 3,
        apiKey: this.configService.get('DEWU_APP_KEY'),
        apiSecret: this.configService.get('DEWU_APP_SECRET'),
        endpoint: 'https://openapi.dewu.com',
      },
      {
        name: 'api4ai',
        enabled: !!this.configService.get('API4AI_KEY'),
        priority: 4,
        apiKey: this.configService.get('API4AI_KEY'),
        endpoint: 'https://api.api4ai.cloud/fashion/v2/results',
      },
    ];

    for (const source of sources) {
      this.sources.set(source.name, source);
    }

    this.logger.log(`Initialized ${this.sources.size} data sources: ${Array.from(this.sources.keys()).join(', ')}`);
  }

  async searchClothing(
    query: string,
    options: {
      category?: string;
      minPrice?: number;
      maxPrice?: number;
      brand?: string;
      page?: number;
      pageSize?: number;
      sources?: string[];
    } = {}
  ): Promise<SearchResult[]> {
    const { _page = 1, _pageSize = 20, sources: requestedSources } = options;
    const enabledSources = Array.from(this.sources.values())
      .filter((s) => s.enabled)
      .filter((s) => !requestedSources || requestedSources.includes(s.name))
      .sort((a, b) => a.priority - b.priority);

    const results: SearchResult[] = [];

    for (const source of enabledSources) {
      try {
        const result = await this.searchFromSource(source.name, query, options);
        results.push(result);
      } catch (error: unknown) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        this.logger.error(`Failed to search from ${source.name}: ${errorMessage}`);
      }
    }

    return results;
  }

  private async searchFromSource(
    sourceName: string,
    query: string,
    options: Record<string, unknown>
  ): Promise<SearchResult> {
    switch (sourceName) {
      case 'taobao':
        return this.searchFromTaobao(query, options);
      case 'jd':
        return this.searchFromJD(query, options);
      case 'dewu':
        return this.searchFromDewu(query, options);
      case 'api4ai':
        return this.searchFromApi4Ai(query, options);
      default:
        throw new Error(`Unknown source: ${sourceName}`);
    }
  }

  private async searchFromTaobao(
    query: string,
    options: Record<string, unknown>
  ): Promise<SearchResult> {
    const config = this.sources.get('taobao');
    if (!config?.apiKey || !config?.apiSecret) {
      throw new Error('Taobao API credentials not configured');
    }

    const params: Record<string, string | number> = {
      method: 'taobao.tbk.item.search',
      app_key: config.apiKey,
      timestamp: new Date().toISOString().replace(/\.\d{3}/, ''),
      format: 'json',
      v: '2.0',
      sign_method: 'md5',
      q: query,
      page_no: (options.page as number) || 1,
      page_size: (options.pageSize as number) || 20,
    };

    if (options.category) {
      params.cat = options.category as string;
    }
    if (options.minPrice) {
      params.start_price = options.minPrice as number;
    }
    if (options.maxPrice) {
      params.end_price = options.maxPrice as number;
    }

    const sign = this.generateTaobaoSign(params, config.apiSecret);
    params.sign = sign;

    try {
      const response = await this.axiosInstance.get(config.endpoint!, { params });
      const data = response.data;

      if (data.error_response) {
        throw new Error(data.error_response.msg || 'Taobao API error');
      }

      const items = (data.tbk_item_search_get_response?.results?.n_tbk_item || []).map(
        (item: Record<string, unknown>) => this.normalizeTaobaoItem(item)
      );

      return {
        items,
        total: data.tbk_item_search_get_response?.total_results || 0,
        page: (options.page as number) || 1,
        pageSize: (options.pageSize as number) || 20,
        source: 'taobao',
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Taobao search error: ${errorMessage}`);
      throw error;
    }
  }

  private generateTaobaoSign(
    params: Record<string, string | number>,
    secret: string
  ): string {
    const sortedKeys = Object.keys(params).sort();
    const signString = sortedKeys.map((key) => `${key}${params[key]}`).join('');
    return crypto.createHash('md5').update(secret + signString + secret).digest('hex').toUpperCase();
  }

  private normalizeTaobaoItem(item: Record<string, unknown>): ClothingItem {
    return {
      id: `tb_${item.num_iid}`,
      externalId: String(item.num_iid || ''),
      name: String(item.title || ''),
      brand: String(item.brand_name || ''),
      price: parseFloat(String(item.reserve_price || item.zk_final_price || 0)),
      originalPrice: parseFloat(String(item.reserve_price || 0)),
      currency: 'CNY',
      images: String(item.pict_url || '').split(',').filter(Boolean),
      mainImage: String(item.pict_url || '').split(',')[0] || '',
      category: String(item.cat_name || ''),
      description: String(item.title || ''),
      source: 'taobao',
      sourceUrl: String(item.item_url || ''),
      rating: parseFloat(String(item.tk_rate || 0)),
      salesCount: parseInt(String(item.volume || 0), 10),
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  private async searchFromJD(
    query: string,
    options: Record<string, unknown>
  ): Promise<SearchResult> {
    const config = this.sources.get('jd');
    if (!config?.apiKey || !config?.apiSecret) {
      throw new Error('JD API credentials not configured');
    }

    const params: Record<string, string | number> = {
      method: 'jd.union.open.goods.jingfen.query',
      app_key: config.apiKey,
      timestamp: Date.now(),
      format: 'json',
      v: '1.0',
      sign_method: 'md5',
      'goodsReq.keyword': query,
      'goodsReq.pageIndex': (options.page as number) || 1,
      'goodsReq.pageSize': (options.pageSize as number) || 20,
    };

    const sign = this.generateJDSign(params, config.apiSecret);
    params.sign = sign;

    try {
      const response = await this.axiosInstance.get(config.endpoint!, { params });
      const data = response.data;

      const items = (data.result?.data || []).map((item: Record<string, unknown>) =>
        this.normalizeJDItem(item)
      );

      return {
        items,
        total: data.result?.totalCount || 0,
        page: (options.page as number) || 1,
        pageSize: (options.pageSize as number) || 20,
        source: 'jd',
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`JD search error: ${errorMessage}`);
      throw error;
    }
  }

  private generateJDSign(
    params: Record<string, string | number>,
    secret: string
  ): string {
    const sortedKeys = Object.keys(params).sort();
    const signString = sortedKeys.map((key) => `${key}${params[key]}`).join('');
    return crypto.createHash('md5').update(secret + signString + secret).digest('hex').toUpperCase();
  }

  private normalizeJDItem(item: JDItem): ClothingItem {
    return {
      id: `jd_${item.skuId}`,
      externalId: String(item.skuId || ''),
      name: String(item.skuName || ''),
      brand: String(item.brandName || ''),
      price: parseFloat(String(item.price || 0)),
      originalPrice: parseFloat(String(item.originalPrice || 0)),
      currency: 'CNY',
      images: String(item.imageInfo?.imageList || '')
        .split(',')
        .filter(Boolean),
      mainImage: String(item.imageInfo?.whiteImage || item.imageInfo?.imageList || '').split(',')[0] || '',
      category: String(item.categoryInfo?.cid1Name || ''),
      subcategory: String(item.categoryInfo?.cid2Name || ''),
      description: String(item.skuName || ''),
      source: 'jd',
      sourceUrl: String(item.materialUrl || ''),
      rating: parseFloat(String(item.goodCommentsShare || 0)),
      salesCount: parseInt(String(item.inOrderCount30Days || 0), 10),
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  private async searchFromDewu(
    query: string,
    options: Record<string, unknown>
  ): Promise<SearchResult> {
    const config = this.sources.get('dewu');
    if (!config?.apiKey || !config?.apiSecret) {
      throw new Error('Dewu API credentials not configured');
    }

    const timestamp = Date.now().toString();
    const params = {
      keyword: query,
      page: (options.page as number) || 1,
      size: (options.pageSize as number) || 20,
    };

    const sign = this.generateDewuSign(params, config.apiSecret, timestamp);

    try {
      const response = await this.axiosInstance.get(`${config.endpoint}/v1/h5/search`, {
        headers: {
          'X-App-Key': config.apiKey,
          'X-Timestamp': timestamp,
          'X-Sign': sign,
        },
        params,
      });

      const data = response.data;
      const items = (data.data?.list || []).map((item: Record<string, unknown>) =>
        this.normalizeDewuItem(item)
      );

      return {
        items,
        total: data.data?.total || 0,
        page: (options.page as number) || 1,
        pageSize: (options.pageSize as number) || 20,
        source: 'dewu',
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Dewu search error: ${errorMessage}`);
      throw error;
    }
  }

  private generateDewuSign(
    params: Record<string, unknown>,
    secret: string,
    timestamp: string
  ): string {
    const paramString = JSON.stringify(params);
    const signString = `${secret}${timestamp}${paramString}`;
    return crypto.createHash('sha256').update(signString).digest('hex');
  }

  private normalizeDewuItem(item: Record<string, unknown>): ClothingItem {
    return {
      id: `dw_${item.productId}`,
      externalId: String(item.productId || ''),
      name: String(item.title || ''),
      brand: String(item.brandName || ''),
      price: parseFloat(String(item.price || 0)),
      originalPrice: parseFloat(String(item.originalPrice || item.price || 0)),
      currency: 'CNY',
      images: String(item.images || '').split(',').filter(Boolean),
      mainImage: String(item.coverImage || '').split(',')[0] || '',
      category: String(item.categoryName || ''),
      description: String(item.title || ''),
      source: 'dewu',
      sourceUrl: `https://www.dewu.com/product/${item.productId}`,
      rating: parseFloat(String(item.rating || 0)),
      salesCount: parseInt(String(item.salesCount || 0), 10),
      tags: String(item.tags || '').split(',').filter(Boolean),
      createdAt: new Date(),
      updatedAt: new Date(),
    };
  }

  private async searchFromApi4Ai(
    query: string,
    options: Record<string, unknown>
  ): Promise<SearchResult> {
    const config = this.sources.get('api4ai');
    if (!config?.apiKey) {
      throw new Error('API4AI credentials not configured');
    }

    return {
      items: [],
      total: 0,
      page: (options.page as number) || 1,
      pageSize: (options.pageSize as number) || 20,
      source: 'api4ai',
    };
  }

  async getItemById(source: string, externalId: string): Promise<ClothingItem | null> {
    switch (source) {
      case 'taobao':
        return this.getTaobaoItem(externalId);
      case 'jd':
        return this.getJDItem(externalId);
      case 'dewu':
        return this.getDewuItem(externalId);
      default:
        throw new Error(`Unknown source: ${source}`);
    }
  }

  private async getTaobaoItem(itemId: string): Promise<ClothingItem | null> {
    const config = this.sources.get('taobao');
    if (!config?.apiKey || !config?.apiSecret) {
      return null;
    }

    const params: Record<string, string | number> = {
      method: 'taobao.tbk.item.info.get',
      app_key: config.apiKey,
      timestamp: new Date().toISOString().replace(/\.\d{3}/, ''),
      format: 'json',
      v: '2.0',
      sign_method: 'md5',
      num_iids: itemId,
    };

    const sign = this.generateTaobaoSign(params, config.apiSecret);
    params.sign = sign;

    try {
      const response = await this.axiosInstance.get(config.endpoint!, { params });
      const data = response.data;

      if (data.tbk_item_info_get_response?.results?.n_tbk_item?.[0]) {
        return this.normalizeTaobaoItem(data.tbk_item_info_get_response.results.n_tbk_item[0]);
      }
      return null;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Taobao get item error: ${errorMessage}`);
      return null;
    }
  }

  private async getJDItem(skuId: string): Promise<ClothingItem | null> {
    const config = this.sources.get('jd');
    if (!config?.apiKey || !config?.apiSecret) {
      return null;
    }

    const params: Record<string, string | number> = {
      method: 'jd.union.open.goods.promotiongoodsinfo.query',
      app_key: config.apiKey,
      timestamp: Date.now(),
      format: 'json',
      v: '1.0',
      sign_method: 'md5',
      skuIds: skuId,
    };

    const sign = this.generateJDSign(params, config.apiSecret);
    params.sign = sign;

    try {
      const response = await this.axiosInstance.get(config.endpoint!, { params });
      const data = response.data;

      if (data.result?.data?.[0]) {
        return this.normalizeJDItem(data.result.data[0]);
      }
      return null;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`JD get item error: ${errorMessage}`);
      return null;
    }
  }

  private async getDewuItem(productId: string): Promise<ClothingItem | null> {
    const config = this.sources.get('dewu');
    if (!config?.apiKey || !config?.apiSecret) {
      return null;
    }

    const timestamp = Date.now().toString();
    const sign = this.generateDewuSign({ productId }, config.apiSecret, timestamp);

    try {
      const response = await this.axiosInstance.get(`${config.endpoint}/v1/h5/product/detail`, {
        headers: {
          'X-App-Key': config.apiKey,
          'X-Timestamp': timestamp,
          'X-Sign': sign,
        },
        params: { productId },
      });

      if (response.data?.data) {
        return this.normalizeDewuItem(response.data.data);
      }
      return null;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Dewu get item error: ${errorMessage}`);
      return null;
    }
  }

  getAvailableSources(): string[] {
    return Array.from(this.sources.values())
      .filter((s) => s.enabled)
      .map((s) => s.name);
  }

  getSourceStatus(): Record<string, { enabled: boolean; priority: number }> {
    const status: Record<string, { enabled: boolean; priority: number }> = {};
    for (const [name, config] of this.sources) {
      status[name] = {
        enabled: config.enabled,
        priority: config.priority,
      };
    }
    return status;
  }
}

