import { Processor, WorkerHost } from '@nestjs/bullmq';
import { Logger } from '@nestjs/common';
import { Job } from 'bullmq';

import { PrismaService } from '../../common/prisma/prisma.service';

const FEATURE_FLAG_QUEUE = 'feature_flag_evaluations';

interface EvaluationJobData {
  flagId: string;
  userId: string | null;
  result: boolean;
  variant: string | null;
  attributes: Record<string, any> | null;
  evaluatedAt: string;
}

@Processor(FEATURE_FLAG_QUEUE)
export class FeatureFlagProcessor extends WorkerHost {
  private readonly logger = new Logger(FeatureFlagProcessor.name);

  constructor(private readonly prisma: PrismaService) {
    super();
  }

  async process(job: Job<EvaluationJobData>): Promise<void> {
    const { flagId, userId, result, variant, attributes, evaluatedAt } = job.data;

    try {
      await this.prisma.featureFlagEvaluation.create({
        data: {
          flagId,
          userId,
          result,
          variant,
          attributes: attributes ?? undefined,
          evaluatedAt: new Date(evaluatedAt),
        },
      });
    } catch (error) {
      this.logger.error(
        `Failed to log evaluation for flag ${flagId}: ${error instanceof Error ? error.message : String(error)}`,
      );
      throw error;
    }
  }
}

import type { FeatureFlag } from '@prisma/client';

export interface ABTestResult {
  enabled: boolean;
  variant: string;
}

export class ABTestStrategy {
  evaluate(flag: FeatureFlag, userId: string): ABTestResult {
    const variants = (flag.value as Record<string, any>).variants ?? [];
    if (!variants.length) {return { enabled: false, variant: 'control' };}

    const hash = this.hashUserId(userId, flag.key);
    const bucket = hash % 100;

    let cumulative = 0;
    for (const variant of variants) {
      cumulative += variant.weight ?? 0;
      if (bucket < cumulative) {
        return { enabled: true, variant: variant.name };
      }
    }
    return { enabled: true, variant: variants[0].name };
  }

  private hashUserId(userId: string, flagKey: string): number {
    const str = `${userId}:${flagKey}`;
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0;
    }
    return Math.abs(hash);
  }
}

import type { FeatureFlag } from '@prisma/client';

export class PercentageStrategy {
  evaluate(flag: FeatureFlag, userId: string): boolean {
    const percentage = (flag.value as Record<string, any>).percentage ?? 0;
    if (percentage <= 0) {return false;}
    if (percentage >= 100) {return true;}
    const hash = this.hashUserId(userId, flag.key);
    return (hash % 100) < percentage;
  }

  private hashUserId(userId: string, flagKey: string): number {
    const str = `${userId}:${flagKey}`;
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0;
    }
    return Math.abs(hash);
  }
}

import type { FeatureFlag } from '@prisma/client';

export class UserSegmentStrategy {
  evaluate(flag: FeatureFlag, _userId: string, attributes?: Record<string, any>): boolean {
    const rules = (flag.rules as Record<string, any>) ?? {};
    const segments = rules.segments ?? [];
    const userSegment = attributes?.userSegment ?? 'default';
    return segments.includes(userSegment);
  }
}

import {
  Injectable,
  CanActivate,
  ExecutionContext,
  UnauthorizedException,
  Inject,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import * as jwt from "jsonwebtoken";

import { PrismaService } from "../../../common/prisma/prisma.service";
import { JwtUserPayload } from "../../../common/types/common.types";

interface MerchantJwtPayload extends JwtUserPayload {
  merchantId?: string;
}

@Injectable()
export class MerchantAuthGuard implements CanActivate {
  constructor(
    private readonly prisma: PrismaService,
    @Inject(ConfigService) private readonly configService: ConfigService,
  ) {}

  async canActivate(context: ExecutionContext): Promise<boolean> {
    const request = context.switchToHttp().getRequest();
    const token = this.extractToken(request);

    if (!token) {
      throw new UnauthorizedException("No token provided");
    }

    const jwtSecret = this.configService.get<string>("JWT_SECRET");
    if (!jwtSecret) {
      throw new Error("JWT_SECRET environment variable is required");
    }

    try {
      const decoded = jwt.verify(token, jwtSecret) as MerchantJwtPayload;

      const merchant = await this.prisma.brandMerchant.findUnique({
        where: { id: decoded.merchantId },
        include: { brand: true },
      });

      if (!merchant?.isActive) {
        throw new UnauthorizedException("Merchant not found or inactive");
      }

      request.merchant = merchant;
      return true;
    } catch (_error) {
      throw new UnauthorizedException("Invalid token");
    }
  }

  private extractToken(request: { headers: { authorization?: string } }): string | null {
    const authHeader = request.headers.authorization;
    if (!authHeader) {return null;}

    const parts = authHeader.split(" ");
    if (parts.length !== 2 || parts[0] !== "Bearer") {return null;}

    return parts[1] ?? null;
  }
}

