import {
  Injectable,
  NotFoundException,
  BadRequestException,
  Logger,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { EventEmitter2 } from "@nestjs/event-emitter";
import { Cron } from "@nestjs/schedule";
import { PrismaClient as _PrismaClient, OrderStatus } from "@prisma/client";

import { resolveServiceUrl as _resolveServiceUrl } from "../../common/config/runtime-flags";
import { StructuredLoggerService as _StructuredLoggerService, ContextualLogger as _ContextualLogger } from "../../common/logging";
import { PrismaService } from "../../common/prisma/prisma.service";
import { RedisService } from "../../common/redis/redis.service";

import {
  CreatePaymentDto,
  _PaymentMethod,
  RefundPaymentDto,
  PaymentStatusResponseDto,
  RefundResponseDto,
  _PaymentRecordDto,
  PaymentListResponseDto,
  PaymentStatus,
} from "./dto";
import {
  PAYMENT_EVENTS,
  PaymentSucceededPayload,
  _PaymentFailedPayload,
  PaymentRefundedPayload,
  SubscriptionActivationPayload,
} from "./events";
import { AlipayProvider } from "./providers/alipay.provider";
import {
  PaymentProviderInterface,
  PaymentProvider,
  CreatePaymentOptions,
  PaymentResult,
  _PaymentCallbackData,
  RefundOptions,
} from "./providers/payment-provider.interface";
import { WechatProvider } from "./providers/wechat.provider";
import {
  PaymentOrderMetadata,
  _PaymentRecordMetadata,
  PaymentRawCallbackData,
} from "./types/common.types";


const PAYMENT_IDEMPOTENCY_PREFIX = "payment:idempotency:";
const IDEMPOTENCY_TTL_SECONDS = 300;

@Injectable()
export class PaymentService {
  private readonly logger = new Logger(PaymentService.name);
  private readonly providers: Map<PaymentProvider, PaymentProviderInterface>;

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
    private readonly alipayProvider: AlipayProvider,
    private readonly wechatProvider: WechatProvider,
    private readonly redisService: RedisService,
    private readonly eventEmitter: EventEmitter2,
  ) {
    this.providers = new Map<PaymentProvider, PaymentProviderInterface>([
      ["alipay", alipayProvider as PaymentProviderInterface],
      ["wechat", wechatProvider as PaymentProviderInterface],
    ]);
  }

  /**
   * 创建支付订单
   */
  async createPayment(
    userId: string,
    dto: CreatePaymentDto,
  ): Promise<PaymentResult> {
    this.logger.log("创建支付订单", {
      userId,
      provider: dto.provider,
      amount: dto.amount,
      orderId: dto.orderId,
    });

    const provider = this.getProvider(dto.provider as PaymentProvider);

    // 检查是否已存在未支付的订单
    const existingOrder = await this.prisma.paymentRecord.findFirst({
      where: {
        userId,
        status: "pending",
        expiredAt: { gt: new Date() },
      },
    });

    if (existingOrder) {
      // 返回已存在的订单信息
      const queryResult = await provider.queryPayment(existingOrder.orderId);
      if (queryResult.status === "pending") {
        return {
          success: true,
          orderId: existingOrder.orderId,
          qrCode: existingOrder.qrCode || undefined,
          expireAt: existingOrder.expiredAt ?? undefined,
        };
      }
    }

    // 获取订单信息（从订阅模块或自定义订单）
    const orderInfo = await this.getOrderInfo(dto.orderId, userId);

    // 创建支付记录
    const expireMinutes = dto.expireMinutes || 30;
    const expiredAt = new Date();
    expiredAt.setMinutes(expiredAt.getMinutes() + expireMinutes);

    const paymentRecord = await this.prisma.paymentRecord.create({
      data: {
        orderId: dto.orderId,
        userId,
        provider: dto.provider,
        amount: dto.amount || orderInfo.amount,
        currency: "CNY",
        status: "pending",
        expiredAt,
        metadata: {
          subject: dto.subject || orderInfo.subject,
          body: dto.body,
          originalOrderId: dto.orderId,
        },
      },
    });

    // 调用支付提供商创建支付
    const options: CreatePaymentOptions = {
      orderId: paymentRecord.orderId,
      amount: paymentRecord.amount.toNumber(),
      subject: dto.subject || orderInfo.subject || "寻裳会员订阅",
      body: dto.body,
      method: dto.method,
      clientIp: dto.clientIp,
      expireMinutes,
      notifyUrl: this.getNotifyUrl(dto.provider),
    };

    const result = await provider.createPayment(options);

    if (result.success) {
      // 更新支付记录
      await this.prisma.paymentRecord.update({
        where: { id: paymentRecord.id },
        data: {
          qrCode: result.qrCode,
          tradeNo: result.tradeNo,
        },
      });

      this.logger.log("支付订单创建成功", {
        orderId: dto.orderId,
        provider: dto.provider,
        amount: paymentRecord.amount.toNumber(),
        userId,
      });
    } else {
      // 更新状态为失败
      await this.prisma.paymentRecord.update({
        where: { id: paymentRecord.id },
        data: {
          status: "failed",
          failedReason: result.error?.message,
        },
      });

      this.logger.error("支付订单创建失败", undefined, {
        orderId: dto.orderId,
        provider: dto.provider,
        error: result.error?.message,
        userId,
      });
    }

    return result;
  }

  /**
   * 查询支付状态
   */
  async queryPayment(
    userId: string,
    orderId: string,
  ): Promise<PaymentStatusResponseDto> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    // 如果状态是 pending，查询最新状态
    if (record.status === "pending") {
      const provider = this.getProvider(record.provider as PaymentProvider);
      const queryResult = await provider.queryPayment(orderId);

      if (
        queryResult.status !== "pending" &&
        (queryResult.status as string) !== record.status
      ) {
        // 状态发生变化，更新记录
        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: queryResult.status,
            tradeNo: queryResult.tradeNo,
            paidAt: queryResult.paidAt,
          },
        });

        return {
          orderId,
          tradeNo: queryResult.tradeNo,
          amount: queryResult.amount ?? 0,
          status: queryResult.status as PaymentStatus,
          paidAt: queryResult.paidAt,
        };
      }
    }

    return {
      orderId,
      tradeNo: record.tradeNo || undefined,
      amount: record.amount.toNumber(),
      status: record.status as PaymentStatus,
      paidAt: record.paidAt || undefined,
    };
  }

  /**
   * 处理支付回调
   */
  async handleCallback(
    providerName: PaymentProvider,
    callbackData: PaymentRawCallbackData,
  ): Promise<{ success: boolean; message: string }> {
    this.logger.log("收到支付回调", { provider: providerName });

    const provider = this.getProvider(providerName);

    // 验证签名
    if (!provider.verifyCallbackSign(callbackData)) {
      this.logger.warn("支付回调签名验证失败", { provider: providerName });
      return { success: false, message: "Invalid signature" };
    }

    // 解析回调数据
    const parsedData = await provider.handleCallback(callbackData);
    const { orderId, tradeNo, amount, status, paidAt } = parsedData;

    // 幂等性保护：使用 Redis 分布式锁
    const lockKey = `${PAYMENT_IDEMPOTENCY_PREFIX}${orderId}`;
    const lockValue = `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    
    const lockAcquired = await this.redisService.getClient().set(
      lockKey,
      lockValue,
      "PX",
      IDEMPOTENCY_TTL_SECONDS * 1000,
      "NX"
    );

    if (!lockAcquired) {
      this.logger.log("订单正在处理中", { orderId });
      return { success: true, message: "Order is being processed" };
    }

    try {
      // 查找支付记录
      const record = await this.prisma.paymentRecord.findUnique({
        where: { orderId },
      });

      if (!record) {
        this.logger.warn("支付记录不存在", { orderId });
        return { success: false, message: "Order not found" };
      }

      // 检查订单状态
      if (record.status !== "pending") {
        this.logger.log("订单已处理", { orderId, status: record.status });
        return { success: true, message: "Order already processed" };
      }

      // 金额校验
      if (Math.abs(record.amount.toNumber() - amount) > 0.01) {
        this.logger.warn("支付金额不匹配", {
          orderId,
          expected: record.amount.toNumber(),
          actual: amount,
        });
        return { success: false, message: "Amount mismatch" };
      }

      // 使用事务更新状态
      await this.prisma.$transaction(async (tx) => {
        // 更新支付记录
        await tx.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: status === "paid" ? "paid" : "failed",
            tradeNo,
            paidAt,
            notifyData: JSON.parse(JSON.stringify(callbackData)),
          },
        });

        // 如果支付成功，激活订阅
        if (status === "paid") {
          await this.activateSubscription(record.userId, record.orderId);

          // 更新关联的 Order 状态为 paid
          await tx.order.updateMany({
            where: {
              id: record.orderId,
              status: OrderStatus.pending,
            },
            data: {
              status: OrderStatus.paid,
              paymentTime: new Date(),
            },
          });
        }
      });

      this.logger.log("支付回调处理成功", {
        orderId,
        status,
        userId: record.userId,
        amount: record.amount.toNumber(),
      });

      // Emit events for decoupled notification and subscription handling
      if (status === "paid") {
        const paymentOrder = await this.prisma.paymentOrder.findUnique({
          where: { id: orderId },
        });

        // Emit payment succeeded event
        const successPayload: PaymentSucceededPayload = {
          userId: record.userId,
          orderId,
          paymentRecordId: record.id,
          amount: record.amount.toNumber(),
          currency: record.currency,
          provider: record.provider,
          tradeNo,
          paidAt,
          metadata: paymentOrder?.metadata as PaymentOrderMetadata | undefined,
        };
        this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_SUCCEEDED, successPayload);
      }

      return { success: true, message: "Success" };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error("支付回调处理失败", errorStack, {
        orderId,
        error: errorMessage,
      });
      return { success: false, message: "Processing failed" };
    } finally {
      // 释放锁（使用 Lua 脚本确保原子性）
      const releaseScript = `
        if redis.call("get", KEYS[1]) == ARGV[1] then
          return redis.call("del", KEYS[1])
        else
          return 0
        end
      `;
      await this.redisService.getClient().eval(releaseScript, 1, lockKey, lockValue);
    }
  }

  /**
   * 申请退款
   */
  async refund(
    userId: string,
    dto: RefundPaymentDto,
  ): Promise<RefundResponseDto> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId: dto.orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    if (record.status !== "paid") {
      throw new BadRequestException("Only paid orders can be refunded");
    }

    if (dto.amount > record.amount.toNumber()) {
      throw new BadRequestException(
        "Refund amount cannot exceed payment amount",
      );
    }

    const refundId = `refund_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const provider = this.getProvider(record.provider as PaymentProvider);

    // 创建退款记录
    const _refundRecord = await this.prisma.refundRecord.create({
      data: {
        id: refundId,
        paymentRecordId: record.id,
        amount: dto.amount,
        reason: dto.reason,
        status: "processing",
      },
    });

    // 调用支付提供商退款
    const options: RefundOptions = {
      orderId: dto.orderId,
      refundId,
      amount: dto.amount,
      reason: dto.reason,
    };

    const result = await provider.refund(options);

    // 更新退款记录
    await this.prisma.refundRecord.update({
      where: { id: refundId },
      data: {
        status: result.success ? "success" : "failed",
        refundNo: result.refundNo,
        failedReason: result.error?.message,
      },
    });

    if (result.success) {
      // 如果是全额退款，更新支付记录状态
      if (dto.amount >= record.amount.toNumber()) {
        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: { status: "refunded", refundedAt: new Date() },
        });
      }

      // Emit refund event for notification
      const refundPayload: PaymentRefundedPayload = {
        userId: record.userId,
        orderId: dto.orderId,
        paymentRecordId: record.id,
        refundId,
        amount: dto.amount,
        reason: dto.reason,
      };
      this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_REFUNDED, refundPayload);
    }

    return result;
  }

  /**
   * 关闭订单
   */
  async closeOrder(userId: string, orderId: string): Promise<boolean> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    if (record.status !== "pending") {
      throw new BadRequestException("Only pending orders can be closed");
    }

    const provider = this.getProvider(record.provider as PaymentProvider);
    const success = await provider.closeOrder(orderId);

    if (success) {
      await this.prisma.paymentRecord.update({
        where: { id: record.id },
        data: { status: "closed" },
      });
    }

    return success;
  }

  /**
   * 获取支付记录列表
   */
  async getPaymentRecords(
    userId: string,
    page: number = 1,
    pageSize: number = 10,
  ): Promise<PaymentListResponseDto> {
    const where = { userId };

    const [records, total] = await Promise.all([
      this.prisma.paymentRecord.findMany({
        where,
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
      }),
      this.prisma.paymentRecord.count({ where }),
    ]);

    return {
      items: records.map((record) => ({
        id: record.id,
        orderId: record.orderId,
        userId: record.userId,
        provider: record.provider,
        amount: record.amount.toNumber(),
        currency: record.currency,
        status: record.status,
        tradeNo: record.tradeNo || undefined,
        paidAt: record.paidAt || undefined,
        createdAt: record.createdAt,
        expiredAt: record.expiredAt || undefined,
      })),
      total,
      page,
      pageSize,
    };
  }

  /**
   * 轮询支付状态（用于前端）
   */
  async pollPaymentStatus(
    userId: string,
    orderId: string,
  ): Promise<{ paid: boolean; status: string }> {
    const result = await this.queryPayment(userId, orderId);
    return {
      paid: result.status === "paid",
      status: result.status,
    };
  }

  // ==================== 私有方法 ====================

  /**
   * 获取支付提供商
   */
  private getProvider(name: PaymentProvider): PaymentProviderInterface {
    const provider = this.providers.get(name);
    if (!provider) {
      throw new BadRequestException(`Unsupported payment provider: ${name}`);
    }
    return provider;
  }

  /**
   * 获取回调 URL
   */
  private getNotifyUrl(provider: PaymentProvider): string {
    const baseUrl =
      this.configService.get<string>("BACKEND_URL") || "http://localhost:3001";
    return `${baseUrl}/api/v1/payment/callback/${provider}`;
  }

  /**
   * 获取订单信息
   */
  private async getOrderInfo(
    orderId: string,
    _userId: string,
  ): Promise<{ amount: number; subject: string }> {
    // 检查是否是订阅订单
    const paymentOrder = await this.prisma.paymentOrder.findUnique({
      where: { id: orderId },
    });

    if (paymentOrder) {
      const metadata = paymentOrder.metadata as PaymentOrderMetadata;
      const amount =
        typeof paymentOrder.amount === "number"
          ? paymentOrder.amount
          : (paymentOrder.amount as { toNumber?: () => number }).toNumber?.() ||
            Number(paymentOrder.amount);
      return {
        amount,
        subject: `寻裳 ${metadata?.planName || "会员"}订阅`,
      };
    }

    // 默认返回
    return {
      amount: 0,
      subject: "寻裳服务",
    };
  }

  /**
   * 激活订阅 - 通过事件驱动
   */
  private async activateSubscription(
    userId: string,
    orderId: string,
  ): Promise<void> {
    const paymentOrder = await this.prisma.paymentOrder.findUnique({
      where: { id: orderId },
    });

    if (paymentOrder) {
      const metadata = paymentOrder.metadata as PaymentOrderMetadata;
      if (metadata?.planId) {
        // Emit event instead of direct service call
        const payload: SubscriptionActivationPayload = {
          userId,
          orderId,
          planId: metadata.planId,
          paymentRecordId: orderId,
          metadata,
        };
        this.eventEmitter.emit(
          PAYMENT_EVENTS.SUBSCRIPTION_ACTIVATION_REQUIRED,
          payload,
        );
      }
    }
  }

  // FIX-CODE-007: 支付宝签名验证方法 (修复时间: 2026-03-19)
  verifyAlipaySignature(body: PaymentRawCallbackData): Promise<boolean> {
    try {
      const provider = this.getProvider("alipay");
      if ('verifyCallbackSign' in provider && typeof provider.verifyCallbackSign === 'function') {
        return provider.verifyCallbackSign(body);
      }
      this.logger.warn("支付宝Provider未实现签名验证方法");
      return false;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error("支付宝签名验证失败", undefined, { error: errorMessage });
      return false;
    }
  }

  /**
   * 自动关闭超时未支付订单（每5分钟执行）
   */
  @Cron("*/5 * * * *")
  async handleCloseExpiredPayments(): Promise<void> {
    const expiredThreshold = new Date();
    expiredThreshold.setMinutes(expiredThreshold.getMinutes() - 30);

    const expiredRecords = await this.prisma.paymentRecord.findMany({
      where: {
        status: "pending",
        expiredAt: { lt: new Date() },
        createdAt: { lt: expiredThreshold },
      },
      take: 50,
    });

    if (expiredRecords.length === 0) {
      return;
    }

    this.logger.log(`Found ${expiredRecords.length} expired payment records to close`);

    for (const record of expiredRecords) {
      try {
        const provider = this.getProvider(record.provider as PaymentProvider);
        await provider.closeOrder(record.orderId);

        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: "closed",
            cancelledAt: new Date(),
          },
        });

        await this.prisma.order.updateMany({
          where: {
            id: record.orderId,
            status: OrderStatus.pending,
          },
          data: {
            status: OrderStatus.cancelled,
          },
        });

        const orderWithItems = await this.prisma.order.findUnique({
          where: { id: record.orderId },
          include: { items: true },
        });

        if (orderWithItems && orderWithItems.items.length > 0) {
          await this.prisma.$transaction(
            orderWithItems.items.map((item) =>
              this.prisma.clothingItem.update({
                where: { id: item.itemId },
                data: { stock: { increment: item.quantity } },
              }),
            ),
          );
        }

        this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_CLOSED, {
          userId: record.userId,
          orderId: record.orderId,
          paymentRecordId: record.id,
        });

        this.logger.log(`Closed expired payment: ${record.orderId}`);
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        this.logger.error(
          `Failed to close expired payment ${record.orderId}: ${message}`,
        );
      }
    }
  }
}

import * as crypto from "crypto";
import * as fs from "fs";
import * as https from "https";
import * as path as _path from "path";

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import {
  PaymentRawCallbackData,
} from "../types/common.types";
import {
  WechatV3CreatePaymentResponse,
  WechatV3QueryResponse,
  WechatV3RefundResponse,
  WechatCallbackData,
  WechatCallbackPayload,
  WechatDecryptedResource,
  WechatV3RequestData,
  WechatApiResponse,
} from "../types/wechat.types";

import {
  PaymentProviderInterface,
  PaymentProvider,
  CreatePaymentOptions,
  PaymentResult,
  PaymentCallbackData,
  RefundOptions,
  RefundResult,
  PaymentQueryResult,
} from "./payment-provider.interface";


@Injectable()
export class WechatProvider implements PaymentProviderInterface, OnModuleInit {
  private readonly logger = new Logger(WechatProvider.name);
  readonly name: PaymentProvider = "wechat";

  private appId!: string;
  private mchId!: string;
  private apiKey!: string;
  private notifyUrl!: string;
  private certPath!: string;
  private keyPath!: string;
  private apiV3Key!: string;
  private serialNo!: string;

  // API 端点
  private readonly gateway = "https://api.mch.weixin.qq.com";
  private readonly v3Gateway = "https://api.mch.weixin.qq.com/v3";

  constructor(private readonly configService: ConfigService) {}

  onModuleInit() {
    this.appId = this.configService.get<string>("WECHAT_APP_ID") || "";
    this.mchId = this.configService.get<string>("WECHAT_MCH_ID") || "";
    this.apiKey = this.configService.get<string>("WECHAT_API_KEY") || "";
    this.apiV3Key = this.configService.get<string>("WECHAT_API_V3_KEY") || "";
    this.notifyUrl = this.configService.get<string>("WECHAT_NOTIFY_URL") || "";
    this.certPath = this.configService.get<string>("WECHAT_CERT_PATH") || "";
    this.keyPath = this.configService.get<string>("WECHAT_KEY_PATH") || "";
    this.serialNo = this.configService.get<string>("WECHAT_SERIAL_NO") || "";

    if (!this.appId || !this.mchId || !this.apiKey) {
      this.logger.warn(
        "Wechat Pay configuration is incomplete. Payment will not work.",
      );
    }
  }

  /**
   * 创建支付订单（使用 V3 API）
   */
  async createPayment(options: CreatePaymentOptions): Promise<PaymentResult> {
    try {
      const {
        orderId,
        amount,
        subject,
        _body,
        method,
        expireMinutes = 30,
      } = options;

      const expireAt = new Date();
      expireAt.setMinutes(expireAt.getMinutes() + expireMinutes);

      // 使用 V3 API
      const endpoint = this.getV3Endpoint(method);
      const requestData = this.buildV3RequestData(
        orderId,
        amount,
        subject,
        method,
        expireMinutes,
      );

      const response = await this.v3Request("POST", endpoint, requestData);

      if (!response.code) {
        // 请求成功
        const createResponse = response as WechatV3CreatePaymentResponse;
        const result: PaymentResult = {
          success: true,
          orderId,
          tradeNo: createResponse.prepay_id,
          expireAt,
          rawData: response as unknown as PaymentRawCallbackData,
        };

        switch (method) {
          case "qrcode":
          case "native":
            // Native 支付返回 code_url
            result.qrCode = createResponse.code_url;
            break;
          case "h5":
            // H5 支付返回 h5_url
            result.h5Url = createResponse.h5_url;
            break;
          case "app":
            // APP 支付返回 prepay_id，需要二次签名
            result.appPayload = this.buildAppPayload(createResponse.prepay_id || "");
            break;
        }

        return result;
      }

      return {
        success: false,
        orderId,
        error: {
          code: response.code,
          message: response.message || "创建支付失败",
          detail: response.detail,
        },
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to create wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        success: false,
        orderId: options.orderId,
        error: {
          code: "CREATE_PAYMENT_FAILED",
          message: "创建支付订单失败",
          detail: errorMessage,
        },
      };
    }
  }

  /**
   * 查询支付状态
   */
  async queryPayment(orderId: string): Promise<PaymentQueryResult> {
    try {
      const endpoint = `/v3/pay/transactions/out-trade-no/${orderId}?mchid=${this.mchId}`;
      const response = await this.v3Request("GET", endpoint);

      if (response.code) {
        return {
          orderId,
          status: "failed",
          rawData: response as unknown as PaymentRawCallbackData,
        };
      }

      const queryResponse = response as WechatV3QueryResponse;
      const statusMap: Record<string, PaymentQueryResult["status"]> = {
        NOTPAY: "pending",
        SUCCESS: "paid",
        CLOSED: "closed",
        REFUND: "refunded",
      };

      const tradeState = queryResponse.trade_state || "";
      return {
        orderId,
        tradeNo: queryResponse.transaction_id,
        amount: queryResponse.amount?.total ? queryResponse.amount.total / 100 : 0,
        status: statusMap[tradeState] || "failed",
        paidAt: queryResponse.success_time
          ? new Date(queryResponse.success_time)
          : undefined,
        rawData: response as unknown as PaymentRawCallbackData,
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to query wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        orderId,
        status: "failed",
        rawData: { error: errorMessage },
      };
    }
  }

  /**
   * 处理支付回调
   */
  handleCallback(
    callbackData: PaymentRawCallbackData,
  ): Promise<PaymentCallbackData> {
    const actualBody = (callbackData.body ?? callbackData) as WechatCallbackData;
    const resource = actualBody.resource;
    const decryptedData = this.decryptResource(resource);

    const statusMap: Record<string, PaymentCallbackData["status"]> = {
      SUCCESS: "paid",
      CLOSED: "cancelled",
      PAYERROR: "failed",
    };

    return {
      orderId: decryptedData.out_trade_no,
      tradeNo: decryptedData.transaction_id,
      amount: decryptedData.amount?.total
        ? decryptedData.amount.total / 100
        : 0,
      status: statusMap[decryptedData.trade_state] || "failed",
      paidAt: decryptedData.success_time
        ? new Date(decryptedData.success_time)
        : new Date(),
      rawData: callbackData,
    };
  }

  /**
   * 验证回调签名
   */
  verifyCallbackSign(callbackData: PaymentRawCallbackData): boolean {
    try {
      // 检查 callbackData 是否包含 WechatCallbackPayload 所需的结构
      const payload = callbackData as unknown as WechatCallbackPayload;
      const { headers, body } = payload;

      if (!headers || !body) {
        return false;
      }

      const timestamp = headers["wechatpay-timestamp"];
      const nonce = headers["wechatpay-nonce"];
      const signature = headers["wechatpay-signature"];
      const serial = headers["wechatpay-serial"];

      if (!timestamp || !nonce || !signature) {
        return false;
      }

      // 构建验签字符串
      const message = `${timestamp}\n${nonce}\n${body}\n`;

      // 使用微信支付平台公钥验证签名
      return this.verifySignature(message, signature, serial);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(
        `Failed to verify wechat callback sign: ${errorMessage}`,
      );
      return false;
    }
  }

  /**
   * 申请退款
   */
  async refund(options: RefundOptions): Promise<RefundResult> {
    try {
      const { orderId, refundId, amount, reason } = options;

      // 先查询原订单获取总金额
      const queryResult = await this.queryPayment(orderId);
      const totalAmount = (queryResult.amount ?? 0) * 100; // 转换为分

      const requestData = {
        out_trade_no: orderId,
        out_refund_no: refundId,
        reason: reason || "用户申请退款",
        amount: {
          refund: Math.round(amount * 100),
          total: Math.round(totalAmount),
          currency: "CNY",
        },
      };

      const response = await this.v3Request(
        "POST",
        "/v3/refund/domestic/refunds",
        requestData as unknown as WechatV3RequestData,
      );

      if (response.code) {
        return {
          success: false,
          refundId,
          status: "failed",
          error: {
            code: response.code,
            message: response.message || "退款失败",
            detail: response.detail,
          },
        };
      }

      const refundResponse = response as WechatV3RefundResponse;
      const statusMap: Record<string, RefundResult["status"]> = {
        SUCCESS: "success",
        PROCESSING: "processing",
        CLOSED: "failed",
      };

      const refundStatus = refundResponse.status || "";
      return {
        success: true,
        refundId,
        refundNo: refundResponse.refund_id,
        status: statusMap[refundStatus] || "processing",
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to refund wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        success: false,
        refundId: options.refundId,
        status: "failed",
        error: {
          code: "REFUND_ERROR",
          message: "退款异常",
          detail: errorMessage,
        },
      };
    }
  }

  /**
   * 关闭订单
   */
  async closeOrder(orderId: string): Promise<boolean> {
    try {
      const endpoint = `/v3/pay/transactions/out-trade-no/${orderId}/close`;
      const requestData = {
        mchid: this.mchId,
      };

      const response = await this.v3Request("POST", endpoint, requestData as unknown as WechatV3RequestData);
      return !response.code;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to close wechat order: ${errorMessage}`,
        errorStack,
      );
      return false;
    }
  }

  // ==================== 私有方法 ====================

  /**
   * 获取 V3 API 端点
   */
  private getV3Endpoint(method: string): string {
    const endpointMap: Record<string, string> = {
      qrcode: "/v3/pay/transactions/native",
      native: "/v3/pay/transactions/native",
      h5: "/v3/pay/transactions/h5",
      app: "/v3/pay/transactions/app",
    };
    return endpointMap[method] || "/v3/pay/transactions/native";
  }

  /**
   * 构建 V3 请求数据
   */
  private buildV3RequestData(
    orderId: string,
    amount: number,
    description: string,
    method: string,
    expireMinutes: number,
  ): WechatV3RequestData {
    const baseData: WechatV3RequestData = {
      appid: this.appId,
      mchid: this.mchId,
      description,
      out_trade_no: orderId,
      notify_url: this.notifyUrl,
      amount: {
        total: Math.round(amount * 100), // 转换为分
        currency: "CNY",
      },
    };

    // 设置过期时间
    const expireTime = new Date();
    expireTime.setMinutes(expireTime.getMinutes() + expireMinutes);
    baseData.time_expire = expireTime.toISOString();

    // 根据支付方式添加额外参数
    if (method === "h5") {
      (baseData as WechatV3RequestData & { scene_info: unknown }).scene_info = {
        payer_client_ip: "127.0.0.1",
        h5_info: {
          type: "Wap",
        },
      };
    }

    return baseData;
  }

  /**
   * 构建 APP 支付参数
   */
  private buildAppPayload(prepayId: string): string {
    const timestamp = Math.floor(Date.now() / 1000).toString();
    const nonceStr = crypto.randomBytes(16).toString("hex");
    const packageStr = `prepay_id=${prepayId}`;

    const message = `${this.appId}\n${timestamp}\n${nonceStr}\n${packageStr}\n`;
    const signature = this.signV3(message);

    const params = {
      appid: this.appId,
      partnerid: this.mchId,
      prepayid: prepayId,
      package: "Sign=WXPay",
      noncestr: nonceStr,
      timestamp,
      sign: signature,
    };

    return JSON.stringify(params);
  }

  /**
   * V3 API 请求
   */
  private async v3Request(
    method: string,
    endpoint: string,
    data?: WechatV3RequestData,
  ): Promise<WechatApiResponse> {
    const url = `${this.v3Gateway}${endpoint}`;
    const timestamp = Math.floor(Date.now() / 1000).toString();
    const nonceStr = crypto.randomBytes(16).toString("hex");

    let bodyStr = "";
    if (data && method !== "GET") {
      bodyStr = JSON.stringify(data);
    }

    const message = `${method}\n${endpoint}\n${timestamp}\n${nonceStr}\n${bodyStr}\n`;
    const signature = this.signV3(message);

    const authorization = `WECHATPAY2-SHA256-RSA2048 mchid="${this.mchId}",nonce_str="${nonceStr}",timestamp="${timestamp}",serial_no="${this.serialNo}",signature="${signature}"`;

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      Accept: "application/json",
      Authorization: authorization,
    };

    try {
      const https = await import("https");
      const agent = this.getHttpsAgent();

      return new Promise((resolve, reject) => {
        const req = https.request(
          url,
          {
            method,
            headers,
            agent,
          },
          (res) => {
            let responseData = "";
            res.on("data", (chunk) => (responseData += chunk));
            res.on("end", () => {
              try {
                resolve(JSON.parse(responseData) as WechatApiResponse);
              } catch (_parseError) {
                // WeChat API may return non-JSON responses in some cases
                // Log this for debugging but continue with raw response
                this.logger.debug(
                  `WeChat API returned non-JSON response (status: ${res.statusCode}). Response (truncated): ${responseData.substring(0, 200)}`,
                );
                resolve({ raw: responseData } as unknown as WechatApiResponse);
              }
            });
          },
        );

        req.on("error", reject);

        if (bodyStr) {
          req.write(bodyStr);
        }
        req.end();
      });
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`V3 request error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * V3 签名
   */
  private signV3(message: string): string {
    try {
      const sign = crypto.createSign("RSA-SHA256");
      sign.update(message);

      const privateKey = this.getPrivateKey();
      return sign.sign(privateKey, "base64");
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`V3 sign error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * 验证签名
   */
  private verifySignature(
    message: string,
    signature: string,
    serial: string,
  ): boolean {
    try {
      const platformCert = this.configService.get<string>(
        "WECHAT_PLATFORM_CERT",
      );
      if (!platformCert) {
        this.logger.error(
          "SECURITY ALERT: Platform certificate not configured. " +
            "Callback signature verification is DISABLED. " +
            "This is a critical security risk - configure WECHAT_PLATFORM_CERT immediately.",
        );
        return false;
      }

      const verify = crypto.createVerify("RSA-SHA256");
      verify.update(message);

      const cert = this.formatCertificate(platformCert);
      const isValid = verify.verify(cert, signature, "base64");

      if (!isValid) {
        this.logger.error(
          `Signature verification failed for serial: ${serial}. ` +
            "Possible callback forgery attempt detected.",
        );
      }

      return isValid;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(
        `Verify signature error: ${errorMessage}. ` +
          "Rejecting callback for security reasons.",
      );
      return false;
    }
  }

  /**
   * 解密回调数据
   */
  private decryptResource(resource: WechatCallbackData["resource"]): WechatDecryptedResource {
    try {
      const { ciphertext, nonce, associated_data } = resource;
      const key = Buffer.from(this.apiV3Key, "utf8");
      const iv = Buffer.from(nonce, "utf8");
      const authTag = Buffer.from(ciphertext.slice(-16), "base64");
      const data = Buffer.from(ciphertext.slice(0, -16), "base64");

      const decipher = crypto.createDecipheriv("aes-256-gcm", key, iv);
      decipher.setAuthTag(authTag);
      decipher.setAAD(Buffer.from(associated_data || "", "utf8"));

      let decrypted = decipher.update(data, undefined, "utf8");
      decrypted += decipher.final("utf8");

      return JSON.parse(decrypted) as WechatDecryptedResource;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`Decrypt resource error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * 获取私钥
   */
  private getPrivateKey(): string {
    if (this.keyPath) {
      // 实际应该从文件读取
      return this.formatPrivateKey(this.keyPath);
    }
    return this.formatPrivateKey(
      this.configService.get<string>("WECHAT_PRIVATE_KEY") || "",
    );
  }

  /**
   * 获取 HTTPS Agent（包含证书）
   */
  private getHttpsAgent(): https.Agent | undefined {
    try {
      const certFilePath = this.certPath;
      const keyFilePath = this.keyPath;

      if (certFilePath && keyFilePath) {
        if (fs.existsSync(certFilePath) && fs.existsSync(keyFilePath)) {
          const cert = fs.readFileSync(certFilePath);
          const key = fs.readFileSync(keyFilePath);

          return new https.Agent({
            cert,
            key,
            rejectUnauthorized: true,
          });
        }

        this.logger.warn(
          `WeChat certificate files not found: cert=${certFilePath}, key=${keyFilePath}`,
        );
      }

      const certEnv = this.configService.get<string>("WECHAT_CERT_CONTENT");
      const keyEnv = this.configService.get<string>("WECHAT_KEY_CONTENT");

      if (certEnv && keyEnv) {
        return new https.Agent({
          cert: Buffer.from(certEnv, "utf8"),
          key: Buffer.from(keyEnv, "utf8"),
          rejectUnauthorized: true,
        });
      }

      this.logger.warn(
        "WeChat merchant certificate not configured. " +
          "Set WECHAT_CERT_PATH/WECHAT_KEY_PATH or WECHAT_CERT_CONTENT/WECHAT_KEY_CONTENT. " +
          "Using default Agent (some V3 API calls may fail).",
      );
      return undefined;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to create HTTPS agent: ${message}`);
      return undefined;
    }
  }

  /**
   * 格式化私钥
   */
  private formatPrivateKey(key: string): string {
    if (key.includes("-----BEGIN")) {
      return key;
    }
    return `-----BEGIN PRIVATE KEY-----\n${key}\n-----END PRIVATE KEY-----`;
  }

  /**
   * 格式化证书
   */
  private formatCertificate(cert: string): string {
    if (cert.includes("-----BEGIN")) {
      return cert;
    }
    return `-----BEGIN CERTIFICATE-----\n${cert}\n-----END CERTIFICATE-----`;
  }
}

import * as crypto from "crypto";
import * as https from "https";

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { resolveServiceUrl } from "../../../common/config/runtime-flags";
import { sanitizeImage } from "../../../common/security/image-sanitizer";

interface AliyunBodyAnalysisResult {
  BodyType?: string;
  UpperBodyRatio?: number;
  LowerBodyRatio?: number;
  ShoulderWidth?: number;
  WaistWidth?: number;
  HipWidth?: number;
}

interface AliyunFaceAnalysisResult {
  FaceShape?: string;
  SkinTone?: string;
  Age?: number;
  Gender?: string;
  Beauty?: number;
}

interface BodyFaceAnalysisResult {
  bodyType?: string;
  skinTone?: string;
  faceShape?: string;
  colorSeason?: string;
  confidence: number;
  rawResult: Record<string, unknown>;
}

@Injectable()
export class AiAnalysisService {
  private readonly logger = new Logger(AiAnalysisService.name);
  private readonly accessKeyId: string;
  private readonly accessKeySecret: string;
  private readonly region: string;
  private readonly aiServiceUrl: string;
  private aiClient: AxiosInstance;
  private aiServiceAvailable = false;
  private readonly localSkinTonePalette: Array<{
    name: string;
    rgb: [number, number, number];
  }> = [
    { name: "fair", rgb: [244, 218, 201] },
    { name: "light", rgb: [228, 190, 165] },
    { name: "medium", rgb: [198, 151, 118] },
    { name: "olive", rgb: [168, 135, 96] },
    { name: "tan", rgb: [145, 105, 72] },
    { name: "dark", rgb: [104, 72, 46] },
  ];

  constructor(private configService: ConfigService) {
    this.accessKeyId = this.configService.get<string>(
      "ALIYUN_ACCESS_KEY_ID",
      "",
    );
    this.accessKeySecret = this.configService.get<string>(
      "ALIYUN_ACCESS_KEY_SECRET",
      "",
    );
    this.region = this.configService.get<string>(
      "ALIYUN_REGION",
      "cn-shanghai",
    );
    this.aiServiceUrl = resolveServiceUrl(this.configService, "AI_SERVICE_URL", "http://localhost:8001");

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 30000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkAiServiceHealth();
  }

  private async checkAiServiceHealth(): Promise<void> {
    try {
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      if (response.data?.status === "healthy") {
        this.aiServiceAvailable = true;
        this.logger.log("Python AI Service connected for body analysis");
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `Python AI Service not available (${this.aiServiceUrl}): ${errorMessage}. Body/face analysis will fall back to Aliyun.`,
      );
      this.aiServiceAvailable = false;
    }
  }

  async analyzeBodyAndFace(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    if (this.aiServiceAvailable) {
      try {
        return await this.callPythonAIService(imageBuffer);
      } catch (error) {
        const message =
          error instanceof Error ? error.message : "Unknown error";
        this.logger.warn(
          `Python AI Service failed, falling back to Aliyun: ${message}`,
        );
      }
    }

    if (!this.accessKeyId || !this.accessKeySecret) {
      this.logger.warn(
        "Aliyun credentials are not configured, using local heuristic body analysis",
      );
      return this.runLocalAnalysis(imageBuffer);
    }

    return this.callAliyunAnalysis(imageBuffer);
  }

  private async callPythonAIService(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    const base64Image = imageBuffer.toString("base64");

    const response = await this.aiClient.post(
      "/api/body-analysis",
      { image_base64: base64Image },
      { headers: { "Content-Type": "application/json" } },
    );

    const data = response.data?.data;
    if (!data) {
      throw new Error("Invalid response from AI service");
    }

    return {
      bodyType: data.body_type,
      skinTone: data.skin_tone,
      faceShape:
        typeof data.face_shape === "string" ? data.face_shape : undefined,
      colorSeason: data.color_season,
      confidence: typeof data.confidence === "number" ? data.confidence : 0.9,
      rawResult: data,
    };
  }

  private async callAliyunAnalysis(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    try {
      const base64Image = imageBuffer.toString("base64");

      const [bodyResult, faceResult] = await Promise.allSettled([
        this.callAliyunBodyAnalysis(base64Image),
        this.callAliyunFaceAnalysis(base64Image),
      ]);

      if (
        bodyResult.status === "rejected" &&
        faceResult.status === "rejected"
      ) {
        throw new Error(
          `Aliyun analysis failed: ${bodyResult.reason?.message || "body failed"}; ${faceResult.reason?.message || "face failed"}`,
        );
      }

      const bodyData =
        bodyResult.status === "fulfilled" ? bodyResult.value : {};
      const faceData =
        faceResult.status === "fulfilled" ? faceResult.value : {};

      const bodyType = this.mapBodyType(bodyData);
      const skinTone = this.mapSkinTone(faceData);
      const faceShape = this.mapFaceShape(faceData);
      const colorSeason = this.determineColorSeason(skinTone, faceData);

      return {
        bodyType,
        skinTone,
        faceShape,
        colorSeason,
        confidence: this.calculateConfidence(bodyResult, faceResult),
        rawResult: { body: bodyData, face: faceData },
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      this.logger.error(`AI analysis failed: ${message}`);
      return this.runLocalAnalysis(imageBuffer);
    }
  }

  private async runLocalAnalysis(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    const sharp = (await import("sharp")).default;
    const image = sanitizeImage(sharp(imageBuffer, { failOn: "none" })).rotate();
    const [metadata, stats] = await Promise.all([image.metadata(), image.stats()]);

    const width = metadata.width ?? 1;
    const height = metadata.height ?? 1;
    const aspectRatio = width / Math.max(height, 1);
    const dominant = [
      Math.round(stats.dominant.r),
      Math.round(stats.dominant.g),
      Math.round(stats.dominant.b),
    ] as [number, number, number];
    const brightness = this.calculateLuminance(dominant);
    const saturation = this.calculateSaturation(dominant);
    const warmth = dominant[0] - dominant[2];
    const confidence = 0.72;

    const skinTone = this.mapRgbToSkinTone(dominant);
    const faceShape = this.estimateFaceShape(aspectRatio, saturation);
    const bodyType = this.estimateBodyType(aspectRatio, saturation);
    const colorSeason = this.estimateColorSeason(skinTone, warmth, brightness);

    return {
      bodyType,
      skinTone,
      faceShape,
      colorSeason,
      confidence,
      rawResult: {
        source: "local_heuristic",
        width,
        height,
        aspectRatio,
        dominantColor: dominant,
        brightness,
        saturation,
        warmth,
      },
    };
  }

  private async callAliyunBodyAnalysis(
    imageBase64: string,
  ): Promise<AliyunBodyAnalysisResult> {
    const params = {
      Action: "DetectBodyCount",
      Version: "2020-03-20",
      ImageURL: `data:image/jpeg;base64,${imageBase64}`,
    };

    try {
      const response = await this.makeAliyunRequest(
        "/viapi/body/analysis",
        params,
      ) as Record<string, { BodyType?: string; UpperBodyRatio?: number; LowerBodyRatio?: number; ShoulderWidth?: number; WaistWidth?: number; HipWidth?: number }>;
      return response.Data || {};
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      throw new Error(`Body analysis API failed: ${message}`);
    }
  }

  private async callAliyunFaceAnalysis(
    imageBase64: string,
  ): Promise<AliyunFaceAnalysisResult> {
    const params = {
      Action: "DetectFace",
      Version: "2020-03-20",
      ImageURL: `data:image/jpeg;base64,${imageBase64}`,
    };

    try {
      const response = await this.makeAliyunRequest(
        "/viapi/face/analysis",
        params,
      ) as Record<string, { FaceAttributes?: AliyunFaceAnalysisResult }>;
      return response.Data?.FaceAttributes || {};
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      throw new Error(`Face analysis API failed: ${message}`);
    }
  }

  private async makeAliyunRequest(
    path: string,
    params: Record<string, string>,
  ): Promise<unknown> {
    const method = "POST";
    const host = `viapi.${this.region}.aliyuncs.com`;

    const timestamp = new Date().toISOString().replace(/\.\d{3}/, "");
    const nonce = crypto.randomUUID();

    const sortedParams = Object.entries(params)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
      .join("&");

    const stringToSign = `${method}&${encodeURIComponent("/")}&${encodeURIComponent(sortedParams)}`;

    const hmac = crypto.createHmac("sha1", `${this.accessKeySecret}&`);
    const signature = hmac.update(stringToSign).digest("base64");

    const requestBody = `${sortedParams}&Signature=${encodeURIComponent(signature)}`;

    return new Promise((resolve, reject) => {
      const req = https.request(
        {
          method,
          host,
          path,
          headers: {
            "Content-Type": "application/x-www-form-urlencoded",
            "x-acs-action": params.Action,
            "x-acs-version": params.Version,
            "x-acs-date": timestamp,
            "x-acs-signature-nonce": nonce,
          },
        },
        (res) => {
          let data = "";
          res.on("data", (chunk) => (data += chunk));
          res.on("end", () => {
            try {
              resolve(JSON.parse(data));
            } catch (parseError) {
              const errorMessage = parseError instanceof Error ? parseError.message : String(parseError);
              this.logger.error(
                `Failed to parse Aliyun API response as JSON. Status: ${res.statusCode}. Raw response (truncated): ${data.substring(0, 200)}. Error: ${errorMessage}`,
              );
              reject(new Error(`Invalid JSON response from Aliyun API: ${errorMessage}`));
            }
          });
        },
      );

      req.on("error", reject);
      req.write(requestBody);
      req.end();
    });
  }

  private mapBodyType(data: AliyunBodyAnalysisResult): string | undefined {
    if (!data.BodyType) {return undefined;}

    const typeMap: Record<string, string> = {
      Rectangle: "rectangle",
      Triangle: "triangle",
      InvertedTriangle: "inverted_triangle",
      Hourglass: "hourglass",
      Oval: "oval",
    };

    return typeMap[data.BodyType] || "rectangle";
  }

  private mapSkinTone(data: AliyunFaceAnalysisResult): string | undefined {
    if (!data.SkinTone) {return undefined;}

    const toneMap: Record<string, string> = {
      Fair: "fair",
      Light: "light",
      Medium: "medium",
      Olive: "olive",
      Tan: "tan",
      Dark: "dark",
    };

    return toneMap[data.SkinTone] || "medium";
  }

  private mapFaceShape(data: AliyunFaceAnalysisResult): string | undefined {
    if (!data.FaceShape) {return undefined;}

    const shapeMap: Record<string, string> = {
      Oval: "oval",
      Round: "round",
      Square: "square",
      Heart: "heart",
      Oblong: "oblong",
      Diamond: "diamond",
    };

    return shapeMap[data.FaceShape] || "oval";
  }

  private calculateLuminance([r, g, b]: [number, number, number]): number {
    return 0.299 * r + 0.587 * g + 0.114 * b;
  }

  private calculateSaturation([r, g, b]: [number, number, number]): number {
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);

    if (max === 0) {
      return 0;
    }

    return (max - min) / max;
  }

  private mapRgbToSkinTone(rgb: [number, number, number]): string {
    let best = this.localSkinTonePalette[0];
    if (!best) {
      return "medium";
    }

    let bestDistance = Number.POSITIVE_INFINITY;
    for (const candidate of this.localSkinTonePalette) {
      const [cr, cg, cb] = candidate.rgb;
      const distance = Math.sqrt(
        Math.pow(rgb[0] - cr, 2) +
          Math.pow(rgb[1] - cg, 2) +
          Math.pow(rgb[2] - cb, 2),
      );
      if (distance < bestDistance) {
        bestDistance = distance;
        best = candidate;
      }
    }

    return best.name;
  }

  private estimateFaceShape(
    aspectRatio: number,
    saturation: number,
  ): string {
    if (aspectRatio > 0.92) {
      return "round";
    }

    if (aspectRatio < 0.68) {
      return "oblong";
    }

    if (saturation < 0.18) {
      return "oval";
    }

    return "heart";
  }

  private estimateBodyType(
    aspectRatio: number,
    saturation: number,
  ): string {
    if (aspectRatio < 0.56) {
      return "hourglass";
    }

    if (aspectRatio < 0.68) {
      return saturation > 0.35 ? "triangle" : "rectangle";
    }

    return "rectangle";
  }

  private estimateColorSeason(
    skinTone: string,
    warmth: number,
    brightness: number,
  ): string {
    if (brightness > 180) {
      return warmth >= 0 ? "spring" : "summer";
    }

    if (skinTone === "tan" || skinTone === "olive" || warmth > 18) {
      return "autumn";
    }

    return "winter";
  }

  private determineColorSeason(
    skinTone: string | undefined,
    _faceData: AliyunFaceAnalysisResult,
  ): string | undefined {
    if (!skinTone) {return undefined;}

    const seasonBySkinTone: Record<string, string> = {
      fair: "summer",
      light: "spring",
      medium: "autumn",
      olive: "autumn",
      tan: "winter",
      dark: "winter",
    };

    return seasonBySkinTone[skinTone] || "autumn";
  }

  private calculateConfidence(
    bodyResult: PromiseSettledResult<unknown>,
    faceResult: PromiseSettledResult<unknown>,
  ): number {
    let confidence = 0.5;

    if (bodyResult.status === "fulfilled") {confidence += 0.25;}
    if (faceResult.status === "fulfilled") {confidence += 0.25;}

    return Math.min(confidence, 1.0);
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { resolveServiceUrl } from "../../../common/config/runtime-flags";

export interface BodyImageAnalysisInput {
  image: Buffer;
  userMeasurements?: BodyMeasurements;
}

export interface BodyMeasurements {
  height?: number;
  weight?: number;
  shoulderWidth?: number;
  bustWidth?: number;
  waistWidth?: number;
  hipWidth?: number;
  inseam?: number;
}

export interface BodyImageAnalysisResult {
  bodyType: BodyType;
  confidence: number;
  measurements: EstimatedMeasurements;
  proportions: BodyProportions;
  recommendations: BodyTypeRecommendations;
  processingTime: number;
}

export type BodyType =
  | "rectangle"
  | "hourglass"
  | "triangle"
  | "inverted_triangle"
  | "oval";

export interface EstimatedMeasurements {
  shoulderWidth: number;
  bustWidth: number;
  waistWidth: number;
  hipWidth: number;
  heightEstimate: number;
  confidence: number;
}

export interface BodyProportions {
  shoulderToHip: number;
  waistToHip: number;
  waistToShoulder: number;
  legToTorso: number;
  category: string;
}

export interface BodyTypeRecommendations {
  suitableStyles: string[];
  avoidStyles: string[];
  colorRecommendations: string[];
  fitRecommendations: string[];
}

export interface PoseKeypoint {
  x: number;
  y: number;
  confidence: number;
  name: string;
}

export interface BodySegmentation {
  torso: number[][];
  legs: number[][];
  arms: number[][];
  head: number[][];
}

@Injectable()
export class BodyImageAnalysisService {
  private readonly logger = new Logger(BodyImageAnalysisService.name);

  private readonly inferenceClient: AxiosInstance;
  private readonly useLocalModel: boolean;
  private readonly modelEndpoint: string;

  private readonly bodyTypeRules = {
    rectangle: {
      name: "矩形/H型",
      description: "肩、腰、臀宽度相近，身体线条平直",
      characteristics: ["肩宽与臀宽相近", "腰部曲线不明显", "腿部通常较长"],
    },
    hourglass: {
      name: "沙漏型/X型",
      description: "肩臀相近，腰部明显纤细，曲线明显",
      characteristics: ["肩宽与臀宽相近", "腰部明显收紧", "胸部丰满"],
    },
    triangle: {
      name: "梨形/A型",
      description: "臀部比肩宽，下半身较丰满",
      characteristics: ["肩部较窄", "臀部较宽", "大腿较粗"],
    },
    inverted_triangle: {
      name: "倒三角/Y型",
      description: "肩部比臀宽，上半身较丰满",
      characteristics: ["肩部较宽", "胸部较丰满", "臀部较窄"],
    },
    oval: {
      name: "椭圆形/O型",
      description: "腰部较粗，四肢相对纤细",
      characteristics: ["腰围较大", "腹部较圆润", "四肢较细"],
    },
  };

  constructor(private configService: ConfigService) {
    this.modelEndpoint = resolveServiceUrl(this.configService, "BODY_ANALYSIS_ENDPOINT", "http://localhost:8003");
    this.useLocalModel =
      this.configService.get<string>("USE_LOCAL_BODY_ANALYSIS", "false") ===
      "true";

    this.inferenceClient = axios.create({
      baseURL: this.modelEndpoint,
      timeout: 60000,
      headers: {
        "Content-Type": "application/json",
      },
    });

    this.logger.log(
      `Body Image Analysis Service initialized. Local model: ${this.useLocalModel}`,
    );
  }

  async analyzeBodyImage(
    input: BodyImageAnalysisInput,
  ): Promise<BodyImageAnalysisResult> {
    const startTime = Date.now();

    try {
      let poseKeypoints: PoseKeypoint[] = [];
      let segmentation: BodySegmentation | null = null;
      let estimatedMeasurements: EstimatedMeasurements;

      if (this.useLocalModel) {
        const inferenceResult = await this.runLocalInference(input.image);
        poseKeypoints = inferenceResult.keypoints;
        _segmentation = inferenceResult.segmentation;
      } else {
        poseKeypoints = this.estimatePoseKeypoints(input.image);
      }

      if (input.userMeasurements) {
        estimatedMeasurements = this.mergeMeasurements(
          poseKeypoints,
          input.userMeasurements,
        );
      } else {
        estimatedMeasurements =
          this.estimateMeasurementsFromPose(poseKeypoints);
      }

      const proportions = this.calculateProportions(estimatedMeasurements);
      const bodyType = this.determineBodyType(proportions);
      const recommendations = this.generateRecommendations(
        bodyType,
        proportions,
        estimatedMeasurements,
      );

      const result: BodyImageAnalysisResult = {
        bodyType,
        confidence: this.calculateConfidence(
          poseKeypoints,
          estimatedMeasurements,
        ),
        measurements: estimatedMeasurements,
        proportions,
        recommendations,
        processingTime: Date.now() - startTime,
      };

      this.logger.log(
        `Body analysis completed. Type: ${bodyType}, Confidence: ${result.confidence.toFixed(2)}`,
      );

      return result;
    } catch (error) {
      this.logger.error(
        `Body analysis failed: ${
          error instanceof Error ? error.message : "Unknown error"
        }`,
      );
      throw error;
    }
  }

  private async runLocalInference(
    image: Buffer,
  ): Promise<{ keypoints: PoseKeypoint[]; segmentation: BodySegmentation }> {
    const imageBase64 = image.toString("base64");

    try {
      const response = await this.inferenceClient.post("/analyze", {
        image: imageBase64,
        tasks: ["pose_estimation", "segmentation"],
      });

      return {
        keypoints: response.data.keypoints || [],
        segmentation:
          response.data.segmentation || this.createEmptySegmentation(),
      };
    } catch (error) {
      this.logger.warn(
        `Local inference failed, using estimation: ${
          error instanceof Error ? error.message : "Unknown error"
        }`,
      );
      return {
        keypoints: this.estimatePoseKeypoints(image),
        segmentation: this.createEmptySegmentation(),
      };
    }
  }

  private estimatePoseKeypoints(image: Buffer): PoseKeypoint[] {
    const imageHash = this.hashBuffer(image);

    const baseKeypoints: { name: string; baseX: number; baseY: number }[] = [
      { name: "nose", baseX: 0.5, baseY: 0.1 },
      { name: "left_shoulder", baseX: 0.35, baseY: 0.2 },
      { name: "right_shoulder", baseX: 0.65, baseY: 0.2 },
      { name: "left_elbow", baseX: 0.3, baseY: 0.35 },
      { name: "right_elbow", baseX: 0.7, baseY: 0.35 },
      { name: "left_wrist", baseX: 0.25, baseY: 0.5 },
      { name: "right_wrist", baseX: 0.75, baseY: 0.5 },
      { name: "left_hip", baseX: 0.4, baseY: 0.55 },
      { name: "right_hip", baseX: 0.6, baseY: 0.55 },
      { name: "left_knee", baseX: 0.42, baseY: 0.75 },
      { name: "right_knee", baseX: 0.58, baseY: 0.75 },
      { name: "left_ankle", baseX: 0.44, baseY: 0.95 },
      { name: "right_ankle", baseX: 0.56, baseY: 0.95 },
    ];

    const variation = ((imageHash % 100) - 50) / 500;

    return baseKeypoints.map((kp) => ({
      x: Math.max(0, Math.min(1, kp.baseX + variation * (Math.random() - 0.5))),
      y: Math.max(0, Math.min(1, kp.baseY + variation * (Math.random() - 0.5))),
      confidence: 0.6 + (imageHash % 40) / 100,
      name: kp.name,
    }));
  }

  private hashBuffer(buffer: Buffer): number {
    let hash = 0;
    for (let i = 0; i < Math.min(buffer.length, 1000); i++) {
      hash = (hash << 5) - hash + (buffer[i] ?? 0);
      hash = hash & hash;
    }
    return Math.abs(hash);
  }

  private createEmptySegmentation(): BodySegmentation {
    return {
      torso: [],
      legs: [],
      arms: [],
      head: [],
    };
  }

  private mergeMeasurements(
    keypoints: PoseKeypoint[],
    userMeasurements: BodyMeasurements,
  ): EstimatedMeasurements {
    const shoulderWidth =
      userMeasurements.shoulderWidth ||
      this.estimateShoulderWidth(keypoints, userMeasurements.height);

    const hipWidth =
      userMeasurements.hipWidth ||
      this.estimateHipWidth(keypoints, userMeasurements.height);

    const waistWidth =
      userMeasurements.waistWidth ||
      this.estimateWaistWidth(keypoints, userMeasurements.height);

    const bustWidth = userMeasurements.bustWidth || waistWidth * 1.1;

    return {
      shoulderWidth,
      bustWidth,
      waistWidth,
      hipWidth,
      heightEstimate: userMeasurements.height || 170,
      confidence: userMeasurements.height ? 0.9 : 0.6,
    };
  }

  private estimateMeasurementsFromPose(
    keypoints: PoseKeypoint[],
  ): EstimatedMeasurements {
    const leftShoulder = keypoints.find((k) => k.name === "left_shoulder");
    const rightShoulder = keypoints.find((k) => k.name === "right_shoulder");
    const leftHip = keypoints.find((k) => k.name === "left_hip");
    const rightHip = keypoints.find((k) => k.name === "right_hip");

    const shoulderWidth =
      leftShoulder && rightShoulder
        ? Math.abs(leftShoulder.x - rightShoulder.x) * 100
        : 40;

    const hipWidth =
      leftHip && rightHip ? Math.abs(leftHip.x - rightHip.x) * 100 : 35;

    const waistWidth = ((shoulderWidth + hipWidth) / 2) * 0.85;
    const bustWidth = shoulderWidth * 0.9;

    const avgConfidence =
      keypoints.reduce((sum, k) => sum + k.confidence, 0) / keypoints.length;

    return {
      shoulderWidth: Math.round(shoulderWidth),
      bustWidth: Math.round(bustWidth),
      waistWidth: Math.round(waistWidth),
      hipWidth: Math.round(hipWidth),
      heightEstimate: 170,
      confidence: avgConfidence,
    };
  }

  private estimateShoulderWidth(
    keypoints: PoseKeypoint[],
    height?: number,
  ): number {
    const leftShoulder = keypoints.find((k) => k.name === "left_shoulder");
    const rightShoulder = keypoints.find((k) => k.name === "right_shoulder");

    if (leftShoulder && rightShoulder) {
      const pixelWidth = Math.abs(leftShoulder.x - rightShoulder.x);
      return Math.round(pixelWidth * (height || 170) * 0.25);
    }

    return 40;
  }

  private estimateHipWidth(keypoints: PoseKeypoint[], height?: number): number {
    const leftHip = keypoints.find((k) => k.name === "left_hip");
    const rightHip = keypoints.find((k) => k.name === "right_hip");

    if (leftHip && rightHip) {
      const pixelWidth = Math.abs(leftHip.x - rightHip.x);
      return Math.round(pixelWidth * (height || 170) * 0.3);
    }

    return 35;
  }

  private estimateWaistWidth(
    _keypoints: PoseKeypoint[],
    _height?: number,
  ): number {
    return 32;
  }

  private calculateProportions(
    measurements: EstimatedMeasurements,
  ): BodyProportions {
    const { shoulderWidth, waistWidth, hipWidth } = measurements;

    const shoulderToHip = shoulderWidth / hipWidth;
    const waistToHip = waistWidth / hipWidth;
    const waistToShoulder = waistWidth / shoulderWidth;

    let category = "balanced";
    if (shoulderToHip > 1.1) {category = "upper_dominant";}
    else if (shoulderToHip < 0.9) {category = "lower_dominant";}
    else if (waistToHip > 0.85) {category = "mid_dominant";}

    return {
      shoulderToHip,
      waistToHip,
      waistToShoulder,
      legToTorso: 0.5,
      category,
    };
  }

  private determineBodyType(proportions: BodyProportions): BodyType {
    const { shoulderToHip, waistToHip, waistToShoulder } = proportions;

    if (
      Math.abs(shoulderToHip - 1) < 0.1 &&
      waistToHip < 0.75 &&
      waistToShoulder < 0.75
    ) {
      return "hourglass";
    }

    if (shoulderToHip < 0.9 && waistToHip > 0.7) {
      return "triangle";
    }

    if (shoulderToHip > 1.1 && waistToShoulder < 0.85) {
      return "inverted_triangle";
    }

    if (waistToShoulder > 0.9 && waistToHip > 0.9) {
      return "oval";
    }

    return "rectangle";
  }

  private calculateConfidence(
    keypoints: PoseKeypoint[],
    measurements: EstimatedMeasurements,
  ): number {
    const keypointConfidence =
      keypoints.reduce((sum, k) => sum + k.confidence, 0) / keypoints.length;

    const measurementConfidence = measurements.confidence;

    return keypointConfidence * 0.4 + measurementConfidence * 0.6;
  }

  private generateRecommendations(
    bodyType: BodyType,
    _proportions: BodyProportions,
    _measurements: EstimatedMeasurements,
  ): BodyTypeRecommendations {
    const recommendations: Record<BodyType, BodyTypeRecommendations> = {
      rectangle: {
        suitableStyles: ["收腰设计", "层次搭配", "V领上衣", "A字裙", "高腰裤"],
        avoidStyles: ["直筒裙", "无腰身设计", "过于宽松的款式"],
        colorRecommendations: ["深色系显瘦", "亮色点缀", "渐变色"],
        fitRecommendations: ["强调腰线", "增加层次感", "选择有结构感的面料"],
      },
      hourglass: {
        suitableStyles: [
          "收腰款式",
          "铅笔裙",
          "高腰裤",
          "裹身裙",
          "紧身针织衫",
        ],
        avoidStyles: ["宽松直筒款式", "无腰身设计", "超大号衣服"],
        colorRecommendations: ["单色系", "深色显瘦", "腰带点缀"],
        fitRecommendations: ["突出腰线", "贴合曲线", "选择有弹性的面料"],
      },
      triangle: {
        suitableStyles: [
          "垫肩上衣",
          "荷叶边衬衫",
          "亮色上衣",
          "A字裙",
          "阔腿裤",
        ],
        avoidStyles: ["紧身裤", "短裙", "浅色下装", "包臀裙"],
        colorRecommendations: ["上身亮色", "下身深色", "上身有图案"],
        fitRecommendations: ["上身增加体积感", "下身简洁流畅", "避免紧身下装"],
      },
      inverted_triangle: {
        suitableStyles: ["V领上衣", "深色上衣", "阔腿裤", "A字裙", "百褶裙"],
        avoidStyles: ["垫肩设计", "泡泡袖", "紧身裙", "亮色上衣"],
        colorRecommendations: ["上身深色", "下身亮色", "下身有图案"],
        fitRecommendations: ["上身简洁", "下身增加体积感", "平衡上下比例"],
      },
      oval: {
        suitableStyles: ["V领上衣", "深色上衣", "直筒裤", "A字裙", "垂感衬衫"],
        avoidStyles: ["紧身款式", "亮色大面积", "横条纹", "腰部有装饰的设计"],
