@ApiTags('queue')
@ApiBearerAuth()
@Controller('queue')
@UseGuards(JwtAuthGuard)
export class QueueController {
  constructor(private readonly queueService: QueueService) {}

  @Post('style-analysis')
  @ApiOperation({ summary: 'Create a style analysis task' })
  @ApiResponse({ status: 201, description: 'Task created successfully' })
  async createStyleAnalysis(
    @CurrentUser('id') userId: string,
    @Body() dto: CreateStyleAnalysisDto,
  ) {
    return this.queueService.addStyleAnalysisTask(
      userId,
      dto.userInput,
      dto.userProfile,
    );
  }

  @Post('virtual-tryon')
  @ApiOperation({ summary: 'Create a virtual try-on task' })
  @ApiResponse({ status: 201, description: 'Task created successfully' })
  async createVirtualTryOn(
    @CurrentUser('id') userId: string,
    @Body() dto: CreateVirtualTryOnDto,
  ) {
    return this.queueService.addVirtualTryOnTask(
      userId,
      dto.photoId,
      dto.itemId,
      dto.category,
    );
  }

  @Post('wardrobe-match')
  @ApiOperation({ summary: 'Create a wardrobe match task' })
  @ApiResponse({ status: 201, description: 'Task created successfully' })
  async createWardrobeMatch(
    @CurrentUser('id') userId: string,
    @Body() dto: CreateWardrobeMatchDto,
  ) {
    return this.queueService.addWardrobeMatchTask(
      userId,
      dto.wardrobeItems,
      dto.targetStyle,
      dto.occasion,
      dto.season,
    );
  }

  @Post('recommendation')
  @ApiOperation({ summary: 'Create a recommendation task' })
  @ApiResponse({ status: 201, description: 'Task created successfully' })
  async createRecommendation(
    @CurrentUser('id') userId: string,
    @Body() dto: CreateRecommendationDto,
  ) {
    return this.queueService.addRecommendationTask(
      userId,
      dto.userInput,
      dto.userProfile,
      dto.occasion,
      dto.category,
      dto.topK,
    );
  }

  @Get('jobs/:jobId')
  @ApiOperation({ summary: 'Get job status' })
  @ApiResponse({ status: 200, description: 'Job status retrieved' })
  @ApiResponse({ status: 404, description: 'Job not found' })
  async getJobStatus(@Param('jobId') jobId: string) {
    const job = await this.queueService.getJobStatus(jobId);
    if (!job) {
      return { error: 'Job not found', statusCode: 404 };
    }
    return job;
  }

  @Get('jobs')
  @ApiOperation({ summary: 'Get user jobs' })
  @ApiResponse({ status: 200, description: 'Jobs retrieved' })
  async getUserJobs(
    @CurrentUser('id') userId: string,
    @Query('limit') limit?: string,
  ) {
    const parsedLimit = limit ? parseInt(limit, 10) : 20;
    return this.queueService.getUserJobs(userId, parsedLimit);
  }

  @Delete('jobs/:jobId')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Cancel a job' })
  @ApiResponse({ status: 200, description: 'Job cancelled' })
  @ApiResponse({ status: 400, description: 'Cannot cancel job' })
  async cancelJob(
    @Param('jobId') jobId: string,
    @CurrentUser('id') userId: string,
  ) {
    const cancelled = await this.queueService.cancelJob(jobId, userId);
    if (!cancelled) {
      return { error: 'Cannot cancel job', statusCode: 400 };
    }
    return { message: 'Job cancelled successfully', jobId };
  }

  @Post('jobs/:jobId/retry')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Retry a failed job' })
  @ApiResponse({ status: 200, description: 'Job retried' })
  @ApiResponse({ status: 400, description: 'Cannot retry job' })
  async retryJob(
    @Param('jobId') jobId: string,
    @CurrentUser('id') userId: string,
  ) {
    const retried = await this.queueService.retryJob(jobId, userId);
    if (!retried) {
      return { error: 'Cannot retry job', statusCode: 400 };
    }
    return { message: 'Job retried successfully', jobId };
  }

  @Get('stats')
  @ApiOperation({ summary: 'Get queue statistics' })
  @ApiResponse({ status: 200, description: 'Queue statistics' })
  async getQueueStats() {
    return this.queueService.getQueueStats();
  }
}

import { BullModule } from '@nestjs/bullmq';
import { Module, Logger, forwardRef } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';

import { GatewayModule } from '../../common/gateway/gateway.module';
import { AIModule } from '../ai/ai.module';
import { CommunityModule } from '../community/community.module';
import { TryOnModule } from '../try-on/try-on.module';

import { QueueName } from './queue-config';
import { QueueMonitorService } from './queue-monitor.service';
import { QUEUE_NAMES } from './queue.constants';
import { QueueController } from './queue.controller';
import {
  QueueProcessor,
  StyleAnalysisProcessor,
  VirtualTryOnProcessor,
  WardrobeMatchProcessor,
  ContentModerationProcessor,
} from './queue.processor';
import { QueueService } from './queue.service';


const logger = new Logger('QueueModule');

@Module({
  imports: [
    // Import GatewayModule to access NotificationService
    GatewayModule,
    AIModule,
    forwardRef(() => CommunityModule),
    forwardRef(() => TryOnModule),
    // Register BullMQ with Redis connection
    BullModule.forRootAsync({
      imports: [ConfigModule],
      useFactory: (configService: ConfigService) => {
        const redisUrl = configService.get<string>('REDIS_URL', 'redis://localhost:6379');
        // Parse Redis URL if it's in the format redis://host:port
        let host = 'localhost';
        let port = 6379;
        let password: string | undefined;

        try {
          const url = new URL(redisUrl);
          host = url.hostname || 'localhost';
          port = parseInt(url.port) || 6379;
          password = url.password || undefined;
        } catch (error) {
          // If URL parsing fails, use defaults
          const errorMessage = error instanceof Error ? error.message : String(error);
          logger.warn(
            `Failed to parse REDIS_URL '${redisUrl}': ${errorMessage}. Using default connection settings (localhost:6379).`,
          );
        }

        return {
          connection: {
            host,
            port,
            password,
          },
          defaultJobOptions: {
            attempts: 3,
            backoff: {
              type: 'exponential',
              delay: 1000,
            },
            removeOnComplete: {
              count: 100,
              age: 24 * 3600, // 24 hours
            },
            removeOnFail: {
              count: 50,
              age: 7 * 24 * 3600, // 7 days
            },
          },
        };
      },
      inject: [ConfigService],
    }),
    // Register individual queues
    BullModule.registerQueue(
      { name: QUEUE_NAMES.AI_TASKS },
      { name: QUEUE_NAMES.STYLE_ANALYSIS },
      { name: QUEUE_NAMES.VIRTUAL_TRYON },
      { name: QUEUE_NAMES.WARDROBE_MATCH },
      { name: QueueName.BODY_ANALYSIS },
      { name: QueueName.PHOTO_PROCESSING },
      { name: QueueName.AI_GENERATION },
      { name: QueueName.NOTIFICATION },
      { name: QueueName.DATA_EXPORT },
      { name: QueueName.CONTENT_MODERATION },
    ),
  ],
  controllers: [QueueController],
  providers: [
    QueueService,
    QueueMonitorService,
    QueueProcessor,
    StyleAnalysisProcessor,
    VirtualTryOnProcessor,
    WardrobeMatchProcessor,
    ContentModerationProcessor,
  ],
  exports: [QueueService, QueueMonitorService],
})
export class QueueModule {}

