/**
 * 将 Prisma Decimal 类型转换为 number
 */
function toNumber(value: Prisma.Decimal | number | null | undefined): number {
  if (value === null || value === undefined) {
    return 0;
  }
  if (typeof value === "number") {
    return value;
  }
  return parseFloat(value.toString());
}

export interface RecommendationContext {
  userId?: string;
  occasion?: string;
  season?: string;
  weather?: string;
  trending?: boolean;
}

export interface ScoredItem {
  id: string;
  name: string;
  images: string[];
  price: number;
  currency: string;
  brand?: {
    id: string;
    name: string;
    logo?: string | null;
  } | null;
  score: number;
  matchReasons: string[];
  category: ClothingCategory;
  breakdown?: {
    contentBased: number;
    collaborative: number;
    knowledgeGraph: number;
    theoryBased: number;
  };
}

interface StylePreferenceItem {
  name: string;
  [key: string]: unknown;
}

type StylePreferences = StylePreferenceItem[] | string[] | null;

interface UserProfile {
  bodyType?: BodyType | null;
  skinTone?: SkinTone | null;
  colorSeason?: ColorSeason | null;
  stylePreferences?: StylePreferences;
  colorPreferences?: string[] | null;
}

interface UserBehaviorData {
  favorites: Array<{ item: Pick<ClothingItem, "category"> | null }>;
  tryOns: Array<{ item: Pick<ClothingItem, "brandId"> | null }>;
  views: Array<{
    query: string;
    id: string;
    createdAt: Date;
    userId: string | null;
    sessionId?: string | null;
  }>;
}

interface ItemAttributes {
  bodyTypeFit?: BodyType[];
  colorSeasons?: ColorSeason[];
  style?: string[];
  occasions?: string[];
}

function toUserProfile(profile: PrismaUserProfile | null): UserProfile | null {
  if (!profile) {return null;}

  let stylePrefs: StylePreferences = null;
  if (profile.stylePreferences) {
    if (Array.isArray(profile.stylePreferences)) {
      stylePrefs = profile.stylePreferences as StylePreferences;
    }
  }

  let colorPrefs: string[] | null = null;
  if (profile.colorPreferences) {
    if (Array.isArray(profile.colorPreferences)) {
      colorPrefs = profile.colorPreferences as string[];
    }
  }

  return {
    bodyType: profile.bodyType,
    skinTone: profile.skinTone,
    colorSeason: profile.colorSeason,
    stylePreferences: stylePrefs,
    colorPreferences: colorPrefs,
  };
}

@Injectable()
export class AdvancedRecommendationService implements OnModuleInit {
  private readonly logger = new Logger(AdvancedRecommendationService.name);

  private readonly strategyWeights = {
    contentBased: 0.25,
    collaborative: 0.25,
    knowledgeGraph: 0.25,
    theoryBased: 0.25,
  };

  constructor(
    private prisma: PrismaService,
    private multimodalFusion: MultimodalFusionService,
    private knowledgeGraph: KnowledgeGraphService,
    private matchingTheory: MatchingTheoryService,
  ) {}

  async onModuleInit() {
    this.logger.log("初始化知识图谱...");
    await this.knowledgeGraph.buildGraph();
    const stats = this.knowledgeGraph.getGraphStats();
    this.logger.log(
      `知识图谱构建完成: ${stats.nodeCount}节点, ${stats.edgeCount}边`,
    );
  }

  async getPersonalizedRecommendations(
    userId: string,
    context: RecommendationContext = {},
    limit: number = 20,
  ): Promise<ScoredItem[]> {
    const prismaProfile = await this.prisma.userProfile.findUnique({
      where: { userId },
    });
    const profile = toUserProfile(prismaProfile);

    const userBehaviors = await this.getUserBehaviors(userId);

    const candidates = await this.getCandidateItems(limit * 4);

    const scoredItems = await Promise.all(
      candidates.map(async (item) => {
        const scores = await this.calculateAllScores(
          profile,
          item,
          userBehaviors,
          context,
        );

        const totalScore = this.combineScores(scores);

        const matchReasons = this.generateMatchReasons(
          profile,
          item,
          scores,
          context,
        );

        return {
          id: item.id,
          name: item.name,
          images: item.images,
          price: toNumber(item.price),
          currency: item.currency,
          brand: item.brand,
          category: item.category,
          score: totalScore,
          matchReasons,
          breakdown: scores,
        };
      }),
    );

    scoredItems.sort((a, b) => b.score - a.score);

    const diverseItems = this.optimizeDiversity(scoredItems, limit);

    return diverseItems;
  }

  private async calculateAllScores(
    profile: UserProfile | null,
    item: ClothingItem,
    userBehaviors: UserBehaviorData,
    context: RecommendationContext,
  ): Promise<{
    contentBased: number;
    collaborative: number;
    knowledgeGraph: number;
    theoryBased: number;
  }> {
    const contentScore = await this.contentBasedScore(profile, item, context);
    const collaborativeScore = this.collaborativeScore(item, userBehaviors);
    const kgScore = await this.knowledgeGraphScore(item, context);
    const theoryScore = this.theoryBasedScore(item, profile, context);

    return {
      contentBased: contentScore,
      collaborative: collaborativeScore,
      knowledgeGraph: kgScore,
      theoryBased: theoryScore,
    };
  }

  private async contentBasedScore(
    profile: UserProfile | null,
    item: ClothingItem,
    context: RecommendationContext,
  ): Promise<number> {
    if (!profile) {return 0.5;}

    const attrs = item.attributes as ItemAttributes | null;
    let score = 0.5;

    if (profile.bodyType && attrs?.bodyTypeFit) {
      if (attrs.bodyTypeFit.includes(profile.bodyType)) {
        score += 0.15;
      }
    }

    if (profile.colorSeason && attrs?.colorSeasons) {
      if (attrs.colorSeasons.includes(profile.colorSeason)) {
        score += 0.1;
      }
    }

    if (profile.skinTone && item.colors?.length > 0) {
      const flatteringColors = this.matchingTheory.getFlatteringColors(
        profile.skinTone,
      );
      const hasFlatteringColor = item.colors.some((c: string) =>
        flatteringColors.some((fc) =>
          c.toLowerCase().includes(fc.toLowerCase()),
        ),
      );
      if (hasFlatteringColor) {
        score += 0.1;
      }
    }

    if (profile.stylePreferences && attrs?.style) {
      const userStyles = Array.isArray(profile.stylePreferences)
        ? profile.stylePreferences.map((s) =>
            typeof s === "string" ? s : s.name,
          )
        : [];
      const itemStyles = attrs.style || [];
      const matchingStyles = userStyles.filter((s: string) =>
        itemStyles.some((is: string) => is.toLowerCase() === s.toLowerCase()),
      );
      score += matchingStyles.length * 0.05;
    }

    if (context.occasion && attrs?.occasions) {
      if (attrs.occasions.includes(context.occasion)) {
        score += 0.1;
      }
    }

    return Math.min(score, 1);
  }

  private collaborativeScore(
    item: ClothingItem,
    userBehaviors: UserBehaviorData,
  ): number {
    let score = 0.5;

    const favoriteCategories = new Set(
      userBehaviors.favorites
        .map((f) => f.item?.category)
        .filter((c): c is ClothingCategory => c !== undefined),
    );
    if (favoriteCategories.has(item.category)) {
      score += 0.1;
    }

    const triedBrands = new Set(
      userBehaviors.tryOns
        .map((t) => t.item?.brandId)
        .filter((id): id is string => id !== null),
    );
    if (item.brandId && triedBrands.has(item.brandId)) {
      score += 0.05;
    }

    score += Math.min(item.viewCount / 200, 0.05);
    score += Math.min(item.likeCount / 100, 0.05);

    return Math.min(score, 1);
  }

  private async knowledgeGraphScore(
    item: ClothingItem,
    context: RecommendationContext,
  ): Promise<number> {
    let score = 0.5;

    const relatedItems = this.knowledgeGraph.findRelatedItems(item.id, [
      "frequently_bought_together",
    ]);
    score += Math.min(relatedItems.length * 0.02, 0.1);

    const compatibleItems = this.knowledgeGraph.findCompatibleItemsByStyle(
      item.id,
    );
    score += Math.min(compatibleItems.length * 0.01, 0.1);

    if (context.occasion) {
      const occasionItems = this.knowledgeGraph.getItemsForOccasion(
        context.occasion,
      );
      const isSuitable = occasionItems.some((i) => i.id === `item_${item.id}`);
      if (isSuitable) {
        score += 0.1;
      }
    }

    return Math.min(score, 1);
  }

  private theoryBasedScore(
    item: ClothingItem,
    profile: UserProfile | null,
    context: RecommendationContext,
  ): number {
    if (!profile) {return 0.5;}

    const attrs = item.attributes as ItemAttributes | null;
    const outfitScore = this.matchingTheory.calculateOutfitScore({
      bodyType: profile.bodyType || undefined,
      skinTone: profile.skinTone || undefined,
      colorSeason: profile.colorSeason || undefined,
      itemColors: item.colors || [],
      itemStyles: attrs?.style || [],
      occasion: context.occasion,
    });

    return outfitScore.score;
  }

  private combineScores(scores: {
    contentBased: number;
    collaborative: number;
    knowledgeGraph: number;
    theoryBased: number;
  }): number {
    return (
      scores.contentBased * this.strategyWeights.contentBased +
      scores.collaborative * this.strategyWeights.collaborative +
      scores.knowledgeGraph * this.strategyWeights.knowledgeGraph +
      scores.theoryBased * this.strategyWeights.theoryBased
    );
  }

  async getOccasionRecommendations(
    userId: string,
    occasion: string,
    limit: number = 10,
  ): Promise<ScoredItem[]> {
    const prismaProfile = await this.prisma.userProfile.findUnique({
      where: { userId },
    });
    const profile = toUserProfile(prismaProfile);

    const styleGuide = this.matchingTheory.getOccasionStyleGuide(occasion);

    const items = await this.prisma.clothingItem.findMany({
      where: {
        isActive: true,
        category: {
          in: [
            ClothingCategory.tops,
            ClothingCategory.bottoms,
            ClothingCategory.dresses,
          ],
        },
      },
      include: {
        brand: { select: { id: true, name: true, logo: true } },
      },
      take: limit * 3,
    });

    const scoredItems = items.map((item) => {
      const attrs = item.attributes as ItemAttributes | null;

      let score = 50;

      if (attrs?.occasions?.includes(occasion)) {
        score += 20;
      }

      if (attrs?.style) {
        const matchingStyles = attrs.style.filter((s: string) =>
          styleGuide.suitableStyles.includes(s.toLowerCase()),
        );
        score += matchingStyles.length * 10;
      }

      if (item.colors) {
        const matchingColors = item.colors.filter((c: string) =>
          styleGuide.suitableColors.some((sc) =>
            c.toLowerCase().includes(sc.toLowerCase()),
          ),
        );
        score += matchingColors.length * 5;
      }

      if (profile) {
        const theoryScore = this.theoryBasedScore(item, profile, { occasion });
        score += theoryScore * 30;
      }

      return {
        id: item.id,
        name: item.name,
        images: item.images,
        price: toNumber(item.price),
        currency: item.currency,
        brand: item.brand,
        category: item.category,
        score: Math.min(score, 100),
        matchReasons: [`适合${this.getOccasionName(occasion)}场合`],
      };
    });

    scoredItems.sort((a, b) => b.score - a.score);

    return scoredItems.slice(0, limit);
  }

  async getOutfitRecommendation(
    baseItemId: string,
    userId?: string,
    occasion?: string,
  ): Promise<{
    tops?: ScoredItem[];
    bottoms?: ScoredItem[];
    accessories?: ScoredItem[];
    overallScore: number;
  }> {
    let profile: UserProfile | null = null;
    if (userId) {
      const prismaProfile = await this.prisma.userProfile.findUnique({
        where: { userId },
      });
      profile = toUserProfile(prismaProfile);
    }

    const baseItem = await this.prisma.clothingItem.findUnique({
      where: { id: baseItemId },
    });

    if (!baseItem) {
      throw new Error("Base item not found");
    }

    const categories = this.getComplementaryCategories(baseItem.category);

    const results: Record<string, ScoredItem[]> = {};
    let totalScore = 0;
    let count = 0;

    for (const [key, category] of Object.entries(categories)) {
      const candidates = await this.prisma.clothingItem.findMany({
        where: { isActive: true, category },
        include: { brand: { select: { id: true, name: true, logo: true } } },
        take: 50,
      });

      const scored = await Promise.all(
        candidates.map(async (item) => {
          const scores = await this.calculateAllScores(
            profile,
            item,
            { favorites: [], tryOns: [], views: [] },
            { occasion },
          );

          const totalScore = this.combineScores(scores);

          return {
            id: item.id,
            name: item.name,
            images: item.images,
            price: toNumber(item.price),
            currency: item.currency,
            brand: item.brand,
            category: item.category,
            score: totalScore,
            matchReasons: this.generateMatchReasons(profile, item, scores, {
              occasion,
            }),
          };
        }),
      );

      scored.sort((a, b) => b.score - a.score);
      results[key] = scored.slice(0, 5);

      const firstScored = scored[0];
      if (firstScored) {
        totalScore += firstScored.score;
        count++;
      }
    }

    return {
      ...results,
      overallScore: count > 0 ? totalScore / count : 0,
    };
  }

  private getComplementaryCategories(
    baseCategory: ClothingCategory,
  ): Record<string, ClothingCategory> {
    const complementMap: Record<
      ClothingCategory,
      Record<string, ClothingCategory>
    > = {
      [ClothingCategory.tops]: {
        bottoms: ClothingCategory.bottoms,
        footwear: ClothingCategory.footwear,
        accessories: ClothingCategory.accessories,
      },
      [ClothingCategory.bottoms]: {
        tops: ClothingCategory.tops,
        footwear: ClothingCategory.footwear,
        accessories: ClothingCategory.accessories,
      },
      [ClothingCategory.dresses]: {
        footwear: ClothingCategory.footwear,
        accessories: ClothingCategory.accessories,
        outerwear: ClothingCategory.outerwear,
      },
      [ClothingCategory.outerwear]: {
        tops: ClothingCategory.tops,
        bottoms: ClothingCategory.bottoms,
        footwear: ClothingCategory.footwear,
      },
      [ClothingCategory.footwear]: {
        tops: ClothingCategory.tops,
        bottoms: ClothingCategory.bottoms,
      },
      [ClothingCategory.accessories]: {
        tops: ClothingCategory.tops,
        bottoms: ClothingCategory.bottoms,
      },
      [ClothingCategory.activewear]: {
        footwear: ClothingCategory.footwear,
        accessories: ClothingCategory.accessories,
      },
      [ClothingCategory.swimwear]: {
        footwear: ClothingCategory.footwear,
        accessories: ClothingCategory.accessories,
      },
    };

    return complementMap[baseCategory] || {};
  }

  async getTrendingRecommendations(limit: number = 20): Promise<ScoredItem[]> {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const items = await this.prisma.clothingItem.findMany({
      where: {
        isActive: true,
        createdAt: { gte: thirtyDaysAgo },
      },
      include: {
        brand: { select: { id: true, name: true, logo: true } },
      },
      orderBy: [{ viewCount: "desc" }, { likeCount: "desc" }],
      take: limit * 2,
    });

    const scoredItems = items.map((item) => {
      const viewScore = Math.min(item.viewCount / 50, 30);
      const likeScore = Math.min(item.likeCount / 25, 30);
      const recencyScore = 20;
      const featuredScore = item.isFeatured ? 20 : 0;

      return {
        id: item.id,
        name: item.name,
        images: item.images,
        price: toNumber(item.price),
        currency: item.currency,
        brand: item.brand,
        category: item.category,
        score: Math.min(
          viewScore + likeScore + recencyScore + featuredScore,
          100,
        ),
        matchReasons: ["热门单品", "近期爆款"],
      };
    });

    scoredItems.sort((a, b) => b.score - a.score);

    return scoredItems.slice(0, limit);
  }

  async getDailyOutfitRecommendation(userId: string): Promise<{
    items: ScoredItem[];
    outfitName: string;
    description: string;
  }> {
    const prismaProfile = await this.prisma.userProfile.findUnique({
      where: { userId },
    });
    const profile = toUserProfile(prismaProfile);

    const outfitTemplates = [
      {
        name: "简约通勤风",
        categories: [
          ClothingCategory.tops,
          ClothingCategory.bottoms,
          ClothingCategory.footwear,
        ],
        description: "简洁大方的职场穿搭，展现专业气质",
      },
      {
        name: "休闲舒适风",
        categories: [ClothingCategory.tops, ClothingCategory.bottoms],
        description: "轻松自在的日常穿搭，舒适为主",
      },
      {
        name: "优雅知性风",
        categories: [ClothingCategory.dresses, ClothingCategory.accessories],
        description: "温柔优雅的气质穿搭",
      },
    ];

    const today = new Date();
    const templateIndex = today.getDate() % outfitTemplates.length;
    // 使用非空断言，因为取模运算保证了索引有效
    const selectedTemplate = outfitTemplates[templateIndex]!;

    const items: ScoredItem[] = [];

    for (const category of selectedTemplate.categories) {
      const categoryItems = await this.prisma.clothingItem.findMany({
        where: {
          isActive: true,
          category,
        },
        include: {
          brand: { select: { id: true, name: true, logo: true } },
        },
        take: 5,
      });

      if (categoryItems.length > 0) {
        const bestItem = await this.findBestItem(categoryItems, profile);
        if (bestItem) {
          items.push(bestItem);
        }
      }
    }

    return {
      items,
      outfitName: selectedTemplate.name,
      description: selectedTemplate.description,
    };
  }

  private async findBestItem(
    items: Array<
      ClothingItem & {
        brand: { id: string; name: string; logo: string | null } | null;
      }
    >,
    profile: UserProfile | null,
  ): Promise<ScoredItem | null> {
    // 如果数组为空，返回 null
    if (items.length === 0) {
      return null;
    }

    // 使用非空断言，因为已经检查了数组长度
    let bestItem: (typeof items)[number] = items[0]!;
    let bestScore = 0;

    for (const item of items) {
      const scores = await this.calculateAllScores(
        profile,
        item,
        { favorites: [], tryOns: [], views: [] },
        {},
      );
      const score = this.combineScores(scores);

      if (score > bestScore) {
        bestScore = score;
        bestItem = item;
      }
    }

    return {
      id: bestItem.id,
      name: bestItem.name,
      images: bestItem.images || [],
      price: toNumber(bestItem.price),
      currency: bestItem.currency,
      brand: bestItem.brand
        ? {
            id: bestItem.brand.id,
            name: bestItem.brand.name,
            logo: bestItem.brand.logo,
          }
        : null,
      category: bestItem.category,
      score: bestScore,
      matchReasons: ["今日推荐"],
    };
  }

  private async getUserBehaviors(userId: string) {
    const [favorites, tryOns, views] = await Promise.all([
      this.prisma.favorite.findMany({
        where: { userId },
        include: { item: true },
        take: 50,
      }),
      this.prisma.virtualTryOn.findMany({
        where: { userId },
        include: { item: true },
        take: 50,
      }),
      this.prisma.searchHistory.findMany({
        where: { userId },
        take: 20,
      }),
    ]);

    return { favorites, tryOns, views };
  }

  private async getCandidateItems(limit: number) {
    return this.prisma.clothingItem.findMany({
      where: { isActive: true },
      include: {
        brand: { select: { id: true, name: true, logo: true } },
      },
      take: limit,
    });
  }

  private generateMatchReasons(
    profile: UserProfile | null,
    item: ClothingItem,
    scores: {
      contentBased: number;
      collaborative: number;
      knowledgeGraph: number;
      theoryBased: number;
    },
    context: RecommendationContext,
  ): string[] {
    const reasons: string[] = [];
    const attrs = item.attributes as ItemAttributes | null;

    if (profile?.bodyType && attrs?.bodyTypeFit?.includes(profile.bodyType)) {
      reasons.push(`适合${this.getBodyTypeName(profile.bodyType)}体型`);
    }

    if (
      profile?.colorSeason &&
      attrs?.colorSeasons?.includes(profile.colorSeason)
    ) {
      reasons.push(`符合${this.getColorSeasonName(profile.colorSeason)}型色彩`);
    }

    if (profile?.skinTone && item.colors?.length > 0) {
      const flatteringColors = this.matchingTheory.getFlatteringColors(
        profile.skinTone,
      );
      const matchedColor = item.colors.find((c: string) =>
        flatteringColors.some((fc) =>
          c.toLowerCase().includes(fc.toLowerCase()),
        ),
      );
      if (matchedColor) {
        reasons.push(`${matchedColor}色适合您的肤色`);
      }
    }

    if (context.occasion && attrs?.occasions?.includes(context.occasion)) {
      reasons.push(`适合${this.getOccasionName(context.occasion)}场合`);
    }

    if (scores.knowledgeGraph > 0.6) {
      reasons.push("搭配热门组合");
    }

    if (reasons.length === 0) {
      reasons.push("为您推荐");
    }

    return reasons.slice(0, 3);
  }

  private optimizeDiversity(items: ScoredItem[], limit: number): ScoredItem[] {
    const result: ScoredItem[] = [];
    const categoryCount: Record<string, number> = {};
    const maxPerCategory = Math.ceil(limit / 4);

    for (const item of items) {
      const count = categoryCount[item.category] || 0;
      if (count < maxPerCategory) {
        result.push(item);
        categoryCount[item.category] = count + 1;
      }

      if (result.length >= limit) {break;}
    }

    if (result.length < limit) {
      for (const item of items) {
        if (!result.some((r) => r.id === item.id)) {
          result.push(item);
          if (result.length >= limit) {break;}
        }
      }
    }

    return result;
  }

  private getBodyTypeName(bodyType: BodyType): string {
    const names: Record<BodyType, string> = {
      [BodyType.rectangle]: "H型",
      [BodyType.triangle]: "A型",
      [BodyType.inverted_triangle]: "Y型",
      [BodyType.hourglass]: "X型",
      [BodyType.oval]: "O型",
    };
    return names[bodyType] || bodyType;
  }

  private getColorSeasonName(season: ColorSeason): string {
    const names: Record<ColorSeason, string> = {
      [ColorSeason.spring_warm]: "春季暖型",
      [ColorSeason.spring_light]: "春季亮型",
      [ColorSeason.summer_cool]: "夏季冷型",
      [ColorSeason.summer_light]: "夏季亮型",
      [ColorSeason.autumn_warm]: "秋季暖型",
      [ColorSeason.autumn_deep]: "秋季深型",
      [ColorSeason.winter_cool]: "冬季冷型",
      [ColorSeason.winter_deep]: "冬季深型",
    };
    return names[season] || season;
  }

  private getOccasionName(occasion: string): string {
    const names: Record<string, string> = {
      daily: "日常",
      work: "工作",
      date: "约会",
      party: "派对",
      sport: "运动",
      travel: "旅行",
    };
    return names[occasion] || occasion;
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { resolveServiceUrl } from "../../../common/config/runtime-flags";

import { ciede2000, rgbToLab, type LabColor } from "./ciede2000";


export interface ClothingNode {
  id: string;
  features: number[];
  category: string;
  attributes: Record<string, string[]>;
}

export interface CompatibilityEdge {
  sourceId: string;
  targetId: string;
  weight: number;
  type: "compatible" | "frequently_bought_together" | "style_match";
}

export interface Hyperedge {
  id: string;
  nodeIds: string[];
  weight: number;
  outfitType: string;
}

export interface CompatibilityResult {
  score: number;
  reasons: string[];
  breakdown: {
    gnnScore: number;
    hypergraphScore: number;
    crossAttentionScore: number;
  };
}

@Injectable()
export class GNNCompatibilityService {
  private readonly logger = new Logger(GNNCompatibilityService.name);

  private aiClient: AxiosInstance;
  private serviceAvailable = false;

  private nodeFeatures: Map<string, number[]> = new Map();
  private nodeMetadata: Map<
    string,
    { category: string; attributes: Record<string, string[]> }
  > = new Map();
  private adjacencyList: Map<string, Set<string>> = new Map();
  private edgeWeights: Map<string, number> = new Map();
  private hyperedges: Hyperedge[] = [];
  private hypergraphIncidence: Map<string, Set<string>> = new Map();

  private readonly categoryCompatibility: Record<string, string[]> = {
    tops: ["bottoms", "outerwear", "footwear", "accessories"],
    bottoms: ["tops", "outerwear", "footwear", "accessories"],
    dresses: ["footwear", "accessories", "outerwear"],
    outerwear: ["tops", "bottoms", "footwear"],
    footwear: ["tops", "bottoms", "dresses"],
    accessories: ["tops", "bottoms", "dresses", "footwear"],
  };

  private readonly styleCompatibility: Record<string, Record<string, number>> =
    {
      casual: { casual: 1.0, sporty: 0.8, streetwear: 0.9, minimalist: 0.7 },
      formal: { formal: 1.0, classic: 0.9, minimalist: 0.8 },
      sporty: { sporty: 1.0, casual: 0.8, streetwear: 0.7 },
      streetwear: { streetwear: 1.0, casual: 0.9, sporty: 0.7 },
      bohemian: { bohemian: 1.0, vintage: 0.8, casual: 0.6 },
      vintage: { vintage: 1.0, bohemian: 0.8, classic: 0.7 },
      minimalist: { minimalist: 1.0, classic: 0.9, formal: 0.8 },
      classic: { classic: 1.0, formal: 0.9, minimalist: 0.8 },
    };

  // Type-aware embedding projection matrices per category
  // Initialized as identity, learnable via feedback
  private readonly categoryProjections: Map<string, number[][]> = new Map();

  // Cross-category weight configurations
  // Different category pairs get different scoring weights
  private readonly crossCategoryWeights: Record<string, {
    embedding: number; category: number; style: number; color: number;
  }> = {
    "tops-bottoms": { embedding: 0.35, category: 0.15, style: 0.25, color: 0.25 },
    "tops-footwear": { embedding: 0.40, category: 0.15, style: 0.30, color: 0.15 },
    "tops-outerwear": { embedding: 0.35, category: 0.15, style: 0.30, color: 0.20 },
    "bottoms-footwear": { embedding: 0.35, category: 0.15, style: 0.30, color: 0.20 },
    "dresses-footwear": { embedding: 0.35, category: 0.15, style: 0.30, color: 0.20 },
    "dresses-accessories": { embedding: 0.40, category: 0.10, style: 0.25, color: 0.25 },
    "accessories-tops": { embedding: 0.40, category: 0.10, style: 0.30, color: 0.20 },
    "accessories-bottoms": { embedding: 0.40, category: 0.10, style: 0.30, color: 0.20 },
  };

  // Color name to RGB mapping for CIEDE2000 computation
  private readonly colorNameToRgb: Record<string, [number, number, number]> = {
    black: [0, 0, 0], white: [255, 255, 255], gray: [128, 128, 128],
    grey: [128, 128, 128], beige: [245, 245, 220], navy: [0, 0, 128],
    red: [255, 0, 0], blue: [0, 0, 255], green: [0, 128, 0],
    yellow: [255, 255, 0], orange: [255, 165, 0], pink: [255, 192, 203],
    purple: [128, 0, 128], brown: [139, 69, 19], tan: [210, 180, 140],
    cream: [255, 253, 208], ivory: [255, 255, 240], camel: [193, 154, 107],
    burgundy: [128, 0, 32], coral: [255, 127, 80], teal: [0, 128, 128],
    olive: [128, 128, 0], maroon: [128, 0, 0], charcoal: [54, 69, 79],
    khaki: [195, 176, 145], rust: [183, 65, 14], lavender: [150, 123, 182],
    mint: [152, 255, 152], sage: [188, 184, 138], blush: [222, 93, 131],
    copper: [184, 115, 51], gold: [255, 215, 0], silver: [192, 192, 192],
  };

  // Neutral colors: low chroma in CIELAB, always compatible
  private readonly neutralColorNames = new Set([
    "black", "white", "gray", "grey", "beige", "navy", "cream",
    "ivory", "camel", "charcoal", "khaki", "silver",
  ]);

  constructor(private configService: ConfigService) {
    const aiServiceUrl = resolveServiceUrl(this.configService, "AI_SERVICE_URL", "http://localhost:8001");

    this.aiClient = axios.create({
      baseURL: aiServiceUrl,
      timeout: 60000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkServiceHealth();
    this.logger.log("GNN Compatibility Service initialized");
  }

  private async checkServiceHealth(): Promise<void> {
    try {
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      if (response.data?.status === "healthy") {
        this.serviceAvailable = true;
        this.logger.log("Python AI Service connected for GNN embeddings");
      }
    } catch (_error) {
      this.logger.warn(
        "Python AI Service not available, using local computation",
      );
      this.serviceAvailable = false;
    }
  }

  addNode(node: ClothingNode): Promise<void> {
    this.nodeFeatures.set(node.id, node.features);
    this.nodeMetadata.set(node.id, {
      category: node.category,
      attributes: node.attributes,
    });

    if (!this.adjacencyList.has(node.id)) {
      this.adjacencyList.set(node.id, new Set());
    }

    this.logger.debug(`Added node ${node.id} to graph`);
  }

  addEdge(edge: CompatibilityEdge): Promise<void> {
    const { sourceId, targetId, weight } = edge;

    if (!this.adjacencyList.has(sourceId)) {
      this.adjacencyList.set(sourceId, new Set());
    }
    if (!this.adjacencyList.has(targetId)) {
      this.adjacencyList.set(targetId, new Set());
    }

    this.adjacencyList.get(sourceId)!.add(targetId);
    this.adjacencyList.get(targetId)!.add(sourceId);

    const edgeKey = this.getEdgeKey(sourceId, targetId);
    this.edgeWeights.set(edgeKey, weight);

    this.logger.debug(
      `Added edge ${sourceId} <-> ${targetId} with weight ${weight}`,
    );
  }

  addHyperedge(hyperedge: Hyperedge): Promise<void> {
    this.hyperedges.push(hyperedge);

    for (const nodeId of hyperedge.nodeIds) {
      if (!this.hypergraphIncidence.has(nodeId)) {
        this.hypergraphIncidence.set(nodeId, new Set());
      }
      this.hypergraphIncidence.get(nodeId)!.add(hyperedge.id);
    }

    this.logger.debug(
      `Added hyperedge ${hyperedge.id} with ${hyperedge.nodeIds.length} nodes`,
    );
  }

  computeCompatibility(
    sourceId: string,
    targetId: string,
  ): Promise<CompatibilityResult> {
    this.logger.log(
      `Computing compatibility between ${sourceId} and ${targetId}`,
    );

    const sourceFeatures = this.nodeFeatures.get(sourceId);
    const targetFeatures = this.nodeFeatures.get(targetId);
    const sourceMeta = this.nodeMetadata.get(sourceId);
    const targetMeta = this.nodeMetadata.get(targetId);

    if (!sourceFeatures || !targetFeatures) {
      return this.getDefaultResult();
    }

    const embeddingSimilarity = this.cosineSimilarity(
      sourceFeatures,
      targetFeatures,
    );

    const categoryScore = this.computeCategoryCompatibility(
      sourceMeta?.category || "",
      targetMeta?.category || "",
    );

    const styleScore = this.computeStyleCompatibility(
      sourceMeta?.attributes?.styles || [],
      targetMeta?.attributes?.styles || [],
    );

    const colorScore = this.computeColorCompatibility(
      sourceMeta?.attributes?.colors || [],
      targetMeta?.attributes?.colors || [],
    );

    const gnnScore = this.computeGNNScore(
      sourceId,
      targetId,
      embeddingSimilarity,
    );
    const hypergraphScore = this.computeHypergraphScore(sourceId, targetId);
    const crossAttentionScore = this.computeCrossAttentionScore(
      embeddingSimilarity,
      categoryScore,
      styleScore,
      colorScore,
      sourceMeta?.category,
      targetMeta?.category,
    );

    const fusedScore = this.fuseScores(
      gnnScore,
      hypergraphScore,
      crossAttentionScore,
    );

    const reasons = this.generateReasons(
      categoryScore,
      styleScore,
      colorScore,
      embeddingSimilarity,
      sourceMeta?.attributes?.styles || [],
      targetMeta?.attributes?.styles || [],
    );

    return {
      score: fusedScore,
      reasons,
      breakdown: {
        gnnScore,
        hypergraphScore,
        crossAttentionScore,
      },
    };
  }

  private cosineSimilarity(a: number[], b: number[]): number {
    if (a.length !== b.length) {return 0;}

    let dotProduct = 0;
    let normA = 0;
    let normB = 0;

    for (let i = 0; i < a.length; i++) {
      const valueA = a[i] ?? 0;
      const valueB = b[i] ?? 0;
      dotProduct += valueA * valueB;
      normA += valueA * valueA;
      normB += valueB * valueB;
    }

    if (normA === 0 || normB === 0) {return 0;}

    return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
  }

  private computeCategoryCompatibility(cat1: string, cat2: string): number {
    if (!cat1 || !cat2) {return 0.5;}

    if (cat1 === cat2) {return 0.3;}

    const compatibleCategories = this.categoryCompatibility[cat1] || [];
    if (compatibleCategories.includes(cat2)) {return 0.9;}

    return 0.4;
  }

  private computeStyleCompatibility(
    styles1: string[],
    styles2: string[],
  ): number {
    if (!styles1.length || !styles2.length) {return 0.5;}

    let maxScore = 0;
    for (const s1 of styles1) {
      const styleMap = this.styleCompatibility[s1];
      if (styleMap) {
        for (const s2 of styles2) {
          const score = styleMap[s2] || 0.5;
          maxScore = Math.max(maxScore, score);
        }
      }
    }

    return maxScore;
  }

  /**
   * Compute color compatibility using CIEDE2000 perceptual color distance.
   * Replaces string-matching with scientific color difference measurement.
   * Neutral colors (low chroma) are treated as always-compatible.
   */
  private computeColorCompatibility(
    colors1: string[],
    colors2: string[],
  ): number {
    if (!colors1.length || !colors2.length) {return 0.5;}

    // Convert color names to CIELAB using the lookup table
    const lab1 = colors1
      .map((c) => this.colorNameToRgb[c.toLowerCase()])
      .filter((rgb): rgb is [number, number, number] => rgb !== undefined)
      .map((rgb) => rgbToLab({ r: rgb[0], g: rgb[1], b: rgb[2] }));

    const lab2 = colors2
      .map((c) => this.colorNameToRgb[c.toLowerCase()])
      .filter((rgb): rgb is [number, number, number] => rgb !== undefined)
      .map((rgb) => rgbToLab({ r: rgb[0], g: rgb[1], b: rgb[2] }));

    // Check for neutral colors (low chroma, always compatible)
    const hasNeutral1 = colors1.some((c) => this.neutralColorNames.has(c.toLowerCase()));
    const hasNeutral2 = colors2.some((c) => this.neutralColorNames.has(c.toLowerCase()));

    if (hasNeutral1 || hasNeutral2) {
      // Both neutral = always compatible
      if (hasNeutral1 && hasNeutral2) {
        return 0.85;
      }

      // One side is neutral: compute CIEDE2000 between non-neutral colors only
      // with wider tolerance (neutral softens any clash)
      const nonNeutralLab1 = colors1
        .filter((c) => !this.neutralColorNames.has(c.toLowerCase()))
        .map((c) => this.colorNameToRgb[c.toLowerCase()])
        .filter((rgb): rgb is [number, number, number] => rgb !== undefined)
        .map((rgb) => rgbToLab({ r: rgb[0], g: rgb[1], b: rgb[2] }));

      const nonNeutralLab2 = colors2
        .filter((c) => !this.neutralColorNames.has(c.toLowerCase()))
        .map((c) => this.colorNameToRgb[c.toLowerCase()])
        .filter((rgb): rgb is [number, number, number] => rgb !== undefined)
        .map((rgb) => rgbToLab({ r: rgb[0], g: rgb[1], b: rgb[2] }));

      if (nonNeutralLab1.length === 0 || nonNeutralLab2.length === 0) {
        return 0.85; // One side is all neutral
      }

      // Check CIEDE2000 between non-neutral colors
      const minDelta = this.minCiede2000(nonNeutralLab1, nonNeutralLab2);
      // Neutral softens the requirement: wider tolerance
      return Math.max(0, Math.min(1, 1 - minDelta / 80));
    }

    // No neutral colors: compute CIEDE2000 distance
    if (lab1.length === 0 || lab2.length === 0) {
      // Fallback to name matching for unknown colors
      return this.fallbackColorMatch(colors1, colors2);
    }

    const minDelta = this.minCiede2000(lab1, lab2);

    // CIEDE2000 scoring:
    // deltaE < 10 = very similar (harmonious) → score ~0.9
    // deltaE 10-25 = complementary → score 0.6-0.8
    // deltaE 25-50 = some contrast → score 0.3-0.6
    // deltaE > 50 = clashing → score < 0.3
    const score = Math.max(0, 1 - minDelta / 50);
    return Math.min(1, score);
  }

  /**
   * Compute minimum CIEDE2000 distance between two sets of CIELAB colors.
   */
  private minCiede2000(
    lab1: Array<{ L: number; a: number; b: number }>,
    lab2: Array<{ L: number; a: number; b: number }>,
  ): number {
    let minDist = Infinity;
    for (const c1 of lab1) {
      for (const c2 of lab2) {
        const delta = ciede2000(c1 as LabColor, c2 as LabColor);
        if (delta < minDist) {
          minDist = delta;
        }
      }
    }
    return minDist;
  }

  /**
   * Fallback color matching using string comparison for unknown color names.
   */
  private fallbackColorMatch(colors1: string[], colors2: string[]): number {
    for (const c1 of colors1) {
      for (const c2 of colors2) {
        if (c1.toLowerCase() === c2.toLowerCase()) {return 0.7;}
      }
    }
    return 0.5;
  }

  private computeGNNScore(
    sourceId: string,
    targetId: string,
    embeddingSimilarity: number,
  ): number {
    const neighbors = this.getNeighbors(sourceId);
    const targetNeighbors = this.getNeighbors(targetId);

    const commonNeighbors = neighbors.filter((n) =>
      targetNeighbors.includes(n),
    );

    let neighborBonus = 0;
    if (commonNeighbors.length > 0) {
      neighborBonus = Math.min(0.2, commonNeighbors.length * 0.05);
    }

    const edgeKey = this.getEdgeKey(sourceId, targetId);
    const edgeWeight = this.edgeWeights.get(edgeKey) || 0;
    const edgeBonus = edgeWeight > 0 ? 0.15 : 0;

    return Math.min(
      1,
      (embeddingSimilarity + 1) / 2 + neighborBonus + edgeBonus,
    );
  }

  private computeHypergraphScore(sourceId: string, targetId: string): number {
    const sourceHyperedges =
      this.hypergraphIncidence.get(sourceId) || new Set();
    const targetHyperedges =
      this.hypergraphIncidence.get(targetId) || new Set();

    const commonHyperedges = [...sourceHyperedges].filter((h) =>
      targetHyperedges.has(h),
    );

    if (commonHyperedges.length === 0) {return 0.5;}

    let totalWeight = 0;
    for (const heId of commonHyperedges) {
      const hyperedge = this.hyperedges.find((h) => h.id === heId);
      if (hyperedge) {
        totalWeight += hyperedge.weight;
      }
    }

    return Math.min(1, 0.5 + totalWeight * 0.1 + commonHyperedges.length * 0.1);
  }

  /**
   * Compute cross-attention score with category-pair-specific weights.
   * Different category pairs (e.g., top-bottom vs top-footwear) get different
   * weight combinations reflecting their compatibility characteristics.
   */
  private computeCrossAttentionScore(
    embeddingSimilarity: number,
    categoryScore: number,
    styleScore: number,
    colorScore: number,
    sourceCategory?: string,
    targetCategory?: string,
  ): number {
    // Look up category-pair-specific weights
    const pairKey = this.getCategoryPairKey(sourceCategory, targetCategory);
    const weights = pairKey
      ? (this.crossCategoryWeights[pairKey] ?? {
          embedding: 0.4, category: 0.25, style: 0.2, color: 0.15,
        })
      : { embedding: 0.4, category: 0.25, style: 0.2, color: 0.15 };

    return (
      weights.embedding * ((embeddingSimilarity + 1) / 2) +
      weights.category * categoryScore +
      weights.style * styleScore +
      weights.color * colorScore
    );
  }

  /**
   * Get canonical category pair key for weight lookup.
   */
  private getCategoryPairKey(cat1?: string, cat2?: string): string | null {
    if (!cat1 || !cat2) {return null;}
    const pair = [cat1, cat2].sort();
    const key = `${pair[0]}-${pair[1]}`;
    if (this.crossCategoryWeights[key]) {return key;}
    // Try reverse order
    const revKey = `${pair[1]}-${pair[0]}`;
    if (this.crossCategoryWeights[revKey]) {return revKey;}
    return null;
  }

  /**
   * Compute outfit-level compatibility score from all pairwise scores.
   * Uses min + weighted average aggregation with diversity bonus.
   */
  computeOutfitScore(pairwiseScores: number[]): {
    score: number;
    diversity: number;
  } {
    if (pairwiseScores.length === 0) {
      return { score: 0.5, diversity: 0 };
    }

    // Aggregate: min(pairwise) * 0.4 + avg(pairwise) * 0.6
    const minScore = Math.min(...pairwiseScores);
    const avgScore = pairwiseScores.reduce((a, b) => a + b, 0) / pairwiseScores.length;
    const aggregated = minScore * 0.4 + avgScore * 0.6;

    // Diversity bonus: penalize if all scores are very similar (boring outfit)
    const variance = pairwiseScores.reduce(
      (sum, s) => sum + (s - avgScore) ** 2, 0,
    ) / pairwiseScores.length;
    const diversity = Math.min(1, Math.sqrt(variance) * 5);

    return { score: aggregated, diversity };
  }

  private fuseScores(
    gnnScore: number,
    hypergraphScore: number,
    crossAttentionScore: number,
  ): number {
    const weights = {
      gnn: 0.35,
      hypergraph: 0.35,
      crossAttention: 0.3,
    };

    return (
      weights.gnn * gnnScore +
      weights.hypergraph * hypergraphScore +
      weights.crossAttention * crossAttentionScore
    );
  }

  private generateReasons(
    categoryScore: number,
    styleScore: number,
    colorScore: number,
    embeddingSimilarity: number,
    styles1: string[],
    styles2: string[],
  ): string[] {
    const reasons: string[] = [];

    if (categoryScore > 0.8) {
      reasons.push("类别互补，适合搭配");
    }

    if (styleScore > 0.8) {
      const commonStyles = styles1.filter((s) => styles2.includes(s));
      if (commonStyles.length > 0) {
        reasons.push(`风格匹配: ${commonStyles.join(", ")}`);
      } else {
        reasons.push("风格协调");
      }
    } else if (styleScore > 0.6) {
      reasons.push("风格基本协调");
    }

    if (colorScore > 0.7) {
      reasons.push("色彩搭配和谐");
    }

    if (embeddingSimilarity > 0.8) {
      reasons.push("视觉风格高度相似");
    } else if (embeddingSimilarity > 0.6) {
      reasons.push("视觉风格相近");
    }

    if (reasons.length === 0) {
      reasons.push("基础搭配推荐");
    }

    return reasons.slice(0, 3);
  }

  private getNeighbors(nodeId: string): string[] {
    return Array.from(this.adjacencyList.get(nodeId) || []);
  }

  private getEdgeKey(sourceId: string, targetId: string): string {
    return [sourceId, targetId].sort().join("-");
  }

  private getDefaultResult(): CompatibilityResult {
    return {
      score: 0.5,
      reasons: ["数据不足，无法精确计算"],
      breakdown: {
        gnnScore: 0.5,
        hypergraphScore: 0.5,
        crossAttentionScore: 0.5,
      },
    };
  }

  async batchComputeCompatibility(
    pairs: Array<{ sourceId: string; targetId: string }>,
  ): Promise<CompatibilityResult[]> {
    return Promise.all(
      pairs.map((pair) =>
        this.computeCompatibility(pair.sourceId, pair.targetId),
      ),
    );
  }

  async getRecommendations(
    itemId: string,
    options?: { limit?: number; category?: string },
  ): Promise<Array<{ itemId: string; score: number; reasons: string[] }>> {
    const limit = options?.limit || 10;
    const candidates: Array<{
      itemId: string;
      score: number;
      reasons: string[];
    }> = [];

    const sourceMeta = this.nodeMetadata.get(itemId);
    const targetCategories = sourceMeta
      ? this.categoryCompatibility[sourceMeta.category] || []
      : [];

    for (const [nodeId] of this.nodeFeatures) {
      if (nodeId !== itemId) {
        const nodeMeta = this.nodeMetadata.get(nodeId);

        if (options?.category && nodeMeta?.category !== options.category)
          {continue;}
        if (
          targetCategories.length > 0 &&
          !targetCategories.includes(nodeMeta?.category || "")
        ) {
          continue;
        }

        const result = await this.computeCompatibility(itemId, nodeId);
        candidates.push({
          itemId: nodeId,
          score: result.score,
          reasons: result.reasons,
        });
      }
    }

    candidates.sort((a, b) => b.score - a.score);

    return candidates.slice(0, limit);
  }

  async buildOutfitHyperedge(
    itemIds: string[],
    outfitType: string,
    weight: number,
  ): Promise<Hyperedge> {
    const hyperedge: Hyperedge = {
      id: `outfit_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      nodeIds: itemIds,
      weight,
      outfitType,
    };

    await this.addHyperedge(hyperedge);

    return hyperedge;
  }

  getGraphStats(): {
    numNodes: number;
    numEdges: number;
    numHyperedges: number;
  } {
    let numEdges = 0;
    for (const [, neighbors] of this.adjacencyList) {
      numEdges += neighbors.size;
    }
    numEdges = Math.floor(numEdges / 2);

    return {
      numNodes: this.nodeFeatures.size,
      numEdges,
      numHyperedges: this.hyperedges.length,
    };
  }

  isServiceAvailable(): boolean {
    return this.serviceAvailable;
  }
}

import { Injectable, Logger, Optional } from "@nestjs/common";

import { PrismaService } from "../../../common/prisma/prisma.service";

import { Neo4jService } from "./neo4j.service";

interface KnowledgeNode {
  id: string;
  type: "item" | "category" | "style" | "occasion" | "brand" | "user";
  properties: Record<string, unknown>;
}

interface KnowledgeEdge {
  source: string;
  target: string;
  relation: string;
  weight: number;
}

interface RecommendationPath {
  nodes: KnowledgeNode[];
  edges: KnowledgeEdge[];
  score: number;
}

@Injectable()
export class KnowledgeGraphService {
  private readonly logger = new Logger(KnowledgeGraphService.name);
  private graph: {
    nodes: Map<string, KnowledgeNode>;
    edges: KnowledgeEdge[];
  } = {
    nodes: new Map(),
    edges: [],
  };

  constructor(
    private prisma: PrismaService,
    @Optional() private neo4jService?: Neo4jService,
  ) {}

  private get useNeo4j(): boolean {
    return !!this.neo4jService?.isReady();
  }

  async buildGraph(): Promise<void> {
    this.logger.log("Building clothing knowledge graph...");

    if (this.useNeo4j) {
      await this.buildGraphFromNeo4j();
    } else {
      await this.buildInMemoryGraph();
    }

    this.logger.log(
      `Graph built: ${this.graph.nodes.size} nodes, ${this.graph.edges.length} edges (mode: ${this.useNeo4j ? "Neo4j" : "in-memory"})`,
    );
  }

  private async buildGraphFromNeo4j(): Promise<void> {
    try {
      const itemResults = await this.neo4jService!.runReadQuery<{
        id: string;
        name: string;
        category: string;
      }>(
        `MATCH (i:Item) RETURN i.id AS id, i.name AS name, i.category AS category LIMIT 2000`,
      );

      itemResults.forEach((item) => {
        const nodeId = `item_${item.id}`;
        this.graph.nodes.set(nodeId, {
          id: nodeId,
          type: "item",
          properties: { name: item.name, category: item.category },
        });
      });

      const relationResults = await this.neo4jService!.runReadQuery<{
        sourceId: string;
        targetId: string;
        relation: string;
        weight: number;
      }>(
        `MATCH (a)-[r]->(b) RETURN a.id AS sourceId, b.id AS targetId, type(r) AS relation, r.weight AS weight LIMIT 5000`,
      );

      relationResults.forEach((rel) => {
        this.graph.edges.push({
          source: `item_${rel.sourceId}`,
          target: `item_${rel.targetId}`,
          relation: rel.relation,
          weight: Number(rel.weight) || 0.5,
        });
      });
    } catch (error) {
      this.logger.warn(`Neo4j graph build failed, falling back to in-memory: ${error}`);
      await this.buildInMemoryGraph();
    }
  }

  private async buildInMemoryGraph(): Promise<void> {
    await this.buildCategoryNodes();
    await this.buildStyleNodes();
    await this.buildOccasionNodes();
    await this.buildItemNodes();
    await this.buildItemRelations();
  }

  private async buildCategoryNodes(): Promise<void> {
    const categories = [
      "tops", "bottoms", "dresses", "outerwear", "footwear",
      "accessories", "activewear", "swimwear", "intimates", "suits",
    ];
    categories.forEach((cat) => {
      const nodeId = `category_${cat}`;
      this.graph.nodes.set(nodeId, {
        id: nodeId,
        type: "category",
        properties: { name: cat },
      });
    });
  }

  private async buildStyleNodes(): Promise<void> {
    const styles = [
      "casual", "formal", "business", "sporty", "bohemian",
      "minimalist", "streetwear", "vintage", "romantic", "edgy",
      "classic", "trendy",
    ];
    styles.forEach((style) => {
      const nodeId = `style_${style}`;
      this.graph.nodes.set(nodeId, {
        id: nodeId,
        type: "style",
        properties: { name: style },
      });
    });
    this.addStyleCompatibilityRules();
  }

  private addStyleCompatibilityRules(): void {
    const compatiblePairs = [
      ["casual", "sporty"], ["casual", "streetwear"],
      ["formal", "business"], ["formal", "classic"],
      ["bohemian", "vintage"], ["minimalist", "classic"],
      ["romantic", "vintage"], ["edgy", "streetwear"],
    ];
    compatiblePairs.forEach(([style1, style2]) => {
      this.graph.edges.push({
        source: `style_${style1}`,
        target: `style_${style2}`,
        relation: "compatible_with",
        weight: 0.8,
      });
    });
  }

  private async buildOccasionNodes(): Promise<void> {
    const occasions = [
      "daily", "work", "date", "party", "sport", "travel",
      "wedding", "interview", "beach", "gym", "dinner", "meeting",
    ];
    occasions.forEach((occasion) => {
      const nodeId = `occasion_${occasion}`;
      this.graph.nodes.set(nodeId, {
        id: nodeId,
        type: "occasion",
        properties: { name: occasion },
      });
    });
    this.addOccasionStyleRules();
  }

  private addOccasionStyleRules(): void {
    const occasionStyleMap: Record<string, string[]> = {
      work: ["business", "formal", "classic"],
      party: ["trendy", "edgy", "formal"],
      date: ["romantic", "casual", "trendy"],
      sport: ["sporty", "casual"],
      daily: ["casual", "minimalist", "streetwear"],
      wedding: ["formal", "classic", "romantic"],
    };
    Object.entries(occasionStyleMap).forEach(([occasion, styles]) => {
      styles.forEach((style) => {
        this.graph.edges.push({
          source: `occasion_${occasion}`,
          target: `style_${style}`,
          relation: "suitable_style",
          weight: 0.7,
        });
      });
    });
  }

  private async buildItemNodes(): Promise<void> {
    const items = await this.prisma.clothingItem.findMany({
      where: { isActive: true },
      take: 1000,
    });

    items.forEach((item) => {
      const nodeId = `item_${item.id}`;
      this.graph.nodes.set(nodeId, {
        id: nodeId,
        type: "item",
        properties: {
          name: item.name,
          category: item.category,
          brandId: item.brandId,
          attributes: item.attributes,
          price: item.price,
        },
      });

      this.graph.edges.push({
        source: nodeId,
        target: `category_${item.category}`,
        relation: "belongs_to",
        weight: 1.0,
      });

      const attrs = item.attributes as Record<string, unknown> | null;
      if (attrs?.style) {
        (attrs.style as string[]).forEach((s: string) => {
          this.graph.edges.push({
            source: nodeId,
            target: `style_${s}`,
            relation: "has_style",
            weight: 0.8,
          });
        });
      }
      if (attrs?.occasions) {
        (attrs.occasions as string[]).forEach((o: string) => {
          this.graph.edges.push({
            source: nodeId,
            target: `occasion_${o}`,
            relation: "suitable_for",
            weight: 0.7,
          });
        });
      }
    });
  }

  private async buildItemRelations(): Promise<void> {
    const cooccurrence = await this.analyzeCooccurrence();
    cooccurrence.forEach((pair) => {
      this.graph.edges.push({
        source: `item_${pair.item1}`,
        target: `item_${pair.item2}`,
        relation: "frequently_bought_together",
        weight: pair.score,
      });
    });
  }

  private async analyzeCooccurrence(): Promise<
    Array<{ item1: string; item2: string; score: number }>
  > {
    const orderItems = await this.prisma.orderItem.findMany({
      include: { order: true },
      take: 5000,
    });

    const cooccurrence: Map<string, Map<string, number>> = new Map();
    const ordersMap = new Map<string, string[]>();
    orderItems.forEach((oi) => {
      if (!ordersMap.has(oi.orderId)) {
        ordersMap.set(oi.orderId, []);
      }
      ordersMap.get(oi.orderId)!.push(oi.itemId);
    });

    ordersMap.forEach((items) => {
      for (let i = 0; i < items.length; i++) {
        for (let j = i + 1; j < items.length; j++) {
          const firstItem = items[i];
          const secondItem = items[j];
          if (!firstItem || !secondItem) {continue;}
          const key1 = firstItem < secondItem ? firstItem : secondItem;
          const key2 = firstItem < secondItem ? secondItem : firstItem;
          if (!cooccurrence.has(key1)) {cooccurrence.set(key1, new Map());}
          const currentRow = cooccurrence.get(key1);
          if (!currentRow) {continue;}
          currentRow.set(key2, (currentRow.get(key2) ?? 0) + 1);
        }
      }
    });

    const results: Array<{ item1: string; item2: string; score: number }> = [];
    const maxCooccur = Math.max(
      ...Array.from(cooccurrence.values()).flatMap((m) => Array.from(m.values())),
      1,
    );

    cooccurrence.forEach((innerMap, item1) => {
      innerMap.forEach((count, item2) => {
        if (count >= 2) {results.push({ item1, item2, score: count / maxCooccur });}
      });
    });
    return results.slice(0, 500);
  }

  async syncItemsToNeo4j(): Promise<void> {
    if (!this.useNeo4j) {
      this.logger.warn("Neo4j not available, skipping sync");
      return;
    }

    const items = await this.prisma.clothingItem.findMany({
      where: { isActive: true },
      take: 5000,
    });

    for (const item of items) {
      const attrs = item.attributes as Record<string, unknown> | null;
      await this.neo4jService!.runWriteQuery(
        `MERGE (i:Item {id: $id})
         SET i.name = $name, i.category = $category, i.price = $price,
             i.brandId = $brandId, i.updatedAt = datetime()`,
        {
          id: item.id,
          name: item.name,
          category: item.category,
          price: item.price,
          brandId: item.brandId,
        },
      );

      if (attrs?.style) {
        for (const style of attrs.style as string[]) {
          await this.neo4jService!.runWriteQuery(
            `MERGE (s:Style {name: $style})
             MERGE (i:Item {id: $itemId})
             MERGE (i)-[:HAS_STYLE {weight: 0.8}]->(s)`,
            { style, itemId: item.id },
          );
        }
      }

      if (attrs?.occasions) {
        for (const occasion of attrs.occasions as string[]) {
          await this.neo4jService!.runWriteQuery(
            `MERGE (o:Occasion {name: $occasion})
             MERGE (i:Item {id: $itemId})
             MERGE (i)-[:SUITABLE_FOR {weight: 0.7}]->(o)`,
            { occasion, itemId: item.id },
          );
        }
      }

      await this.neo4jService!.runWriteQuery(
        `MERGE (c:Category {name: $category})
         MERGE (i:Item {id: $itemId})
         MERGE (i)-[:BELONGS_TO {weight: 1.0}]->(c)`,
        { category: item.category, itemId: item.id },
      );
    }

    this.logger.log(`Synced ${items.length} items to Neo4j`);
  }

  async getRecommendationsByStylePath(
    itemId: string,
    maxDepth: number = 3,
  ): Promise<Array<{ itemId: string; score: number; path: string[] }>> {
    if (this.useNeo4j) {
      try {
        const results = await this.neo4jService!.runReadQuery<{
          targetId: string;
          score: number;
          pathLabels: string[];
        }>(
          `MATCH path = (i:Item {id: $itemId})-[*1..${maxDepth}]-(target:Item)
           WHERE target.id <> $itemId
           WITH target, path,
                reduce(s = 0, r IN relationships(path) | s + COALESCE(r.weight, 0.5)) / length(path) AS avgWeight,
                [n IN nodes(path) | labels(n)[0]] AS pathLabels
           RETURN target.id AS targetId, avgWeight * pow(0.9, length(path) - 1) AS score, pathLabels
           ORDER BY score DESC LIMIT 20`,
          { itemId },
        );
        return results.map((r) => ({
          itemId: r.targetId,
          score: Number(r.score),
          path: r.pathLabels,
        }));
      } catch (error) {
        this.logger.warn(`Neo4j style path query failed: ${error}`);
      }
    }

    return this.getInMemoryStylePathRecommendations(itemId, maxDepth);
  }

  private getInMemoryStylePathRecommendations(
    itemId: string,
    _maxDepth: number,
  ): Array<{ itemId: string; score: number; path: string[] }> {
    const compatibleItems = this.findCompatibleItemsByStyle(itemId);
    return compatibleItems
      .filter((item) => item.item.id !== `item_${itemId}`)
      .map((item) => ({
        itemId: item.item.id.replace("item_", ""),
        score: item.score,
        path: ["Item", "Style", "Item"],
      }));
  }

  findPaths(
    startId: string,
    endId: string,
    maxDepth: number = 3,
  ): RecommendationPath[] {
    const paths: RecommendationPath[] = [];
    const visited = new Set<string>();
    this.dfs(startId, endId, [], [], visited, paths, maxDepth);
    return paths.sort((a, b) => b.score - a.score).slice(0, 10);
  }

  private dfs(
    current: string,
    target: string,
    nodePath: KnowledgeNode[],
    edgePath: KnowledgeEdge[],
    visited: Set<string>,
    results: RecommendationPath[],
    maxDepth: number,
  ): void {
    if (nodePath.length > maxDepth) {return;}
    const currentNode = this.graph.nodes.get(current);
    if (!currentNode) {return;}
    visited.add(current);
    nodePath.push(currentNode);

    if (current === target) {
      results.push({
        nodes: [...nodePath],
        edges: [...edgePath],
        score: this.calculatePathScore(edgePath),
      });
      nodePath.pop();
      visited.delete(current);
      return;
    }

    const outgoingEdges = this.graph.edges.filter((e) => e.source === current);
    for (const edge of outgoingEdges) {
      if (!visited.has(edge.target)) {
        edgePath.push(edge);
        this.dfs(edge.target, target, nodePath, edgePath, visited, results, maxDepth);
        edgePath.pop();
      }
    }
    nodePath.pop();
    visited.delete(current);
  }

  private calculatePathScore(edges: KnowledgeEdge[]): number {
    if (edges.length === 0) {return 0;}
    const avgWeight = edges.reduce((sum, e) => sum + e.weight, 0) / edges.length;
    return avgWeight * Math.pow(0.9, edges.length - 1);
  }

  findRelatedItems(itemId: string, relationTypes?: string[]): KnowledgeNode[] {
    const nodePrefix = `item_${itemId}`;
    const related: KnowledgeNode[] = [];
    this.graph.edges
      .filter(
        (e) =>
          (e.source === nodePrefix || e.target === nodePrefix) &&
          (!relationTypes || relationTypes.includes(e.relation)),
      )
      .forEach((edge) => {
        const relatedId = edge.source === nodePrefix ? edge.target : edge.source;
        const node = this.graph.nodes.get(relatedId);
        if (node?.type === "item") {related.push(node);}
      });
    return related;
  }

  findCompatibleItemsByStyle(
    itemId: string,
  ): Array<{ item: KnowledgeNode; score: number }> {
    const nodePrefix = `item_${itemId}`;
    const itemNode = this.graph.nodes.get(nodePrefix);
    if (!itemNode) {return [];}

    const itemStyles = this.graph.edges
      .filter((e) => e.source === nodePrefix && e.relation === "has_style")
      .map((e) => e.target);

    const compatibleItems: Map<string, number> = new Map();
    itemStyles.forEach((styleId) => {
      const compatibleStyles = this.graph.edges
        .filter(
          (e) =>
            (e.source === styleId || e.target === styleId) &&
            e.relation === "compatible_with",
        )
        .map((e) => (e.source === styleId ? e.target : e.source));

      compatibleStyles.forEach((compStyle) => {
        this.graph.edges
          .filter((e) => e.target === compStyle && e.relation === "has_style")
          .forEach((e) => {
            compatibleItems.set(e.source, (compatibleItems.get(e.source) || 0) + 0.2);
          });
      });
    });

    const results: Array<{ item: KnowledgeNode; score: number }> = [];
    compatibleItems.forEach((score, id) => {
      const node = this.graph.nodes.get(id);
      if (node && id !== nodePrefix) {results.push({ item: node, score: Math.min(score, 1) });}
    });
    return results.sort((a, b) => b.score - a.score).slice(0, 20);
  }

  getItemsForOccasion(occasion: string): KnowledgeNode[] {
    const occasionNode = `occasion_${occasion}`;
    const items: KnowledgeNode[] = [];
    this.graph.edges
      .filter((e) => e.target === occasionNode && e.relation === "suitable_for")
      .forEach((e) => {
        const node = this.graph.nodes.get(e.source);
        if (node?.type === "item") {items.push(node);}
      });
    return items;
  }

  getGraphStats(): {
    nodeCount: number;
    edgeCount: number;
    typeDistribution: Record<string, number>;
  } {
    const typeDistribution: Record<string, number> = {};
    this.graph.nodes.forEach((node) => {
      typeDistribution[node.type] = (typeDistribution[node.type] || 0) + 1;
    });
    return {
      nodeCount: this.graph.nodes.size,
      edgeCount: this.graph.edges.length,
      typeDistribution,
    };
  }
}

import { Injectable, Logger } from "@nestjs/common";

import { PrismaService } from "../../../common/prisma/prisma.service";

export interface LTRFeature {
  name: string;
  weight: number;
  minValue: number;
  maxValue: number;
  normalize: boolean;
}

export interface LTRConfig {
  features: LTRFeature[];
  learningRate: number;
  regularization: number;
  maxIterations: number;
}

export interface RankingFeatures {
  itemId: string;
  contentScore: number;
  collaborativeScore: number;
  popularityScore: number;
  freshnessScore: number;
  diversityScore: number;
  personalizationScore: number;
  contextScore: number;
}

export interface RankingResult {
  itemId: string;
  score: number;
  features: RankingFeatures;
  explanation: string[];
}

export interface UserFeedback {
  userId: string;
  itemId: string;
  action: "click" | "like" | "purchase" | "skip" | "dislike";
  timestamp: Date;
}

interface FeatureWeights {
  contentScore: number;
  collaborativeScore: number;
  popularityScore: number;
  freshnessScore: number;
  diversityScore: number;
  personalizationScore: number;
  contextScore: number;
}

@Injectable()
export class LearningToRankService {
  private readonly logger = new Logger(LearningToRankService.name);

  private weights: FeatureWeights = {
    contentScore: 0.25,
    collaborativeScore: 0.2,
    popularityScore: 0.15,
    freshnessScore: 0.1,
    diversityScore: 0.1,
    personalizationScore: 0.15,
    contextScore: 0.05,
  };

  private readonly LEARNING_RATE = 0.01;
  private readonly MIN_SAMPLES = 100;

  private defaultConfig: LTRConfig = {
    features: [
      { name: "ruleScore", weight: 0.2, minValue: 0, maxValue: 100, normalize: true },
      { name: "colorScore", weight: 0.15, minValue: 0, maxValue: 100, normalize: true },
      { name: "cfScore", weight: 0.2, minValue: 0, maxValue: 1, normalize: true },
      { name: "kgScore", weight: 0.15, minValue: 0, maxValue: 1, normalize: true },
      { name: "sasrecScore", weight: 0.15, minValue: 0, maxValue: 1, normalize: true },
      { name: "vectorScore", weight: 0.1, minValue: 0, maxValue: 1, normalize: true },
      { name: "popularityScore", weight: 0.05, minValue: 0, maxValue: 1, normalize: true },
    ],
    learningRate: 0.01,
    regularization: 0.001,
    maxIterations: 100,
  };

  constructor(private prisma: PrismaService) {
    this.loadWeights();
  }

  rankItems(
    userId: string,
    items: RankingFeatures[],
    _context: { occasion?: string; season?: string; timeOfDay?: string } = {},
  ): Promise<RankingResult[]> {
    const results: RankingResult[] = [];

    const seenCategories = new Set<string>();
    const seenBrands = new Set<string>();

    for (const item of items) {
      const score = this.calculateFinalScore(item, seenCategories, seenBrands);
      const explanation = this.generateExplanation(item, score);

      results.push({
        itemId: item.itemId,
        score,
        features: item,
        explanation,
      });
    }

    return results.sort((a, b) => b.score - a.score);
  }

  private calculateFinalScore(
    features: RankingFeatures,
    _seenCategories: Set<string>,
    _seenBrands: Set<string>,
  ): number {
    let score = 0;

    score += features.contentScore * this.weights.contentScore;
    score += features.collaborativeScore * this.weights.collaborativeScore;
    score += features.popularityScore * this.weights.popularityScore;
    score += features.freshnessScore * this.weights.freshnessScore;
    score += features.diversityScore * this.weights.diversityScore;
    score += features.personalizationScore * this.weights.personalizationScore;
    score += features.contextScore * this.weights.contextScore;

    return Math.max(0, Math.min(100, score));
  }

  private generateExplanation(
    features: RankingFeatures,
    _score: number,
  ): string[] {
    const explanations: string[] = [];

    if (features.contentScore > 0.7) {
      explanations.push("与您的风格偏好高度匹配");
    }

    if (features.collaborativeScore > 0.7) {
      explanations.push("相似用户也喜欢");
    }

    if (features.popularityScore > 0.8) {
      explanations.push("热门商品");
    }

    if (features.freshnessScore > 0.8) {
      explanations.push("新品上架");
    }

    if (features.personalizationScore > 0.7) {
      explanations.push("为您个性化推荐");
    }

    if (explanations.length === 0) {
      explanations.push("为您推荐");
    }

    return explanations;
  }

  async updateFromFeedback(feedback: UserFeedback): Promise<void> {
    const feedbackWeight = this.getFeedbackWeight(feedback.action);

    if (feedbackWeight === 0) {return;}

    await this.prisma.rankingFeedback.create({
      data: {
        userId: feedback.userId,
        itemId: feedback.itemId,
        action: feedback.action,
        weight: feedbackWeight,
      },
    });

    const totalSamples = await this.prisma.rankingFeedback.count();

    if (totalSamples >= this.MIN_SAMPLES && totalSamples % 50 === 0) {
      await this.retrainWeights();
    }
  }

  private getFeedbackWeight(action: string): number {
    const weights: Record<string, number> = {
      purchase: 1.0,
      like: 0.5,
      click: 0.2,
      skip: -0.1,
      dislike: -0.5,
    };

    return weights[action] || 0;
  }

  private async retrainWeights(): Promise<void> {
    this.logger.log("Starting weight retraining...");

    const feedbacks = await this.prisma.rankingFeedback.findMany({
      take: 1000,
      orderBy: { createdAt: "desc" },
    });

    if (feedbacks.length < this.MIN_SAMPLES) {return;}

    const gradientAccumulator: FeatureWeights = {
      contentScore: 0,
      collaborativeScore: 0,
      popularityScore: 0,
      freshnessScore: 0,
      diversityScore: 0,
      personalizationScore: 0,
      contextScore: 0,
    };

    for (const feedback of feedbacks) {
      const features = await this.getItemFeatures(
        feedback.itemId,
        feedback.userId,
      );
      if (!features) {continue;}

      const predicted = this.calculateFinalScore(
        features,
        new Set(),
        new Set(),
      );
      const actual = Number(feedback.weight) > 0 ? 1 : 0;
      const error = actual - predicted / 100;

      const featureKeys = Object.keys(
        gradientAccumulator,
      ) as (keyof FeatureWeights)[];
      for (const key of featureKeys) {
        gradientAccumulator[key] += error * features[key];
      }
    }

    const n = feedbacks.length;
    const featureKeys = Object.keys(this.weights) as (keyof FeatureWeights)[];

    for (const key of featureKeys) {
      const gradient = gradientAccumulator[key] / n;
      this.weights[key] += this.LEARNING_RATE * gradient;
      this.weights[key] = Math.max(0.05, Math.min(0.5, this.weights[key]));
    }

    this.normalizeWeights();
    await this.saveWeights();

    this.logger.log("Weight retraining completed");
  }

  private normalizeWeights(): void {
    const total = Object.values(this.weights).reduce((sum, w) => sum + w, 0);

    if (total === 0) {
      this.weights = {
        contentScore: 0.25,
        collaborativeScore: 0.2,
        popularityScore: 0.15,
        freshnessScore: 0.1,
        diversityScore: 0.1,
        personalizationScore: 0.15,
        contextScore: 0.05,
      };
      return;
    }

    const featureKeys = Object.keys(this.weights) as (keyof FeatureWeights)[];
    for (const key of featureKeys) {
      this.weights[key] /= total;
    }
  }

  private async getItemFeatures(
    itemId: string,
    _userId: string,
  ): Promise<RankingFeatures | null> {
    const item = await this.prisma.clothingItem.findUnique({
      where: { id: itemId },
      select: {
        viewCount: true,
        likeCount: true,
        createdAt: true,
      },
    });

    if (!item) {return null;}

    const maxViews = 10000;
    const maxLikes = 1000;

    return {
      itemId,
      contentScore: 0.5,
      collaborativeScore: 0.5,
      popularityScore:
        Math.min(item.viewCount / maxViews, 1) * 0.5 +
        Math.min(item.likeCount / maxLikes, 1) * 0.5,
      freshnessScore: this.calculateFreshness(item.createdAt),
      diversityScore: 0.5,
      personalizationScore: 0.5,
      contextScore: 0.5,
    };
  }

  private calculateFreshness(createdAt: Date): number {
    const ageInDays =
      (Date.now() - createdAt.getTime()) / (1000 * 60 * 60 * 24);

    if (ageInDays < 7) {return 1.0;}
    if (ageInDays < 30) {return 0.8;}
    if (ageInDays < 90) {return 0.6;}
    if (ageInDays < 180) {return 0.4;}
    return 0.2;
  }

  private async loadWeights(): Promise<void> {
    try {
      const savedWeights = await this.prisma.systemConfig.findUnique({
        where: { key: "ranking_weights" },
      });

      if (savedWeights) {
        this.weights = JSON.parse(savedWeights.value as string);
      }
    } catch (_error) {
      this.logger.warn("Could not load weights, using defaults");
    }
  }

  private async saveWeights(): Promise<void> {
    try {
      await this.prisma.systemConfig.upsert({
        where: { key: "ranking_weights" },
        update: { value: JSON.stringify(this.weights) },
        create: {
          key: "ranking_weights",
          value: JSON.stringify(this.weights),
        },
      });
    } catch (_error) {
      this.logger.error("Failed to save weights");
    }
  }

  getWeights(): FeatureWeights {
    return { ...this.weights };
  }

  setWeights(newWeights: Partial<FeatureWeights>): void {
    this.weights = { ...this.weights, ...newWeights };
    this.normalizeWeights();
  }

  predict(
    features: Record<string, number>,
    config?: Partial<LTRConfig>,
  ): number {
    const cfg = { ...this.defaultConfig, ...config };
    let score = 0;
    for (const feature of cfg.features) {
      const value = features[feature.name] || 0;
      const normalized = feature.normalize
        ? (value - feature.minValue) /
          (feature.maxValue - feature.minValue || 1)
        : value;
      score += feature.weight * Math.max(0, Math.min(1, normalized));
    }
    return score;
  }

  trainModel(
    feedbackData: Array<{
      features: Record<string, number>;
      label: number;
    }>,
  ): Promise<void> {
    const cfg = this.defaultConfig;
    for (let iter = 0; iter < cfg.maxIterations; iter++) {
      let totalLoss = 0;
      for (const sample of feedbackData) {
        const prediction = this.predict(sample.features);
        const error = prediction - sample.label;
        totalLoss += error * error;
        for (const feature of cfg.features) {
          const value = sample.features[feature.name] || 0;
          const normalized = feature.normalize
            ? (value - feature.minValue) /
              (feature.maxValue - feature.minValue || 1)
            : value;
          feature.weight -=
            cfg.learningRate *
            (error * normalized + cfg.regularization * feature.weight);
          feature.weight = Math.max(0, feature.weight);
        }
      }
      if (totalLoss / feedbackData.length < 0.001) {break;}
    }
    const totalWeight = cfg.features.reduce((sum, f) => sum + f.weight, 0);
    if (totalWeight > 0) {
      cfg.features.forEach((f) => (f.weight /= totalWeight));
    }
  }

  getFeatureWeights(): Record<string, number> {
    return Object.fromEntries(
      this.defaultConfig.features.map((f) => [f.name, f.weight]),
    );
  }
}

import {
  Injectable,
  Logger,
  ServiceUnavailableException,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { allowUnverifiedAiFallbacks, resolveServiceUrl } from "../../../common/config/runtime-flags";
import { PrismaService } from "../../../common/prisma/prisma.service";

interface MultimodalFeatures {
  visual: number[];
  textual: number[];
  attributes: Record<string, unknown>;
}

interface FusionConfig {
  visualWeight: number;
  textualWeight: number;
  attributeWeight: number;
}

interface CompatibilityScore {
  score: number;
  reasons: string[];
  breakdown: {
    visual: number;
    textual: number;
    attribute: number;
  };
}

@Injectable()
export class MultimodalFusionService {
  private readonly logger = new Logger(MultimodalFusionService.name);
  private aiClient: AxiosInstance;
  private aiServiceAvailable = false;
  private readonly allowFallbacks: boolean;
  private readonly aiServiceUrl: string;

  private readonly defaultConfig: FusionConfig = {
    visualWeight: 0.4,
    textualWeight: 0.35,
    attributeWeight: 0.25,
  };

  constructor(
    private prisma: PrismaService,
    private configService: ConfigService,
  ) {
    this.allowFallbacks = allowUnverifiedAiFallbacks(this.configService);

    this.aiServiceUrl = resolveServiceUrl(this.configService, "AI_SERVICE_URL", "http://localhost:8001");

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 30000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkAiServiceHealth();
  }

  private async checkAiServiceHealth(): Promise<void> {
    try {
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      if (response.data?.status === "healthy") {
        this.aiServiceAvailable = true;
        this.logger.log("AI Service connected for feature extraction");
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `AI Service not available for multimodal embeddings (${this.aiServiceUrl}): ${errorMessage}`,
      );
      this.aiServiceAvailable = false;
    }
  }

  async extractVisualFeatures(imageUrl: string): Promise<number[]> {
    if (!this.aiServiceAvailable) {
      if (this.allowFallbacks) {
        return this.generateDeterministicEmbedding(512, imageUrl);
      }

      throw new ServiceUnavailableException(
        "AI visual embedding service is unavailable",
      );
    }

    try {
      const response = await this.aiClient.post("/api/embedding", {
        image_url: imageUrl,
      });
      if (
        response.data?.success &&
        Array.isArray(response.data.data?.embedding)
      ) {
        return response.data.data.embedding;
      }
    } catch (error: unknown) {
      this.logger.error(
        `AI visual embedding failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (this.allowFallbacks) {
        return this.generateDeterministicEmbedding(512, imageUrl);
      }
      throw new ServiceUnavailableException("AI visual embedding failed");
    }

    if (this.allowFallbacks) {
      return this.generateDeterministicEmbedding(512, imageUrl);
    }

    throw new ServiceUnavailableException(
      "AI visual embedding response did not include an embedding",
    );
  }

  async extractTextualFeatures(text: string): Promise<number[]> {
    if (!this.aiServiceAvailable) {
      if (this.allowFallbacks) {
        return this.generateDeterministicEmbedding(300, text);
      }

      throw new ServiceUnavailableException(
        "AI text embedding service is unavailable",
      );
    }

    try {
      const response = await this.aiClient.post("/api/embedding/text", {
        text: text,
      });
      if (
        response.data?.success &&
        Array.isArray(response.data.data?.embedding)
      ) {
        return response.data.data.embedding;
      }
    } catch (error: unknown) {
      this.logger.error(
        `AI text embedding failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (this.allowFallbacks) {
        return this.generateDeterministicEmbedding(300, text);
      }
      throw new ServiceUnavailableException("AI text embedding failed");
    }

    if (this.allowFallbacks) {
      return this.generateDeterministicEmbedding(300, text);
    }

    throw new ServiceUnavailableException(
      "AI text embedding response did not include an embedding",
    );
  }

  async extractItemFeatures(itemId: string): Promise<MultimodalFeatures> {
    const item = await this.prisma.clothingItem.findUnique({
      where: { id: itemId },
    });

    if (!item) {
      throw new Error(`Item ${itemId} not found`);
    }

    const visualFeatures = await this.extractVisualFeatures(
      item.images[0] ?? "",
    );

    const textContent = [
      item.name,
      item.description || "",
      ...((item.attributes as Record<string, unknown>)?.style as string[] || []),
    ].join(" ");
    const textualFeatures = await this.extractTextualFeatures(textContent);

    return {
      visual: visualFeatures,
      textual: textualFeatures,
      attributes: item.attributes as Record<string, unknown>,
    };
  }

  weightedFusion(
    features: MultimodalFeatures,
    config: FusionConfig = this.defaultConfig,
  ): number[] {
    const { visual, textual, attributes } = features;
    const { visualWeight, textualWeight, attributeWeight } = config;

    const visualNormalized = this.normalizeVector(visual);
    const textualNormalized = this.normalizeVector(textual);

    const attributeVector = this.attributesToVector(attributes);
    const attributeNormalized = this.normalizeVector(attributeVector);

    const maxLen = Math.max(
      visualNormalized.length,
      textualNormalized.length,
      attributeNormalized.length,
    );

    const fused = new Array(maxLen).fill(0);

    for (let i = 0; i < maxLen; i++) {
      const v = visualNormalized[i % visualNormalized.length] || 0;
      const t = textualNormalized[i % textualNormalized.length] || 0;
      const a = attributeNormalized[i % attributeNormalized.length] || 0;

      fused[i] = v * visualWeight + t * textualWeight + a * attributeWeight;
    }

    return this.normalizeVector(fused);
  }

  calculateCompatibility(
    item1Features: MultimodalFeatures,
    item2Features: MultimodalFeatures,
    config?: FusionConfig,
  ): Promise<CompatibilityScore> {
    const visualScore = this.cosineSimilarity(
      item1Features.visual,
      item2Features.visual,
    );

    const textualScore = this.cosineSimilarity(
      item1Features.textual,
      item2Features.textual,
    );

    const attributeScore = this.calculateAttributeCompatibility(
      item1Features.attributes,
      item2Features.attributes,
    );

    const { visualWeight, textualWeight, attributeWeight } =
      config || this.defaultConfig;

    const totalScore =
      visualScore * visualWeight +
      textualScore * textualWeight +
      attributeScore * attributeWeight;

    const reasons = this.generateCompatibilityReasons(
      { visual: visualScore, textual: textualScore, attribute: attributeScore },
      item1Features.attributes,
      item2Features.attributes,
    );

    return {
      score: Math.max(0, Math.min(1, totalScore)),
      reasons,
      breakdown: {
        visual: visualScore,
        textual: textualScore,
        attribute: attributeScore,
      },
    };
  }

  private cosineSimilarity(vec1: number[], vec2: number[]): number {
    const len = Math.min(vec1.length, vec2.length);

    let dotProduct = 0;
    let norm1 = 0;
    let norm2 = 0;

    for (let i = 0; i < len; i++) {
      const value1 = vec1[i] ?? 0;
      const value2 = vec2[i] ?? 0;
      dotProduct += value1 * value2;
      norm1 += value1 * value1;
      norm2 += value2 * value2;
    }

    if (norm1 === 0 || norm2 === 0) {return 0;}
    return dotProduct / (Math.sqrt(norm1) * Math.sqrt(norm2));
  }

  private normalizeVector(vec: number[]): number[] {
    const norm = Math.sqrt(vec.reduce((sum, v) => sum + v * v, 0));
    if (norm === 0) {return vec;}
    return vec.map((v) => v / norm);
  }

  private attributesToVector(attributes: Record<string, unknown>): number[] {
    const vector: number[] = [];

    if (attributes.style) {
      const styleEncoding = this.encodeCategory(attributes.style as string[]);
      vector.push(...styleEncoding);
    }

    if (attributes.occasions) {
      const occasionEncoding = this.encodeCategory(attributes.occasions as string[]);
      vector.push(...occasionEncoding);
    }

    if (attributes.season) {
      const seasonEncoding = this.encodeCategory(attributes.season as string[]);
      vector.push(...seasonEncoding);
    }

    if (attributes.patterns) {
      const patternEncoding = this.encodeCategory(attributes.patterns as string[]);
      vector.push(...patternEncoding);
    }

    while (vector.length < 128) {
      vector.push(0);
    }

    return vector.slice(0, 128);
  }

  private encodeCategory(items: string[]): number[] {
    const encoding = new Array(32).fill(0);
    if (!Array.isArray(items)) {return encoding;}

    items.forEach((item, index) => {
      if (index < 32) {
        const hash = this.simpleHash(item);
        encoding[index] = (hash % 1000) / 1000;
      }
    });

    return encoding;
  }

  private simpleHash(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const char = str.charCodeAt(i);
      hash = (hash << 5) - hash + char;
      hash = hash & hash;
    }
    return Math.abs(hash);
  }

  private calculateAttributeCompatibility(
    attrs1: Record<string, unknown>,
    attrs2: Record<string, unknown>,
  ): number {
    let score = 0.5;

    if (attrs1.style && attrs2.style) {
      const style1 = attrs1.style as string[];
      const style2 = attrs2.style as string[];
      const commonStyles = style1.filter((s: string) =>
        style2.includes(s),
      );
      score += commonStyles.length * 0.1;
    }

    if (attrs1.occasions && attrs2.occasions) {
      const occ1 = attrs1.occasions as string[];
      const occ2 = attrs2.occasions as string[];
      const commonOccasions = occ1.filter((o: string) =>
        occ2.includes(o),
      );
      score += commonOccasions.length * 0.05;
    }

    if (attrs1.season && attrs2.season) {
      const season1 = attrs1.season as string[];
      const season2 = attrs2.season as string[];
      const commonSeasons = season1.filter((s: string) =>
        season2.includes(s),
      );
      score += commonSeasons.length * 0.05;
    }

    return Math.min(score, 1);
  }

  private generateCompatibilityReasons(
    scores: { visual: number; textual: number; attribute: number },
    attrs1: Record<string, unknown>,
    attrs2: Record<string, unknown>,
  ): string[] {
    const reasons: string[] = [];

    if (scores.visual > 0.7) {
      reasons.push("视觉风格高度匹配");
    }

    if (scores.textual > 0.7) {
      reasons.push("描述语义相似");
    }

    if (attrs1.style && attrs2.style) {
      const style1 = attrs1.style as string[];
      const style2 = attrs2.style as string[];
      const commonStyles = style1.filter((s: string) =>
        style2.includes(s),
      );
      if (commonStyles.length > 0) {
        reasons.push(`共同风格: ${commonStyles.join(", ")}`);
      }
    }

    if (attrs1.occasions && attrs2.occasions) {
      const occ1 = attrs1.occasions as string[];
      const occ2 = attrs2.occasions as string[];
      const commonOccasions = occ1.filter((o: string) =>
        occ2.includes(o),
      );
      if (commonOccasions.length > 0) {
        reasons.push(`适合场合: ${commonOccasions.join(", ")}`);
      }
    }

    if (reasons.length === 0) {
      reasons.push("风格互补搭配");
    }

    return reasons.slice(0, 3);
  }

  private generateDeterministicEmbedding(dim: number, seed: string): number[] {
    const embedding: number[] = [];
    const hash = this.simpleHash(seed);
    let current = hash;

    for (let i = 0; i < dim; i++) {
      current = (current * 1103515245 + 12345) % 2147483648;
      embedding.push(((current % 2000) - 1000) / 1000);
    }

    return embedding;
  }

  async batchExtractFeatures(
    itemIds: string[],
  ): Promise<Map<string, MultimodalFeatures>> {
    const featuresMap = new Map<string, MultimodalFeatures>();

    await Promise.all(
      itemIds.map(async (id) => {
        const features = await this.extractItemFeatures(id);
        featuresMap.set(id, features);
      }),
    );

    return featuresMap;
  }

  async findCompatibleItems(
    queryItemId: string,
    candidateIds: string[],
    topK: number = 10,
  ): Promise<Array<{ itemId: string; score: CompatibilityScore }>> {
    const queryFeatures = await this.extractItemFeatures(queryItemId);
    const candidatesFeatures = await this.batchExtractFeatures(candidateIds);

    const results = await Promise.all(
      candidateIds.map(async (id) => {
        const features = candidatesFeatures.get(id);
        if (!features) {return null;}

        const score = await this.calculateCompatibility(
          queryFeatures,
          features,
        );
        return { itemId: id, score };
      }),
    );

    return results
      .filter(
        (r): r is { itemId: string; score: CompatibilityScore } => r !== null,
      )
      .sort((a, b) => b.score.score - a.score.score)
      .slice(0, topK);
  }
}

import {
  Injectable,
  Logger,
  OnModuleInit,
  OnModuleDestroy,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import neo4j, { Driver, Session, Result } from "neo4j-driver";

@Injectable()
export class Neo4jService implements OnModuleInit, OnModuleDestroy {
  private readonly logger = new Logger(Neo4jService.name);
  private driver: Driver | null = null;
  private isConnected = false;

  constructor(private configService: ConfigService) {}

  async onModuleInit() {
    const url = this.configService.get<string>("NEO4J_URL");
    const user = this.configService.get<string>("NEO4J_USER", "neo4j");
    const password = this.configService.get<string>("NEO4J_PASSWORD", "neo4j123");

    if (!url) {
      this.logger.warn("NEO4J_URL not configured, knowledge graph features disabled");
      return;
    }

    try {
      this.driver = neo4j.driver(url, neo4j.auth.basic(user, password), {
        maxConnectionLifetime: 3 * 60 * 60 * 1000,
        maxConnectionPoolSize: 50,
        connectionAcquisitionTimeout: 30000,
      });

      await this.driver.verifyConnectivity();
      this.isConnected = true;
      this.logger.log(`Neo4j connected: ${url}`);

      await this.ensureConstraints();
    } catch (error) {
      this.logger.warn(`Neo4j connection failed, using fallback: ${error}`);
      this.isConnected = false;
    }
  }

  async onModuleDestroy() {
    if (this.driver) {
      await this.driver.close();
      this.driver = null;
      this.isConnected = false;
    }
  }

  private async ensureConstraints(): Promise<void> {
    if (!this.driver) {return;}

    const session = this.driver.session();
    try {
      await session.run(
        `CREATE CONSTRAINT item_id IF NOT EXISTS FOR (i:Item) REQUIRE i.id IS UNIQUE`,
      );
      await session.run(
        `CREATE CONSTRAINT category_name IF NOT EXISTS FOR (c:Category) REQUIRE c.name IS UNIQUE`,
      );
      await session.run(
        `CREATE CONSTRAINT style_name IF NOT EXISTS FOR (s:Style) REQUIRE s.name IS UNIQUE`,
      );
      await session.run(
        `CREATE CONSTRAINT user_id IF NOT EXISTS FOR (u:User) REQUIRE u.id IS UNIQUE`,
      );
      this.logger.log("Neo4j constraints ensured");
    } catch (error) {
      this.logger.warn(`Constraint creation warning: ${error}`);
    } finally {
      await session.close();
    }
  }

  isReady(): boolean {
    return this.isConnected && this.driver !== null;
  }

  async runQuery(
    query: string,
    params: Record<string, unknown> = {},
  ): Promise<Result> {
    if (!this.driver) {
      throw new Error("Neo4j driver not initialized");
    }

    const session = this.driver.session();
    try {
      const result = await session.run(query, params);
      return result;
    } finally {
      await session.close();
    }
  }

  async runReadQuery<T>(
    query: string,
    params: Record<string, unknown> = {},
  ): Promise<T[]> {
    if (!this.driver) {
      throw new Error("Neo4j driver not initialized");
    }

    const session = this.driver.session();
    try {
      const result = await session.executeRead((tx) => tx.run(query, params));
      return result.records.map((record) => {
        const obj: Record<string, unknown> = {};
        record.keys.forEach((key) => {
          obj[key as string] = record.get(key);
        });
        return obj as T;
      });
    } finally {
      await session.close();
    }
  }

  async runWriteQuery(
    query: string,
    params: Record<string, unknown> = {},
  ): Promise<Result> {
    if (!this.driver) {
      throw new Error("Neo4j driver not initialized");
    }

    const session = this.driver.session();
    try {
      const result = await session.executeWrite((tx) => tx.run(query, params));
      return result;
    } finally {
      await session.close();
    }
  }

  getSession(): Session {
    if (!this.driver) {
      throw new Error("Neo4j driver not initialized");
    }
    return this.driver.session();
  }
}

