        CB_TIMEOUT: 30000,
        CB_GLOBAL_BUDGET: 20,
        CB_WINDOW_MS: 60000,
      };
      return config[key] ?? defaultValue;
    }),
  };

  beforeEach(async () => {
    redis = createRedisMock();

    const module: TestingModule = await Test.createTestingModule({
      providers: [
