  });
});

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { EventEmitter2 } from "@nestjs/event-emitter";

export interface IVaultClient {
  getSecret(path: string): Promise<Record<string, unknown>>;
  rotateKey(keyName: string): Promise<void>;
  healthCheck(): Promise<boolean>;
}

export interface VaultSecret {
  data: Record<string, unknown>;
  metadata?: {
    version: number;
    created_time: string;
    destroyed: boolean;
  };
}

export interface KeyRotationEvent {
  keyName: string;
  rotatedAt: Date;
  version: number;
}

@Injectable()
export class VaultService implements IVaultClient, OnModuleInit {
  private readonly logger = new Logger(VaultService.name);
  private vaultAddr: string | null = null;
  private vaultToken: string | null = null;
  private isMockMode = true;

  constructor(
    private readonly configService: ConfigService,
    private readonly eventEmitter: EventEmitter2,
  ) {}

  onModuleInit() {
    this.vaultAddr = this.configService.get<string>("VAULT_ADDR") ?? null;
    this.vaultToken = this.configService.get<string>("VAULT_TOKEN") ?? null;

    if (this.vaultAddr && this.vaultToken) {
      this.isMockMode = false;
      this.logger.log(`Vault client initialized - connected to ${this.vaultAddr}`);
    } else {
      this.isMockMode = true;
      this.logger.warn("Vault not configured (VAULT_ADDR/VAULT_TOKEN missing) - using mock implementation with env vars");
    }
  }

  async getSecret(path: string): Promise<Record<string, unknown>> {
    if (this.isMockMode) {
      return this.getSecretFromEnv(path);
    }

    try {
      const response = await fetch(`${this.vaultAddr}/v1/secret/data/${path}`, {
        headers: {
          "X-Vault-Token": this.vaultToken!,
          "Content-Type": "application/json",
        },
      });

      if (!response.ok) {
        this.logger.error(`Vault read failed for path ${path}: ${response.status} ${response.statusText}`);
        return this.getSecretFromEnv(path);
      }

      const body = await response.json() as { data?: { data?: Record<string, unknown> } };
      return body.data?.data ?? {};
    } catch (error) {
      this.logger.error(`Vault connection error for path ${path}: ${error instanceof Error ? error.message : String(error)}`);
      return this.getSecretFromEnv(path);
    }
  }

  async rotateKey(keyName: string): Promise<void> {
    if (this.isMockMode) {
      this.logger.warn(`Key rotation requested for ${keyName} in mock mode - no-op`);
      this.emitRotationEvent(keyName, 1);
      return;
    }

    try {
      const response = await fetch(`${this.vaultAddr}/v1/transit/keys/${keyName}/rotate`, {
        method: "POST",
        headers: {
          "X-Vault-Token": this.vaultToken!,
          "Content-Type": "application/json",
        },
      });

      if (!response.ok) {
        throw new Error(`Vault key rotation failed: ${response.status} ${response.statusText}`);
      }

      const keyInfo = await this.getKeyVersion(keyName);
      this.emitRotationEvent(keyName, keyInfo);
      this.logger.log(`Rotated Vault key: ${keyName} to version ${keyInfo}`);
    } catch (error) {
      this.logger.error(`Key rotation failed for ${keyName}: ${error instanceof Error ? error.message : String(error)}`);
      throw error;
    }
  }

  async healthCheck(): Promise<boolean> {
    if (this.isMockMode) {
      return true;
    }

    try {
      const response = await fetch(`${this.vaultAddr}/v1/sys/health`, {
        headers: { "X-Vault-Token": this.vaultToken! },
      });
      return response.status === 200;
    } catch {
      return false;
    }
  }

  isUsingMock(): boolean {
    return this.isMockMode;
  }

  private async getSecretFromEnv(path: string): Promise<Record<string, unknown>> {
    const envPrefix = path.toUpperCase().replace(/\//g, "_");
    const result: Record<string, unknown> = {};

    const envMappings: Record<string, string> = {
      encryption: "ENCRYPTION_KEY",
      database: "DATABASE_URL",
      jwt: "JWT_SECRET",
      redis: "REDIS_URL",
    };

    const envKey = envMappings[path] ?? envPrefix;
    const value = this.configService.get<string>(envKey);

    if (value) {
      result.value = value;
    }

    return result;
  }

  private async getKeyVersion(keyName: string): Promise<number> {
    try {
      const response = await fetch(`${this.vaultAddr}/v1/transit/keys/${keyName}`, {
        headers: {
          "X-Vault-Token": this.vaultToken!,
        },
      });

      if (!response.ok) {
        return 1;
      }

      const body = await response.json() as { data?: { latest_version?: number } };
      return body.data?.latest_version ?? 1;
    } catch {
      return 1;
    }
  }

  private emitRotationEvent(keyName: string, version: number): void {
    const event: KeyRotationEvent = {
      keyName,
      rotatedAt: new Date(),
      version,
    };
    this.eventEmitter.emit("vault.key.rotated", event);
  }
}

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import { resolveServiceUrl } from "../../common/config/runtime-flags";
import { PrismaService } from "../../common/prisma/prisma.service";
import { RedisService } from "../../common/redis/redis.service";
import { StorageService } from "../../common/storage/storage.service";

interface ReadinessCheckResult {
  name: string;
  passed: boolean;
  message: string;
}

@Injectable()
export class SystemReadinessService implements OnModuleInit {
  private readonly logger = new Logger(SystemReadinessService.name);

  constructor(
    private prisma: PrismaService,
    private redis: RedisService,
    private storage: StorageService,
    private configService: ConfigService,
  ) {}

  async onModuleInit(): Promise<void> {
    this.logger.log("Running system readiness checks...");
    const results = await this.runAllChecks();

    const failed = results.filter((r) => !r.passed);
    const passed = results.filter((r) => r.passed);

    for (const result of passed) {
      this.logger.log(`[PASS] ${result.name}: ${result.message}`);
    }
    for (const result of failed) {
      this.logger.error(`[FAIL] ${result.name}: ${result.message}`);
    }

    if (failed.length > 0) {
      const isProduction = this.configService.get<string>("NODE_ENV") === "production";
      const summary = `System readiness check failed: ${failed.length}/${results.length} checks failed (${failed.map((f) => f.name).join(", ")})`;

      if (isProduction) {
        this.logger.error(summary);
        throw new Error(summary);
      } else {
        this.logger.warn(`${summary} - Continuing in development mode`);
      }
    } else {
      this.logger.log(`All ${results.length} readiness checks passed`);
    }
  }

  private async runAllChecks(): Promise<ReadinessCheckResult[]> {
    return Promise.all([
      this.checkEnvVariables(),
      this.checkDatabase(),
      this.checkRedis(),
      this.checkMinioConfig(),
      this.checkMLService(),
    ]);
  }

  private async checkEnvVariables(): Promise<ReadinessCheckResult> {
    const requiredVars = [
      "DATABASE_URL",
      "REDIS_URL",
      "MINIO_ENDPOINT",
      "MINIO_ACCESS_KEY",
      "MINIO_SECRET_KEY",
      "JWT_SECRET",
    ];

    const missing = requiredVars.filter(
      (varName) => !this.configService.get<string>(varName),
    );

    if (missing.length > 0) {
      return {
        name: "Environment Variables",
        passed: false,
        message: `Missing required env vars: ${missing.join(", ")}`,
      };
    }

    return {
      name: "Environment Variables",
      passed: true,
      message: `All ${requiredVars.length} required env vars are set`,
    };
  }

  private async checkDatabase(): Promise<ReadinessCheckResult> {
    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3000);

      await Promise.race([
        this.prisma.$queryRaw`SELECT 1`,
        new Promise((_, reject) =>
          controller.signal.addEventListener("abort", () =>
            reject(new Error("Timeout after 3s")),
          ),
        ),
      ]);
      clearTimeout(timeout);

      return {
        name: "Database",
        passed: true,
        message: "Connection established",
      };
    } catch (error) {
      return {
        name: "Database",
        passed: false,
        message: error instanceof Error ? error.message : "Connection failed",
      };
    }
  }

  private async checkRedis(): Promise<ReadinessCheckResult> {
    try {
      const client = this.redis.getClient();
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3000);

      await Promise.race([
        client.ping(),
        new Promise((_, reject) =>
          controller.signal.addEventListener("abort", () =>
            reject(new Error("Timeout after 3s")),
          ),
        ),
      ]);
      clearTimeout(timeout);

      return {
        name: "Redis",
        passed: true,
        message: "Connection established",
      };
    } catch (error) {
      return {
        name: "Redis",
        passed: false,
        message: error instanceof Error ? error.message : "Connection failed",
      };
    }
  }

  private async checkMinioConfig(): Promise<ReadinessCheckResult> {
    const endpoint = this.configService.get<string>("MINIO_ENDPOINT");
    const accessKey = this.configService.get<string>("MINIO_ACCESS_KEY");
    const secretKey = this.configService.get<string>("MINIO_SECRET_KEY");
    const bucket = this.configService.get<string>("MINIO_BUCKET", "xuno");

    if (!endpoint || !accessKey || !secretKey) {
      return {
        name: "MinIO",
        passed: false,
        message: "Missing MinIO configuration (MINIO_ENDPOINT, MINIO_ACCESS_KEY, MINIO_SECRET_KEY)",
      };
    }

    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3000);

      await Promise.race([
        this.storage.getFileUrl("__readiness_check__", 1),
        new Promise((_, reject) =>
          controller.signal.addEventListener("abort", () =>
            reject(new Error("Timeout after 3s")),
          ),
        ),
      ]);
      clearTimeout(timeout);

      return {
        name: "MinIO",
        passed: true,
        message: `Configured (endpoint: ${endpoint}, bucket: ${bucket})`,
      };
    } catch (error) {
      const msg = error instanceof Error ? error.message : "Unknown error";
      return {
        name: "MinIO",
        passed: false,
        message: `Config present but service unreachable: ${msg}`,
      };
    }
  }

  private async checkMLService(): Promise<ReadinessCheckResult> {
    const mlServiceUrl = resolveServiceUrl(this.configService, "ML_SERVICE_URL", "http://localhost:8001");

    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3000);

      const response = await fetch(`${mlServiceUrl}/health`, {
        signal: controller.signal,
      });
      clearTimeout(timeout);

      if (!response.ok) {
        return {
          name: "ML Service",
          passed: false,
          message: `Returned status ${response.status}`,
        };
      }

      return {
        name: "ML Service",
        passed: true,
        message: `Reachable at ${mlServiceUrl}`,
      };
    } catch (error) {
      return {
        name: "ML Service",
        passed: false,
        message: `Unreachable at ${mlServiceUrl}: ${error instanceof Error ? error.message : "Unknown error"}`,
      };
    }
  }
}

