          contentId: rejectedPostId,
          contentType: "post",
          reason: "申诉理由",
        })
        .expect(401);
    });
  });

  describe("审核后状态验证", () => {
    it("被审核通过的帖子应该出现在公开列表中", async () => {
      const response = await request(app.getHttpServer())
