      }
    });
  });
});

import { INestApplication, ValidationPipe, VersioningType } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import request from 'supertest';

import { AppModule } from '../src/app.module';

describe('Health E2E', () => {
  let app: INestApplication;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.setGlobalPrefix('api');
    app.enableVersioning({ type: VersioningType.URI, defaultVersion: '1' });
    app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));
    await app.init();
  });

  afterAll(async () => {
    await app.close();
  });

  /** Helper to extract attributes from JSON:API response */
  const extractAttributes = (body: Record<string, unknown>) => {
    return (body as any).data?.attributes ?? body;
  };

  describe('/api/v1/health (GET)', () => {
    it('should return health status', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs).toHaveProperty('status');
      expect(['healthy', 'unhealthy', 'degraded']).toContain(attrs.status);
      expect(attrs).toHaveProperty('timestamp');
      expect(attrs).toHaveProperty('uptime');
      expect(attrs).toHaveProperty('version');
    });

    it('should include database health check', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs.checks).toHaveProperty('database');
      expect(attrs.checks.database).toHaveProperty('status');
      expect(['up', 'down']).toContain(attrs.checks.database.status);
    });

    it('should include redis health check', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs.checks).toHaveProperty('redis');
      expect(attrs.checks.redis).toHaveProperty('status');
      expect(['up', 'down']).toContain(attrs.checks.redis.status);
    });

    it('should include storage health check', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs.checks).toHaveProperty('storage');
      expect(attrs.checks.storage).toHaveProperty('status');
      expect(['up', 'down']).toContain(attrs.checks.storage.status);
    });

    it('should include latency information', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health')
        .expect(200);

      const attrs = extractAttributes(response.body);
      if (attrs.checks.database.status === 'up') {
        expect(attrs.checks.database).toHaveProperty('latency');
        expect(typeof attrs.checks.database.latency).toBe('number');
      }
    });
  });

  describe('/api/v1/health/live (GET)', () => {
    it('should return liveness status', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health/live')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs).toHaveProperty('status', 'alive');
      expect(attrs).toHaveProperty('timestamp');
    });

    it('should be fast (no dependency checks)', async () => {
      const start = Date.now();
      await request(app.getHttpServer())
        .get('/api/v1/health/live')
        .expect(200);
      const duration = Date.now() - start;

      expect(duration).toBeLessThan(100);
    });
  });

  describe('/api/v1/health/ready (GET)', () => {
    it('should return readiness status', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health/ready')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs).toHaveProperty('ready');
      expect(typeof attrs.ready).toBe('boolean');
      expect(attrs).toHaveProperty('checks');
    });

    it('should check all dependencies', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health/ready')
        .expect(200);

      const attrs = extractAttributes(response.body);
      expect(attrs.checks).toHaveProperty('database');
      expect(attrs.checks).toHaveProperty('redis');
      expect(typeof attrs.checks.database).toBe('boolean');
      expect(typeof attrs.checks.redis).toBe('boolean');
    });

    it('should return ready=true only when all checks pass', async () => {
      const response = await request(app.getHttpServer())
        .get('/api/v1/health/ready')
        .expect(200);

      const attrs = extractAttributes(response.body);
      const checks = attrs.checks as Record<string, boolean>;
      const allChecksPass = Object.values(checks).every(v => v === true);
      expect(attrs.ready).toBe(allChecksPass);
    });
  });
});

/**
 * Phase 1 Integration Test: Profile Sync
 *
 * Tests cross-module event propagation: profile updates publish profile:updated
 * events, quiz completion publishes quiz:completed events, and subscribers
 * receive them. Also verifies profile completeness calculation.
 *
 * Only imports services that compile cleanly; avoids importing controllers
 * or services that depend on modules with pre-existing type errors.
 */

import { EventEmitter2 } from "@nestjs/event-emitter";
import { Test, TestingModule } from "@nestjs/testing";

import { RedisService, REDIS_CLIENT } from "../../src/common/redis/redis.service";
import { ProfileCompletenessService } from "../../src/modules/profile/services/profile-completeness.service";
import { ProfileEventEmitter } from "../../src/modules/profile/services/profile-event-emitter.service";
import {
  createRedisKeyTracker,
  RedisKeyTracker,
  createMockRedisClient,
  createMockRedisService,
} from "../utils/redis-test-utils";

describe("Phase 1 Integration: Profile Sync", () => {
  let redisTracker: RedisKeyTracker;
  let mockRedisService: ReturnType<typeof createMockRedisService>;
  let profileEventEmitter: ProfileEventEmitter;
  let completenessService: ProfileCompletenessService;
  let eventEmitter2: EventEmitter2;

  const TEST_USER_ID = "user-sync-001";

  beforeAll(async () => {
    redisTracker = createRedisKeyTracker();
    mockRedisService = createMockRedisService(redisTracker);

    const moduleFixture: TestingModule = await Test.createTestingModule({
      providers: [
        ProfileCompletenessService,
        ProfileEventEmitter,
        { provide: REDIS_CLIENT, useValue: createMockRedisClient(redisTracker) },
        { provide: RedisService, useValue: mockRedisService },
        EventEmitter2,
      ],
    }).compile();

    profileEventEmitter = moduleFixture.get(ProfileEventEmitter);
    completenessService = moduleFixture.get(ProfileCompletenessService);
    eventEmitter2 = moduleFixture.get(EventEmitter2);
  });

  afterEach(() => {
    jest.clearAllMocks();
    redisTracker.reset();
  });

  // -------------------------------------------------------------------
  // 1. Profile update emits profile:updated event
  // -------------------------------------------------------------------
  describe("profile:updated event", () => {
    it("should publish profile:updated to Redis when profile is updated", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");

      await profileEventEmitter.emitProfileUpdated(TEST_USER_ID, ["nickname"]);

      expect(publishSpy).toHaveBeenCalledWith(
        "profile:updated",
        expect.any(String),
      );

      const callArgs = publishSpy.mock.calls[0]!;
      const message = JSON.parse(callArgs[1]);
      expect(message).toEqual({
        userId: TEST_USER_ID,
        changedFields: ["nickname"],
        timestamp: expect.any(Number),
      });
    });

    it("should include all changed fields in the event", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");

      await profileEventEmitter.emitProfileUpdated(TEST_USER_ID, [
        "gender",
        "birthDate",
        "height",
        "weight",
      ]);

      const callArgs = publishSpy.mock.calls[0]!;
      const message = JSON.parse(callArgs[1]);
      expect(message.changedFields).toEqual([
        "gender",
        "birthDate",
        "height",
        "weight",
      ]);
    });
  });

  // -------------------------------------------------------------------
  // 2. Quiz completion emits quiz:completed event
  // -------------------------------------------------------------------
  describe("quiz:completed event", () => {
    it("should publish quiz:completed to Redis when quiz result is saved", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");
      const quizId = "quiz-001";

      await profileEventEmitter.emitQuizResultSaved(TEST_USER_ID, quizId);

      expect(publishSpy).toHaveBeenCalledWith(
        "quiz:completed",
        expect.any(String),
      );

      const callArgs = publishSpy.mock.calls[0]!;
      const message = JSON.parse(callArgs[1]);
      expect(message).toEqual({
        userId: TEST_USER_ID,
        quizId,
        timestamp: expect.any(Number),
      });
    });
  });

  // -------------------------------------------------------------------
  // 3. NestJS EventEmitter2 subscribers receive events
  // -------------------------------------------------------------------
  describe("EventEmitter2 subscribers", () => {
    it("should notify AI Stylist subscriber on profile:updated", async () => {
      const aiStylistHandler = jest.fn();
      eventEmitter2.on("profile.updated", aiStylistHandler);

      eventEmitter2.emit("profile.updated", {
        userId: TEST_USER_ID,
        changedFields: ["bodyType"],
      });

      expect(aiStylistHandler).toHaveBeenCalledWith({
        userId: TEST_USER_ID,
        changedFields: ["bodyType"],
      });

      eventEmitter2.removeListener("profile.updated", aiStylistHandler);
    });

    it("should notify Recommendations subscriber on quiz:completed", async () => {
      const recommendationsHandler = jest.fn();
      eventEmitter2.on("quiz.completed", recommendationsHandler);

      eventEmitter2.emit("quiz.completed", {
        userId: TEST_USER_ID,
        quizId: "quiz-001",
      });

      expect(recommendationsHandler).toHaveBeenCalledWith({
        userId: TEST_USER_ID,
        quizId: "quiz-001",
      });

      eventEmitter2.removeListener("quiz.completed", recommendationsHandler);
    });
  });

  // -------------------------------------------------------------------
  // 4. Profile completeness calculation
  // -------------------------------------------------------------------
  describe("Profile completeness", () => {
    it("should return low percentage for minimal profile", () => {
      const result = completenessService.calculateCompleteness({
        gender: "female",
        birthDate: null,
        nickname: null,
        height: null,
        weight: null,
        bodyType: null,
        colorSeason: null,
        styleProfiles: [],
        stylePreferences: [],
        colorPreferences: [],
        photos: [],
      });

      expect(result.percentage).toBeLessThan(20);
      expect(result.missingFields).toContain("出生日期");
      expect(result.missingFields).toContain("昵称");
      expect(result.missingFields).toContain("身材数据");
    });

    it("should return 100% for complete profile", () => {
      const result = completenessService.calculateCompleteness({
        gender: "female",
        birthDate: new Date("1995-01-01"),
        nickname: "测试用户",
        height: 165,
        weight: 55,
        bodyType: "hourglass",
        colorSeason: "spring",
        styleProfiles: [{ id: "sp-1" }],
        stylePreferences: ["casual"],
        colorPreferences: ["#FF0000"],
        photos: [{ id: "photo-1" }],
      });

      expect(result.percentage).toBe(100);
      expect(result.missingFields).toEqual([]);
    });

    it("should list missing fields correctly for partial profile", () => {
      const result = completenessService.calculateCompleteness({
        gender: "female",
        birthDate: new Date("1995-01-01"),
        nickname: "测试用户",
        height: null,
        weight: null,
        bodyType: null,
        colorSeason: null,
        styleProfiles: [],
        stylePreferences: [],
        colorPreferences: [],
        photos: [],
      });

      // Basic info (30%) is complete: gender(10) + birthDate(10) + nickname(10) = 30
      expect(result.percentage).toBe(30);
      expect(result.missingFields).toContain("身材数据");
      expect(result.missingFields).toContain("风格档案");
      expect(result.missingFields).toContain("色彩分析");
      expect(result.missingFields).toContain("个人照片");
    });

    it("should return 0% for empty profile", () => {
      const result = completenessService.calculateCompleteness({
        gender: null,
        birthDate: null,
        nickname: null,
        height: null,
        weight: null,
        bodyType: null,
        colorSeason: null,
        styleProfiles: [],
        stylePreferences: [],
        colorPreferences: [],
        photos: [],
      });

      expect(result.percentage).toBe(0);
      expect(result.missingFields.length).toBeGreaterThan(0);
    });
  });

  // -------------------------------------------------------------------
  // 5. Cross-module integration: Profile update triggers event
  // -------------------------------------------------------------------
  describe("Cross-module event flow", () => {
    it("should publish profile:updated when profile fields change", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");

      await profileEventEmitter.emitProfileUpdated(TEST_USER_ID, ["height", "weight"]);

      expect(publishSpy).toHaveBeenCalledTimes(1);
      expect(publishSpy).toHaveBeenCalledWith(
        "profile:updated",
        expect.stringContaining(TEST_USER_ID),
      );
    });

    it("should publish quiz:completed after quiz result saved", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");

      await profileEventEmitter.emitQuizResultSaved(TEST_USER_ID, "quiz-default");

      expect(publishSpy).toHaveBeenCalledTimes(1);
      expect(publishSpy).toHaveBeenCalledWith(
        "quiz:completed",
        expect.stringContaining("quiz-default"),
      );
    });

    it("should support multiple event types in sequence", async () => {
      const publishSpy = jest.spyOn(mockRedisService, "publish");

      await profileEventEmitter.emitProfileUpdated(TEST_USER_ID, ["colorSeason"]);
      await profileEventEmitter.emitQuizResultSaved(TEST_USER_ID, "quiz-002");

      expect(publishSpy).toHaveBeenCalledTimes(2);
      expect(publishSpy).toHaveBeenNthCalledWith(
        1,
        "profile:updated",
        expect.any(String),
      );
      expect(publishSpy).toHaveBeenNthCalledWith(
        2,
        "quiz:completed",
        expect.any(String),
      );
    });
  });
});

/**
 * 用户完整流程集成测试
 * @description 测试用户从注册到完成虚拟试衣的完整业务流程
 * 
 * 测试流程:
 * 1. 用户注册
 * 2. 用户登录
 * 3. 更新用户画像
 * 4. 获取个性化推荐
 * 5. 虚拟试衣
 */

import { INestApplication, ValidationPipe, VersioningType } from "@nestjs/common";
import { Test, TestingModule } from "@nestjs/testing";
import {
  BodyType,
  SkinTone,
  ColorSeason,
  ClothingCategory,
  PhotoType,
  TryOnStatus,
} from "@prisma/client";
import request from "supertest";

import { AppModule } from "../../src/app.module";
import { PrismaService } from "../../src/common/prisma/prisma.service";
import { profileFixtures, performanceThresholds } from "../utils/fixtures";
import {
  generateTestEmail,
  measureResponseTime,
} from "../utils/test.utils";

const API = "/api/v1";

/** Extract data from JSON:API response, merging id from data level into attributes */
const extractData = (body: Record<string, unknown>) => {
  const d = (body as any).data;
  if (d?.attributes && typeof d === "object") {
    return { id: d.id, ...d.attributes };
  }
  return d ?? body;
};

describe("User Flow E2E - 完整用户流程", () => {
  let app: INestApplication;
  let prisma: PrismaService;
  let accessToken: string;
  let refreshToken: string;
  let userId: string;
  let photoId: string;
  let itemId: string;
  let tryOnId: string;

  const testUser = {
    email: generateTestEmail(),
    password: "Test123456!",
    nickname: "用户流程测试",
  };

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.setGlobalPrefix("api");
    app.enableVersioning({ type: VersioningType.URI, defaultVersion: "1" });
    app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));
    await app.init();

    prisma = app.get(PrismaService);
  });

  afterAll(async () => {
    // 清理测试数据
    if (userId) {
      await prisma.virtualTryOn.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.aiStylistSession.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.userPhoto.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.userProfile.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.cartItem.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.favorite.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.user.delete({ where: { id: userId } }).catch(() => {});
    }
    if (itemId) {
      await prisma.clothingItem.delete({ where: { id: itemId } }).catch(() => {});
    }
    await app.close();
  });

  describe("阶段 1: 用户注册", () => {
    it("应该成功注册新用户", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/register`)
        .send(testUser)
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");
      expect(response.body.included[0].attributes).toHaveProperty("email", testUser.email);
      expect(response.body.included[0].attributes).toHaveProperty("nickname", testUser.nickname);

      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
      userId = response.body.included[0].id;
    });

    it("注册响应时间应该符合性能要求", async () => {
      const duration = await measureResponseTime(async () => {
        await request(app.getHttpServer())
          .post(`${API}/auth/register`)
          .send({
            email: generateTestEmail(),
            password: "Test123456!",
            nickname: "性能测试用户",
          })
          .expect(201);
      });

      expect(duration).toBeLessThan(performanceThresholds.auth.register);
    });
  });

  describe("阶段 2: 用户登录", () => {
    it("应该成功登录已注册用户", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/login`)
        .send({
          email: testUser.email,
          password: testUser.password,
        })
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");

      // 更新 token
      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
    });

    it("应该获取当前用户信息", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/auth/me`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const meData = extractData(response.body);
      expect(meData).toHaveProperty("id", userId);
      expect(meData).toHaveProperty("email", testUser.email);
    });

    it("应该能够刷新 Token", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/refresh`)
        .send({ refreshToken })
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");

      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
    });
  });

  describe("阶段 3: 更新用户画像", () => {
    it("应该成功获取初始画像（可能为空）", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      // 初始画像可能为空或有默认值
      expect(response.body).toBeDefined();
    });

    it("应该成功更新用户画像", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send(profileFixtures.validProfile)
        .expect(200);

      expect(extractData(response.body).profile?.bodyType).toBe(BodyType.hourglass);
      expect(extractData(response.body).profile?.skinTone).toBe(SkinTone.medium);
      expect(extractData(response.body).profile?.colorSeason).toBe(ColorSeason.autumn_warm);
    });

    it("应该成功获取体型分析报告", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile/body-analysis`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("bodyType");
      expect(extractData(response.body)).toHaveProperty("recommendations");
    });

    it("应该成功获取色彩分析报告", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile/color-analysis`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("colorSeason");
      expect(extractData(response.body)).toHaveProperty("bestColors");
      expect(extractData(response.body)).toHaveProperty("avoidColors");
    });

    it("应该成功更新风格偏好", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile/preferences/styles`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({
          styles: ["casual", "minimalist", "elegant"],
        })
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("success", true);
    });

    it("应该成功更新颜色偏好", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile/preferences/colors`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({
          colors: ["black", "white", "navy", "beige"],
        })
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("success", true);
    });
  });

  describe("阶段 4: 获取个性化推荐", () => {
    it("应该成功获取个性化推荐列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/recommendations`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("items");
      expect(Array.isArray(extractData(response.body).items)).toBe(true);
    });

    it("应该成功获取风格指南", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/recommendations/style-guide`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("bodyType");
      expect(extractData(response.body)).toHaveProperty("colorSeason");
      expect(extractData(response.body)).toHaveProperty("recommendations");
    });

    it("应该成功获取服装分类列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/clothing/categories`)
        .expect(200);

      const categories = (response.body).data ?? response.body;
      expect(Array.isArray(categories)).toBe(true);
    });

    it("应该成功获取服装列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/clothing`)
        .query({ limit: 5 })
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const clothingData = extractData(response.body);
      expect(clothingData).toHaveProperty("total");

      // Items are in included array for JSON:API
      const included = (response.body).included ?? [];
      if (included.length > 0) {
        itemId = included[0].id;
      }
    });

    it("推荐响应时间应该符合性能要求", async () => {
      const duration = await measureResponseTime(async () => {
        await request(app.getHttpServer())
          .get(`${API}/recommendations`)
          .set("Authorization", `Bearer ${accessToken}`)
          .expect(200);
      });

      expect(duration).toBeLessThan(performanceThresholds.recommendations.list);
    });
  });

  describe("阶段 5: 虚拟试衣", () => {
    beforeAll(async () => {
      // 创建测试用户照片
      const photo = await prisma.userPhoto.create({
        data: {
          userId,
          type: PhotoType.full_body,
          url: "https://example.com/test-photo.jpg",
          thumbnailUrl: "https://example.com/test-photo-thumb.jpg",
        },
      });
      photoId = photo.id;

      // Always create a test item for try-on (don't rely on clothing list test)
      const item = await prisma.clothingItem.create({
        data: {
          name: "测试T恤-E2E",
          category: ClothingCategory.tops,
          images: ["https://example.com/test-item.jpg"],
          price: 199.0,
          colors: ["white", "black"],
          sizes: ["S", "M", "L"],
        },
      });
      itemId = item.id;
    });

    it("应该成功创建试衣请求", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/try-on`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({
          photoId,
          itemId,
        })
        .expect(201);

      expect(extractData(response.body)).toHaveProperty("id");
      expect(extractData(response.body)).toHaveProperty("status");
      expect([
        TryOnStatus.pending,
        TryOnStatus.processing,
        TryOnStatus.completed,
      ]).toContain(extractData(response.body).status);

      tryOnId = extractData(response.body).id;
    });

    it("应该成功获取试衣历史", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/try-on/history`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const historyData = extractData(response.body);
      expect(historyData).toHaveProperty("total");
      // Items may be in included array for JSON:API
      const items = (response.body).included ?? historyData.items ?? [];
      expect(Array.isArray(items)).toBe(true);
    });

    it("应该成功获取试衣状态", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/try-on/${tryOnId}`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const statusData = extractData(response.body);
      expect(statusData).toHaveProperty("id", tryOnId);
      expect(statusData).toHaveProperty("status");
      // photo and item may be in included array or as IDs
      expect(statusData).toHaveProperty("photoId");
      expect(statusData).toHaveProperty("itemId");
    });

    it("创建试衣响应时间应该符合性能要求", async () => {
      const duration = await measureResponseTime(async () => {
        await request(app.getHttpServer())
          .post(`${API}/try-on`)
          .set("Authorization", `Bearer ${accessToken}`)
          .send({ photoId, itemId })
          .expect(201);
      });

      expect(duration).toBeLessThan(performanceThresholds.tryOn.create);
    });
  });

  describe("阶段 6: 用户登出", () => {
    it("应该成功刷新 Token 并登出", async () => {
      // Re-login to get a fresh token for logout test
      const loginRes = await request(app.getHttpServer())
        .post(`${API}/auth/login`)
        .send({ email: testUser.email, password: testUser.password })
        .expect(201);

      const freshToken = loginRes.body.data.attributes.accessToken;

      await request(app.getHttpServer())
        .post(`${API}/auth/logout`)
        .set("Authorization", `Bearer ${freshToken}`)
        .send({ refreshToken })
        .expect(201);
    });

    it("登出后 Refresh Token 应该失效", async () => {
      // Trying to use the old refresh token should fail
      await request(app.getHttpServer())
        .post(`${API}/auth/refresh`)
        .send({ refreshToken })
        .expect(401);
    });
  });

  describe("完整流程性能测试", () => {
    it("完整用户流程应该在合理时间内完成", async () => {
      const startTime = Date.now();

      // 重新注册一个用户进行完整流程测试
      const newUser = {
        email: generateTestEmail(),
        password: "Test123456!",
        nickname: "完整流程测试",
      };

      // 1. 注册
      const registerResponse = await request(app.getHttpServer())
        .post(`${API}/auth/register`)
        .send(newUser)
        .expect(201);
      const newAccessToken = registerResponse.body.data.attributes.accessToken;
      const newUserId = registerResponse.body.included[0].id;

      // 2. 更新画像
      await request(app.getHttpServer())
        .put(`${API}/profile`)
        .set("Authorization", `Bearer ${newAccessToken}`)
        .send(profileFixtures.minimalProfile)
        .expect(200);

      // 3. 获取推荐
      await request(app.getHttpServer())
        .get(`${API}/recommendations`)
        .set("Authorization", `Bearer ${newAccessToken}`)
        .expect(200);

      // 4. 获取服装列表
      await request(app.getHttpServer())
        .get(`${API}/clothing`)
        .query({ limit: 5 })
        .set("Authorization", `Bearer ${newAccessToken}`)
        .expect(200);

      const totalDuration = Date.now() - startTime;

      // 完整流程应该在 5 秒内完成
      expect(totalDuration).toBeLessThan(5000);

      // 清理
      await prisma.userProfile.deleteMany({ where: { userId: newUserId } }).catch(() => {});
      await prisma.user.delete({ where: { id: newUserId } }).catch(() => {});
    });
  });
});

import { INestApplication, ValidationPipe } from "@nestjs/common";
import { Test, TestingModule } from "@nestjs/testing";
import request from "supertest";

import { AppModule } from "../src/app.module";
import { PrismaService } from "../src/common/prisma/prisma.service";

describe("Recommendation Flow E2E", () => {
  let app: INestApplication;
  let prisma: PrismaService;
  let accessToken: string;
  let userId: string;

  const testUser = {
    email: "rec-e2e@example.com",
    password: "Test123456!",
    nickname: "Rec E2E User",
  };

  const coldStartUser = {
    email: "cold-e2e@example.com",
    password: "Test123456!",
    nickname: "Cold Start User",
  };

  let coldStartAccessToken: string;
  let coldStartUserId: string;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));
    await app.init();

    prisma = app.get(PrismaService);
  });

  afterAll(async () => {
    const userIds = [userId, coldStartUserId].filter(Boolean);
    for (const uid of userIds) {
      await prisma.user.delete({ where: { id: uid } }).catch(() => {});
    }
    await app.close();
  });

  describe("前置条件：用户注册", () => {
    it("应该成功注册老用户", async () => {
      const response = await request(app.getHttpServer())
        .post("/api/v1/auth/register")
        .send(testUser)
        .expect(201);

      accessToken = response.body.access_token;
      userId = response.body.user.id;
    });

    it("应该成功注册冷启动用户", async () => {
      const response = await request(app.getHttpServer())
        .post("/api/v1/auth/register")
        .send(coldStartUser)
        .expect(201);

      coldStartAccessToken = response.body.access_token;
      coldStartUserId = response.body.user.id;
    });
  });

  describe("GET /api/v1/recommendations - 获取推荐", () => {
    it("老用户应该获取个性化推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
      expect(Array.isArray(response.body.items)).toBe(true);
    });

    it("冷启动用户应该获取热门推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations")
        .set("Authorization", `Bearer ${coldStartAccessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
      expect(Array.isArray(response.body.items)).toBe(true);
    });

    it("未认证时应该返回 401", async () => {
      await request(app.getHttpServer())
        .get("/api/v1/recommendations")
        .expect(401);
    });
  });

  describe("GET /api/v1/recommendations - 分类筛选", () => {
    it("应该支持按分类筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?category=tops")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该支持按风格筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?style=casual")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该支持按场合筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?occasion=daily")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });
  });

  describe("GET /api/v1/recommendations - 分页", () => {
    it("应该支持分页参数", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=1&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
      expect(response.body).toHaveProperty("total");
      expect(response.body).toHaveProperty("hasMore");
    });

    it("应该支持 cursor 分页", async () => {
      const firstPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (firstPage.body.cursor) {
        const secondPage = await request(app.getHttpServer())
          .get(
            `/api/v1/recommendations?cursor=${firstPage.body.cursor}&pageSize=5`,
          )
          .set("Authorization", `Bearer ${accessToken}`)
          .expect(200);

        expect(secondPage.body).toHaveProperty("items");
      }
    });

    it("第二页结果不应与第一页重复", async () => {
      const firstPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=1&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const secondPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=2&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (
        firstPage.body.items.length > 0 &&
        secondPage.body.items.length > 0
      ) {
        const firstIds = firstPage.body.items.map((i: any) => i.id);
